{
  "name": "Smart Rapor - Kalkulator Nilai Masa Depan",
  "description": "Sebuah aplikasi kalkulator nilai rapor modern dan futuristik untuk membantu siswa memantau rata-rata nilai dan merencanakan target prestasi akademik mereka."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Subject {
  id: string;
  name: string;
  score: number;
}

export interface Semester {
  id: number;
  subjects: Subject[];
}

export interface AppData {
  semesters: Semester[];
  targetAvg: number;
  totalSemestersTarget: number;
}

export enum StatusColor {
  SAFE = 'text-emerald-400 border-emerald-400/30 bg-emerald-400/10',
  WARNING = 'text-amber-400 border-amber-400/30 bg-amber-400/10',
  DANGER = 'text-rose-400 border-rose-400/30 bg-rose-400/10'
}

import { AppData, Semester } from './types';

export const calculateSemesterAverage = (semester: Semester): number => {
  if (semester.subjects.length === 0) return 0;
  const sum = semester.subjects.reduce((acc, sub) => acc + sub.score, 0);
  return sum / semester.subjects.length;
};

export const calculateOverallAverage = (semesters: Semester[]): number => {
  const activeSemesters = semesters.filter(s => s.subjects.length > 0);
  if (activeSemesters.length === 0) return 0;
  const sumOfAverages = activeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
  return sumOfAverages / activeSemesters.length;
};

export const STORAGE_KEY = 'smart_rapor_data';

export const saveToStorage = (data: AppData) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
};

export const loadFromStorage = (): AppData | null => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : null;
};

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';

// Helper for unique IDs
const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: AppData = {
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);

  // Initialize data from local storage
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
    }
    setIsLoaded(true);
  }, []);

  // Save to storage on change
  useEffect(() => {
    if (isLoaded) {
      saveToStorage(data);
    }
  }, [data, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || data.semesters[0],
    [data.semesters, activeSemesterId]
  );

  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  const completedCount = useMemo(() => 
    data.semesters.filter(s => s.subjects.length > 0).length,
    [data.semesters]
  );

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completedCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = data.semesters
      .filter(s => s.subjects.length > 0)
      .reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);

    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data, completedCount]);

  const getStatus = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    const newSubject: Subject = { id: generateId(), name: '', score: 0 };
    const newSemesters = data.semesters.map(s => 
      s.id === activeSemesterId 
        ? { ...s, subjects: [...s.subjects, newSubject] }
        : s
    );
    setData({ ...data, semesters: newSemesters });
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    const newSemesters = data.semesters.map(s => {
      if (s.id === activeSemesterId) {
        return {
          ...s,
          subjects: s.subjects.map(sub => 
            sub.id === subId ? { ...sub, [field]: value } : sub
          )
        };
      }
      return s;
    });
    setData({ ...data, semesters: newSemesters });
  };

  const handleDeleteSubject = (subId: string) => {
    const newSemesters = data.semesters.map(s => 
      s.id === activeSemesterId 
        ? { ...s, subjects: s.subjects.filter(sub => sub.id !== subId) }
        : s
    );
    setData({ ...data, semesters: newSemesters });
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-500">
      {/* Header */}
      <header className="border-b border-white/10 glass-card sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-cyan-500 flex items-center justify-center shadow-[0_0_15px_rgba(34,211,238,0.5)]">
              <span className="text-white font-bold text-xl">S</span>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-white flex items-center gap-1">
              SMART <span className="text-cyan-400">RAPOR</span>
            </h1>
          </div>
          <div className="hidden md:flex items-center gap-4 text-xs tech-font text-slate-400">
            <span>VERSION 2.0.0</span>
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span>SYSTEM ACTIVE</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 mt-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Summary & Target */}
        <aside className="lg:col-span-4 space-y-6">
          <section className="glass-card rounded-2xl p-6 relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-32 h-32 bg-cyan-500/10 blur-3xl -mr-16 -mt-16 rounded-full group-hover:bg-cyan-500/20 transition-colors"></div>
            <h2 className="text-slate-400 text-sm font-medium mb-1 tracking-wider uppercase">Rata-rata Keseluruhan</h2>
            <div className="flex items-baseline gap-2">
              <span className="text-5xl font-bold tech-font text-white">{overallAvg.toFixed(1)}</span>
              <span className="text-slate-500 text-sm">/ 100</span>
            </div>
            <div className={`mt-4 inline-flex items-center px-3 py-1 rounded-full border text-xs font-semibold ${getStatus(overallAvg)}`}>
              {overallAvg >= data.targetAvg ? 'Target Tercapai' : 'Perlu Peningkatan'}
            </div>
          </section>

          <section className="glass-card rounded-2xl p-6 border-l-4 border-cyan-500">
            <h2 className="text-white font-semibold mb-4 flex items-center gap-2">
               Target Akademik
            </h2>
            <div className="space-y-4">
              <div>
                <label className="block text-xs text-slate-400 mb-1 tracking-wider uppercase">Target Akhir</label>
                <div className="relative">
                  <input 
                    type="number" 
                    value={data.targetAvg}
                    onChange={(e) => setData({ ...data, targetAvg: Number(e.target.value) })}
                    className="w-full bg-slate-900/50 border border-white/10 rounded-xl px-4 py-2 text-white tech-font focus:ring-2 focus:ring-cyan-500 outline-none transition-all"
                  />
                  <span className="absolute right-4 top-2 text-slate-500">%</span>
                </div>
              </div>
              <div>
                <label className="block text-xs text-slate-400 mb-1 tracking-wider uppercase">Jumlah Semester</label>
                <input 
                  type="number" 
                  value={data.totalSemestersTarget}
                  onChange={(e) => setData({ ...data, totalSemestersTarget: Number(e.target.value) })}
                  className="w-full bg-slate-900/50 border border-white/10 rounded-xl px-4 py-2 text-white tech-font focus:ring-2 focus:ring-cyan-500 outline-none transition-all"
                />
              </div>
            </div>
          </section>

          <section className="glass-card rounded-2xl p-6 bg-gradient-to-br from-slate-800/50 to-slate-900/50">
            <h2 className="text-white font-semibold mb-4">Estimasi Masa Depan</h2>
            <div className="space-y-4">
              <div className="p-4 rounded-xl bg-white/5 border border-white/5">
                <p className="text-xs text-slate-400 mb-2 uppercase tracking-tighter">Minimal Nilai Semester Berikutnya</p>
                <p className={`text-3xl font-bold tech-font ${neededAvg > 100 ? 'text-rose-500' : 'text-cyan-400'}`}>
                  {neededAvg > 100 ? 'Hampir Mustahil' : neededAvg.toFixed(1)}
                </p>
                {neededAvg > 100 && (
                  <p className="text-[10px] text-rose-400 mt-1 italic">*Target Anda terlalu tinggi dibanding riwayat nilai saat ini.</p>
                )}
              </div>
              <p className="text-sm text-slate-400 leading-relaxed italic">
                "{neededAvg > 0 
                  ? `Kamu perlu mempertahankan rata-rata sekitar ${neededAvg.toFixed(1)} di ${data.totalSemestersTarget - completedCount} semester tersisa untuk mencapai target ${data.targetAvg}.`
                  : 'Target sudah tercapai! Pertahankan prestasimu.'}"
              </p>
            </div>
          </section>
        </aside>

        {/* Right Column: Semester Management */}
        <div className="lg:col-span-8 space-y-6">
          {/* Semester Tabs */}
          <div className="flex overflow-x-auto gap-2 pb-2 scrollbar-hide">
            {data.semesters.map(sem => (
              <button
                key={sem.id}
                onClick={() => setActiveSemesterId(sem.id)}
                className={`flex-shrink-0 px-6 py-3 rounded-xl transition-all duration-300 font-medium ${
                  activeSemesterId === sem.id 
                    ? 'bg-cyan-500 text-white shadow-[0_0_20px_rgba(34,211,238,0.4)]' 
                    : 'glass-card text-slate-400 hover:text-white'
                }`}
              >
                Semester {sem.id}
              </button>
            ))}
          </div>

          <section className="glass-card rounded-3xl p-4 md:p-8 min-h-[500px]">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h3 className="text-2xl font-bold text-white">Data Nilai</h3>
                <p className="text-slate-400 text-sm">Rata-rata Semester: <span className="tech-font text-cyan-400 font-bold ml-1">{calculateSemesterAverage(activeSemester).toFixed(1)}</span></p>
              </div>
              <button 
                onClick={handleAddSubject}
                className="bg-white/10 hover:bg-white/20 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all border border-white/5"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                <span>Mata Pelajaran</span>
              </button>
            </div>

            {activeSemester.subjects.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-50">
                <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4">
                   <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                </div>
                <p className="text-slate-400 italic">Belum ada data mata pelajaran di semester ini.</p>
                <button onClick={handleAddSubject} className="mt-4 text-cyan-400 hover:underline text-sm font-medium">Tambah Sekarang</button>
              </div>
            ) : (
              <div className="space-y-4">
                {activeSemester.subjects.map((sub, idx) => (
                  <div key={sub.id} className="group flex flex-col md:flex-row gap-3 md:items-center bg-slate-900/30 p-4 rounded-2xl border border-white/5 hover:border-cyan-500/30 transition-all">
                    <span className="tech-font text-xs text-slate-500 w-6">{(idx + 1).toString().padStart(2, '0')}</span>
                    <input 
                      type="text" 
                      placeholder="Nama Mata Pelajaran"
                      value={sub.name}
                      onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      className="flex-grow bg-transparent border-none focus:ring-0 text-white font-medium placeholder:text-slate-600 outline-none"
                    />
                    <div className="flex items-center gap-3">
                      <div className="relative">
                        <input 
                          type="number" 
                          placeholder="0"
                          min="0"
                          max="100"
                          value={sub.score || ''}
                          onChange={(e) => {
                            let val = parseInt(e.target.value) || 0;
                            if (val > 100) val = 100;
                            if (val < 0) val = 0;
                            handleUpdateSubject(sub.id, 'score', val);
                          }}
                          className="w-24 bg-slate-800 border border-white/10 rounded-lg px-3 py-1.5 text-center text-cyan-400 tech-font font-bold focus:ring-2 focus:ring-cyan-500 outline-none transition-all"
                        />
                      </div>
                      <button 
                        onClick={() => handleDeleteSubject(sub.id)}
                        className="text-slate-500 hover:text-rose-400 p-2 rounded-lg hover:bg-rose-400/10 transition-all"
                      >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </section>
        </div>
      </main>

      {/* Footer */}
      <footer className="mt-20 border-t border-white/5 py-12">
        <div className="max-w-6xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="text-center md:text-left">
            <p className="text-slate-500 text-sm mb-1">Dibuat dengan dedikasi untuk pelajar Indonesia</p>
            <p className="text-white font-medium tracking-wide tech-font">Website by Dafid</p>
          </div>

          <a 
            href="https://dapidhub.my.id" 
            target="_blank" 
            rel="noopener noreferrer"
            className="group relative px-8 py-3 bg-cyan-500 rounded-full font-bold text-white transition-all hover:scale-105 active:scale-95 shadow-[0_0_20px_rgba(34,211,238,0.3)]"
          >
            <span className="relative z-10 flex items-center gap-2">
              Dapidhub
              <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
            </span>
            <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-20 transition-opacity rounded-full"></div>
          </a>
        </div>
        <div className="text-center mt-12 text-[10px] uppercase tracking-[0.3em] text-slate-700 tech-font">
          &copy; 2024 DIGITAL ACADEMIC COMPASS
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';

// Helper for unique IDs
const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: AppData = {
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);

  // Initialize data from local storage
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
    }
    setIsLoaded(true);
  }, []);

  // Save to storage on change
  useEffect(() => {
    if (isLoaded) {
      saveToStorage(data);
    }
  }, [data, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || data.semesters[0],
    [data.semesters, activeSemesterId]
  );

  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  // Calculate average for each specific subject across all semesters
  const subjectAverages = useMemo(() => {
    const masterSubjects = data.semesters[0].subjects;
    return masterSubjects.map(masterSub => {
      let sum = 0;
      let count = 0;
      data.semesters.forEach(sem => {
        const sub = sem.subjects.find(s => s.id === masterSub.id);
        if (sub && sub.score > 0) {
          sum += sub.score;
          count++;
        }
      });
      return {
        id: masterSub.id,
        name: masterSub.name || 'Tanpa Nama',
        avg: count > 0 ? sum / count : 0
      };
    });
  }, [data.semesters]);

  const completedCount = useMemo(() => 
    data.semesters.filter(s => s.subjects.length > 0 && s.subjects.some(sub => sub.score > 0)).length,
    [data.semesters]
  );

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completedCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = data.semesters
      .filter(s => s.subjects.length > 0 && s.subjects.some(sub => sub.score > 0))
      .reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);

    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data, completedCount]);

  const getStatus = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    // Only allowed in Semester 1 perspective, but adds to all semesters
    const newId = generateId();
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
    }));
    setData({ ...data, semesters: newSemesters });
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    const newSemesters = data.semesters.map(s => {
      // If updating name, update in ALL semesters to keep sync
      if (field === 'name') {
        return {
          ...s,
          subjects: s.subjects.map(sub => 
            sub.id === subId ? { ...sub, name: value as string } : sub
          )
        };
      }
      // If updating score, only update the ACTIVE semester
      if (s.id === activeSemesterId) {
        return {
          ...s,
          subjects: s.subjects.map(sub => 
            sub.id === subId ? { ...sub, [field]: value } : sub
          )
        };
      }
      return s;
    });
    setData({ ...data, semesters: newSemesters });
  };

  const handleDeleteSubject = (subId: string) => {
    // Deleting from one deletes from all (since list is synced)
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: s.subjects.filter(sub => sub.id !== subId)
    }));
    setData({ ...data, semesters: newSemesters });
  };

  return (
    <div className="min-h-screen pb-12 transition-colors duration-500">
      {/* Header */}
      <header className="border-b border-white/10 glass-card sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-cyan-500 flex items-center justify-center shadow-[0_0_15px_rgba(34,211,238,0.5)]">
              <span className="text-white font-bold text-xl">S</span>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-white flex items-center gap-1">
              SMART <span className="text-cyan-400">RAPOR</span>
            </h1>
          </div>
          <div className="hidden md:flex items-center gap-4 text-xs tech-font text-slate-400">
            <span>CORE_SYNC: ACTIVE</span>
            <div className="w-2 h-2 rounded-full bg-cyan-500 animate-pulse"></div>
            <span>DAFID_TECH</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 mt-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Summary & Target */}
        <aside className="lg:col-span-4 space-y-6">
          <section className="glass-card rounded-2xl p-6 relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-32 h-32 bg-cyan-500/10 blur-3xl -mr-16 -mt-16 rounded-full group-hover:bg-cyan-500/20 transition-colors"></div>
            <h2 className="text-slate-400 text-sm font-medium mb-1 tracking-wider uppercase">Rata-rata Total</h2>
            <div className="flex items-baseline gap-2">
              <span className="text-5xl font-bold tech-font text-white">{overallAvg.toFixed(1)}</span>
              <span className="text-slate-500 text-sm">/ 100</span>
            </div>
            <div className={`mt-4 inline-flex items-center px-3 py-1 rounded-full border text-xs font-semibold ${getStatus(overallAvg)}`}>
              {overallAvg >= data.targetAvg ? 'Status: Aman' : 'Status: Perlu Usaha'}
            </div>
          </section>

          {/* New Section: Subject Averages */}
          {subjectAverages.length > 0 && (
            <section className="glass-card rounded-2xl p-6 border-t-4 border-cyan-500/50">
              <h2 className="text-white font-semibold mb-4 text-sm uppercase tracking-widest">Rata-rata Per Mapel</h2>
              <div className="space-y-3 max-h-60 overflow-y-auto pr-2 scrollbar-thin">
                {subjectAverages.map(item => (
                  <div key={item.id} className="flex justify-between items-center bg-slate-900/40 p-3 rounded-xl border border-white/5">
                    <span className="text-slate-300 text-xs truncate max-w-[150px]">{item.name || 'Mapel Baru'}</span>
                    <span className="tech-font text-cyan-400 font-bold text-sm">{item.avg.toFixed(1)}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          <section className="glass-card rounded-2xl p-6 border-l-4 border-cyan-500">
            <h2 className="text-white font-semibold mb-4 flex items-center gap-2">
               Target Akademik
            </h2>
            <div className="space-y-4">
              <div>
                <label className="block text-xs text-slate-400 mb-1 tracking-wider uppercase">Target Rata-rata</label>
                <div className="relative">
                  <input 
                    type="number" 
                    value={data.targetAvg}
                    onChange={(e) => setData({ ...data, targetAvg: Number(e.target.value) })}
                    className="w-full bg-slate-900/50 border border-white/10 rounded-xl px-4 py-2 text-white tech-font focus:ring-2 focus:ring-cyan-500 outline-none transition-all"
                  />
                  <span className="absolute right-4 top-2 text-slate-500">%</span>
                </div>
              </div>
              <div>
                <label className="block text-xs text-slate-400 mb-1 tracking-wider uppercase">Total Semester</label>
                <input 
                  type="number" 
                  value={data.totalSemestersTarget}
