                  className="w-full bg-slate-900/50 border border-white/10 rounded-xl px-4 py-2 text-white tech-font focus:ring-2 focus:ring-cyan-500 outline-none transition-all"
                />
              </div>
            </div>
          </section>

          <section className="glass-card rounded-2xl p-6 bg-gradient-to-br from-slate-800/50 to-slate-900/50">
            <h2 className="text-white font-semibold mb-4">Analisis Estimasi</h2>
            <div className="space-y-4">
              <div className="p-4 rounded-xl bg-white/5 border border-white/5">
                <p className="text-xs text-slate-400 mb-2 uppercase tracking-tighter">Minimal Nilai Semester Sisa</p>
                <p className={`text-3xl font-bold tech-font ${neededAvg > 100 ? 'text-rose-500' : 'text-emerald-400'}`}>
                  {neededAvg > 100 ? 'OUT OF REACH' : neededAvg.toFixed(1)}
                </p>
              </div>
              <p className="text-xs text-slate-400 leading-relaxed italic border-l-2 border-slate-700 pl-3">
                {neededAvg > 0 
                  ? `Dibutuhkan rata-rata ${neededAvg.toFixed(1)} pada semester yang belum diisi untuk mencapai target akhir ${data.targetAvg}.`
                  : 'Target Anda saat ini sudah terpenuhi secara rata-rata.'}
              </p>
            </div>
          </section>
        </aside>

        {/* Right Column: Semester Management */}
        <div className="lg:col-span-8 space-y-6">
          {/* Semester Tabs */}
          <div className="flex overflow-x-auto gap-2 pb-2 scrollbar-hide">
            {data.semesters.map(sem => (
              <button
                key={sem.id}
                onClick={() => setActiveSemesterId(sem.id)}
                className={`flex-shrink-0 px-6 py-3 rounded-xl transition-all duration-300 font-medium ${
                  activeSemesterId === sem.id 
                    ? 'bg-cyan-500 text-white shadow-[0_0_20px_rgba(34,211,238,0.4)]' 
                    : 'glass-card text-slate-400 hover:text-white'
                }`}
              >
                Semester {sem.id}
              </button>
            ))}
          </div>

          <section className="glass-card rounded-3xl p-4 md:p-8 min-h-[500px] relative overflow-hidden">
            {/* Background decorative element */}
            <div className="absolute -bottom-20 -right-20 w-64 h-64 bg-cyan-500/5 blur-[100px] rounded-full pointer-events-none"></div>

            <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
              <div>
                <h3 className="text-2xl font-bold text-white flex items-center gap-3">
                  Data Semester {activeSemesterId}
                  {activeSemesterId !== 1 && (
                    <span className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded border border-white/5 font-normal">SINKRONISASI AKTIF</span>
                  )}
                </h3>
                <p className="text-slate-400 text-sm">Rata-rata Semester ini: <span className="tech-font text-cyan-400 font-bold ml-1">{calculateSemesterAverage(activeSemester).toFixed(1)}</span></p>
              </div>

              {activeSemesterId === 1 && (
                <button 
                  onClick={handleAddSubject}
                  className="bg-cyan-500/10 hover:bg-cyan-500/20 text-cyan-400 px-5 py-2.5 rounded-xl flex items-center justify-center gap-2 transition-all border border-cyan-500/30 font-semibold text-sm"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                  <span>Tambah Mapel</span>
                </button>
              )}
            </div>

            {activeSemesterId !== 1 && activeSemester.subjects.length === 0 && (
              <div className="bg-amber-400/10 border border-amber-400/20 p-4 rounded-2xl mb-6 flex items-start gap-3">
                <svg className="w-5 h-5 text-amber-400 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                <p className="text-xs text-amber-200/80 leading-relaxed">
                  Daftar mata pelajaran kosong. Silakan tambahkan mata pelajaran di <b>Semester 1</b> terlebih dahulu. Semester ini akan mengikuti daftar tersebut secara otomatis.
                </p>
              </div>
            )}

            {activeSemester.subjects.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center opacity-40">
                <div className="w-20 h-20 rounded-full bg-slate-800 flex items-center justify-center mb-6">
                   <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
                </div>
                <p className="text-slate-300 font-medium">Belum ada data mata pelajaran.</p>
                {activeSemesterId === 1 && (
                  <button onClick={handleAddSubject} className="mt-4 text-cyan-400 hover:text-cyan-300 transition-colors text-sm font-bold">MULAI TAMBAH MAPEL</button>
                )}
              </div>
            ) : (
              <div className="space-y-4">
                {activeSemester.subjects.map((sub, idx) => (
                  <div key={sub.id} className="group flex flex-col md:row gap-3 md:items-center bg-slate-900/50 p-4 rounded-2xl border border-white/5 hover:border-cyan-500/40 transition-all duration-300">
                    <div className="flex items-center gap-3 flex-grow">
                      <span className="tech-font text-[10px] text-slate-600 bg-slate-800 w-7 h-7 rounded-full flex items-center justify-center border border-white/5">
                        {(idx + 1).toString().padStart(2, '0')}
                      </span>
                      <input 
                        type="text" 
                        placeholder="Nama Mata Pelajaran"
                        value={sub.name}
                        readOnly={activeSemesterId !== 1}
                        onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)}
                        className={`flex-grow bg-transparent border-none focus:ring-0 text-white font-semibold placeholder:text-slate-700 outline-none ${activeSemesterId !== 1 ? 'cursor-default opacity-80' : ''}`}
                      />
                    </div>

                    <div className="flex items-center gap-3 ml-10 md:ml-0">
                      <div className="relative group/input">
                        <label className="absolute -top-6 left-0 text-[10px] text-slate-500 opacity-0 group-hover/input:opacity-100 transition-opacity">NILAI</label>
                        <input 
                          type="number" 
                          placeholder="0"
                          min="0"
                          max="100"
                          value={sub.score || ''}
                          onChange={(e) => {
                            let val = parseInt(e.target.value) || 0;
                            if (val > 100) val = 100;
                            if (val < 0) val = 0;
                            handleUpdateSubject(sub.id, 'score', val);
                          }}
                          className="w-24 bg-slate-800/80 border border-white/10 rounded-xl px-3 py-2 text-center text-cyan-400 tech-font font-bold focus:ring-2 focus:ring-cyan-500 outline-none transition-all"
                        />
                      </div>

                      {activeSemesterId === 1 && (
                        <button 
                          onClick={() => handleDeleteSubject(sub.id)}
                          className="text-slate-600 hover:text-rose-500 p-2.5 rounded-xl hover:bg-rose-500/10 transition-all"
                          title="Hapus Mapel"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </section>
        </div>
      </main>

      {/* Footer */}
      <footer className="mt-20 border-t border-white/5 py-12">
        <div className="max-w-6xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-8">
          <div className="text-center md:text-left">
            <div className="flex items-center gap-2 justify-center md:justify-start mb-2">
              <div className="w-6 h-6 rounded bg-cyan-500/20 border border-cyan-500/40 flex items-center justify-center">
                <span className="text-cyan-400 font-bold text-xs">D</span>
              </div>
              <p className="text-white font-bold tracking-wider tech-font text-sm">Website by Dafid</p>
            </div>
            <p className="text-slate-500 text-[11px] uppercase tracking-widest">Digital Academic Record Management System</p>
          </div>

          <a 
            href="https://dapidhub.my.id" 
            target="_blank" 
            rel="noopener noreferrer"
            className="group relative px-10 py-4 bg-slate-900 border border-cyan-500/30 rounded-2xl font-bold text-white transition-all hover:border-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.1)] hover:shadow-[0_0_30px_rgba(34,211,238,0.2)]"
          >
            <span className="relative z-10 flex items-center gap-3 tech-font text-sm">
              <span className="text-cyan-400">CONNECT_TO</span> Dapidhub
              <svg className="w-4 h-4 text-cyan-400 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
            </span>
          </a>
        </div>
        <div className="text-center mt-12 text-[10px] uppercase tracking-[0.5em] text-slate-800 font-bold">
          SECURE • STABLE • SYNCED
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';

const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: AppData = {
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) setData(saved);
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || data.semesters[0],
    [data.semesters, activeSemesterId]
  );

  // Helper: Check Semester Status
  // Returns: 'empty' | 'partial' | 'complete'
  const getSemesterStatus = (semester: Semester) => {
    if (semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  };

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = data.semesters.some(s => getSemesterStatus(s) === 'complete');
    return { hasPartial, hasComplete, canCalculate: !hasPartial && hasComplete };
  }, [data.semesters]);

  const overallAvg = useMemo(() => {
    const completeSemesters = data.semesters.filter(s => getSemesterStatus(s) === 'complete');
    return calculateOverallAverage(completeSemesters);
  }, [data.semesters]);

  const subjectAverages = useMemo(() => {
    const masterSubjects = data.semesters[0].subjects;
    const completeSemesters = data.semesters.filter(s => getSemesterStatus(s) === 'complete');

    return masterSubjects.map(masterSub => {
      let sum = 0;
      let count = 0;
      completeSemesters.forEach(sem => {
        const sub = sem.subjects.find(s => s.id === masterSub.id);
        if (sub && sub.score > 0) {
          sum += sub.score;
          count++;
        }
      });
      return {
        id: masterSub.id,
        name: masterSub.name || 'Mapel Tanpa Nama',
        avg: count > 0 ? sum / count : 0
      };
    });
  }, [data.semesters]);

  const completedCount = data.semesters.filter(s => getSemesterStatus(s) === 'complete').length;

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completedCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = data.semesters
      .filter(s => getSemesterStatus(s) === 'complete')
      .reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);

    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data, completedCount]);

  const getStatus = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    const newId = generateId();
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    const newSemesters = data.semesters.map(s => {
      if (field === 'name') {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
        };
      }
      if (s.id === activeSemesterId) {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
        };
      }
      return s;
    });
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: s.subjects.filter(sub => sub.id !== subId)
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  return (
    <div className="min-h-screen pb-20 transition-all duration-500">
      <header className="border-b border-white/10 glass-card sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-cyan-500 flex items-center justify-center shadow-[0_0_15px_rgba(34,211,238,0.5)]">
              <span className="text-white font-bold text-xl">S</span>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-white">
              SMART <span className="text-cyan-400">RAPOR</span>
            </h1>
          </div>
          <div className="flex items-center gap-4 text-[10px] tech-font text-slate-500">
            <div className="flex items-center gap-1">
              <span className={`w-2 h-2 rounded-full ${validation.canCalculate ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : 'bg-rose-500 shadow-[0_0_8px_#f43f5e]'}`}></span>
              {validation.canCalculate ? 'READY' : 'INVALID_DATA'}
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8">
        {/* Input Configuration Section */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
          <div className="glass-card rounded-2xl p-4 flex flex-col justify-center">
            <label className="text-[10px] text-slate-500 uppercase tracking-widest mb-1">Target Rata-rata Akhir</label>
            <input 
              type="number" 
              value={data.targetAvg}
              onChange={(e) => { setData({ ...data, targetAvg: Number(e.target.value) }); setShowResults(false); }}
              className="bg-transparent text-2xl font-bold tech-font text-white outline-none focus:text-cyan-400 transition-colors"
            />
          </div>
          <div className="glass-card rounded-2xl p-4 flex flex-col justify-center border-l-4 border-cyan-500">
            <label className="text-[10px] text-slate-500 uppercase tracking-widest mb-1">Total Target Semester</label>
            <input 
              type="number" 
              value={data.totalSemestersTarget}
              onChange={(e) => { setData({ ...data, totalSemestersTarget: Number(e.target.value) }); setShowResults(false); }}
              className="bg-transparent text-2xl font-bold tech-font text-white outline-none focus:text-cyan-400 transition-colors"
            />
          </div>
        </section>

        {/* Semester Input Section */}
        <div className="mb-8 space-y-4">
          <div className="flex overflow-x-auto gap-2 pb-2 scrollbar-hide">
            {data.semesters.map(sem => {
              const status = getSemesterStatus(sem);
              return (
                <button
                  key={sem.id}
                  onClick={() => setActiveSemesterId(sem.id)}
                  className={`flex-shrink-0 px-6 py-3 rounded-xl transition-all relative ${
                    activeSemesterId === sem.id 
                      ? 'bg-cyan-500 text-white shadow-[0_0_20px_rgba(34,211,238,0.4)]' 
                      : 'glass-card text-slate-400 hover:text-white'
                  }`}
                >
                  <span className="text-sm font-bold">Sem {sem.id}</span>
                  {status === 'partial' && <span className="absolute -top-1 -right-1 w-3 h-3 bg-rose-500 border-2 border-slate-900 rounded-full animate-pulse"></span>}
                  {status === 'complete' && <span className="absolute -top-1 -right-1 w-3 h-3 bg-emerald-500 border-2 border-slate-900 rounded-full"></span>}
                </button>
              );
            })}
          </div>

          <section className="glass-card rounded-3xl p-6 md:p-8">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-xl font-bold text-white">Input Nilai <span className="text-cyan-400">Semester {activeSemesterId}</span></h3>
              {activeSemesterId === 1 && (
                <button onClick={handleAddSubject} className="bg-cyan-500/10 hover:bg-cyan-500/20 text-cyan-400 p-2 rounded-lg border border-cyan-500/30 transition-all">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </button>
              )}
            </div>

            <div className="space-y-3">
              {activeSemester.subjects.length === 0 ? (
                <div className="py-12 text-center text-slate-500 italic text-sm">
                  {activeSemesterId === 1 ? 'Klik ikon plus untuk menambah mata pelajaran.' : 'Tambahkan mata pelajaran di Semester 1 terlebih dahulu.'}
                </div>
              ) : (
                activeSemester.subjects.map((sub, idx) => (
                  <div key={sub.id} className="flex items-center gap-3 bg-slate-900/40 p-3 rounded-xl border border-white/5">
                    <input 
                      type="text" 
                      value={sub.name}
                      readOnly={activeSemesterId !== 1}
                      onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      className="flex-grow bg-transparent text-white text-sm outline-none font-medium px-2"
                      placeholder="Nama Mapel"
                    />
                    <input 
                      type="number" 
                      value={sub.score || ''}
                      onChange={(e) => handleUpdateSubject(sub.id, 'score', Math.min(100, Math.max(0, parseInt(e.target.value) || 0)))}
                      className="w-16 bg-slate-800 border border-white/10 rounded-lg py-1.5 text-center text-cyan-400 font-bold tech-font outline-none"
                    />
                    {activeSemesterId === 1 && (
                      <button onClick={() => handleDeleteSubject(sub.id)} className="text-slate-600 hover:text-rose-500">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    )}
                  </div>
                ))
              )}
            </div>
          </section>
        </div>

        {/* Calculation Trigger Section */}
        <div className="mt-12 text-center">
          {!validation.canCalculate && validation.hasPartial && (
            <div className="mb-4 text-rose-400 text-xs font-medium animate-bounce">
              ⚠️ Ada nilai yang belum terisi lengkap di salah satu semester aktif!
            </div>
          )}
          <button 
            disabled={!validation.canCalculate}
            onClick={() => setShowResults(true)}
            className={`px-12 py-4 rounded-2xl font-bold tech-font text-lg tracking-widest transition-all ${
              validation.canCalculate 
                ? 'bg-cyan-500 text-white shadow-[0_0_30px_rgba(34,211,238,0.4)] hover:scale-105 active:scale-95 cursor-pointer' 
                : 'bg-slate-800 text-slate-600 cursor-not-allowed border border-white/5'
            }`}
          >
            PROSES HASIL AKADEMIK
          </button>
        </div>

        {/* Results View - Hidden until requested */}
        {showResults && (
          <div className="mt-16 space-y-12 animate-[fadeIn_0.6s_ease-out]">
            <h2 className="text-2xl font-bold text-white text-center flex items-center justify-center gap-4">
              <div className="h-px w-12 bg-cyan-500/50"></div>
              LAPORAN ANALISIS
              <div className="h-px w-12 bg-cyan-500/50"></div>
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {data.semesters.map(sem => {
                const status = getSemesterStatus(sem);
                const avg = calculateSemesterAverage(sem);
                return (
                  <div key={sem.id} className="glass-card rounded-2xl p-5 border border-white/5 hover:border-cyan-500/20 transition-all">
                    <div className="flex justify-between items-start mb-4">
                      <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Sem {sem.id}</span>
                      {status === 'empty' ? (
                        <span className="text-[10px] bg-slate-800 text-slate-500 px-2 py-0.5 rounded border border-white/5">COOMING SOON</span>
                      ) : (
                        <span className="text-cyan-400 font-bold tech-font">{avg.toFixed(1)}</span>
                      )}
                    </div>
                    <div className="space-y-2 opacity-60">
                      {status === 'empty' ? (
                        <div className="h-1 bg-slate-800 rounded-full w-full"></div>
                      ) : (
                        sem.subjects.map(sub => (
                          <div key={sub.id} className="flex justify-between text-[10px] text-slate-300">
                            <span className="truncate max-w-[100px]">{sub.name}</span>
                            <span>{sub.score}</span>
                          </div>
                        ))
                      )}
                    </div>
                  </div>
                );
              })}
            </div>

