                >
                  Lihat Laporan Detail
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Detailed Results View */}
        {showResults && (
          <div className="mt-16 space-y-12 animate-[fadeIn_0.6s_ease-out]">
            <h2 className="text-2xl font-bold text-white text-center flex items-center justify-center gap-4">
              <div className="h-px w-12 bg-cyan-500/50"></div>
              LAPORAN ANALISIS DETAIL
              <div className="h-px w-12 bg-cyan-500/50"></div>
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {data.semesters.map(sem => {
                const status = getSemesterStatus(sem);
                const avg = calculateSemesterAverage(sem);
                return (
                  <div key={sem.id} className="glass-card rounded-2xl p-5 border border-white/5 hover:border-cyan-500/20 transition-all group">
                    <div className="flex justify-between items-start mb-4">
