  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) setData(saved);
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || data.semesters[0],
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = (semester: Semester) => {
    if (semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  };

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const completeSemesters = data.semesters.filter(s => getSemesterStatus(s) === 'complete');
    const hasComplete = completeSemesters.length > 0;

    // Custom Validations
    const isValidTarget = data.targetAvg >= 1 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget >= 1 && data.totalSemestersTarget <= 12;
    const semMismatch = completeSemesters.length > data.totalSemestersTarget;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      semMismatch,
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount && !semMismatch 
    };
  }, [data]);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const subjectAverages = useMemo(() => {
    const masterSubjects = data.semesters[0].subjects;
    return masterSubjects.map(masterSub => {
      let sum = 0;
      let count = 0;
      completeSemesters.forEach(sem => {
        const sub = sem.subjects.find(s => s.id === masterSub.id);
        if (sub && sub.score > 0) {
          sum += sub.score;
          count++;
        }
      });
      return {
        id: masterSub.id,
        name: masterSub.name || 'Mapel Tanpa Nama',
        avg: count > 0 ? sum / count : 0
      };
    });
  }, [data.semesters, completeSemesters]);

  const completedCount = completeSemesters.length;

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completedCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data, completedCount, completeSemesters]);

  const getStatus = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    const newId = generateId();
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    const newSemesters = data.semesters.map(s => {
      if (field === 'name') {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
        };
      }
      if (s.id === activeSemesterId) {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
        };
      }
      return s;
    });
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: s.subjects.filter(sub => sub.id !== subId)
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  return (
    <div className="min-h-screen pb-20 transition-all duration-500 bg-[#0a0f1d]">
      <header className="border-b border-white/10 glass-card sticky top-0 z-40">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-cyan-500 flex items-center justify-center shadow-[0_0_15px_rgba(34,211,238,0.5)]">
              <span className="text-white font-bold text-xl">S</span>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-white">
              SMART <span className="text-cyan-400">RAPOR</span>
            </h1>
          </div>
          <div className="flex items-center gap-4 text-[10px] tech-font text-slate-500">
            <div className="flex items-center gap-1">
              <span className={`w-2 h-2 rounded-full ${validation.canCalculate ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : 'bg-rose-500 shadow-[0_0_8px_#f43f5e]'}`}></span>
              {validation.canCalculate ? 'CORE_ACTIVE' : 'VALIDATION_REQUIRED'}
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8">
        {/* Input Configuration Section */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
          <div className="glass-card rounded-2xl p-4 flex flex-col justify-center border border-white/5">
            <label className="text-[10px] text-slate-500 uppercase tracking-widest mb-1 font-bold">Target Rata-rata (0-100)</label>
            <div className="relative">
              <input 
                type="number" 
                value={data.targetAvg || ''}
                min="0"
                max="100"
                onChange={(e) => { 
                  let val = Math.min(100, Math.max(0, Number(e.target.value)));
                  setData({ ...data, targetAvg: val }); 
                  setShowResults(false); 
                }}
                className={`bg-transparent text-2xl font-bold tech-font outline-none transition-colors w-full ${!validation.isValidTarget ? 'text-rose-400' : 'text-white focus:text-cyan-400'}`}
                placeholder="Ex: 85"
              />
            </div>
          </div>
          <div className="glass-card rounded-2xl p-4 flex flex-col justify-center border-l-4 border-cyan-500 border-t border-r border-b border-white/5">
            <label className="text-[10px] text-slate-500 uppercase tracking-widest mb-1 font-bold">Total Semester Program (1-12)</label>
            <input 
              type="number" 
              value={data.totalSemestersTarget || ''}
              min="1"
              max="12"
              onChange={(e) => { 
                let val = Math.min(12, Math.max(1, Number(e.target.value)));
                setData({ ...data, totalSemestersTarget: val }); 
                setShowResults(false); 
              }}
              className={`bg-transparent text-2xl font-bold tech-font outline-none transition-colors w-full ${!validation.isValidSemCount || validation.semMismatch ? 'text-rose-400' : 'text-white focus:text-cyan-400'}`}
              placeholder="Ex: 6"
            />
          </div>
        </section>

        {/* Semester Input Section */}
        <div className="mb-8 space-y-4">
          <div className="flex overflow-x-auto gap-2 pb-2 scrollbar-hide">
            {data.semesters.map(sem => {
              const status = getSemesterStatus(sem);
              return (
                <button
                  key={sem.id}
                  onClick={() => setActiveSemesterId(sem.id)}
                  className={`flex-shrink-0 px-6 py-3 rounded-xl transition-all relative ${
                    activeSemesterId === sem.id 
                      ? 'bg-cyan-500 text-white shadow-[0_0_20px_rgba(34,211,238,0.4)]' 
                      : 'glass-card text-slate-400 hover:text-white'
                  }`}
                >
                  <span className="text-sm font-bold">Sem {sem.id}</span>
                  {status === 'partial' && <span className="absolute -top-1 -right-1 w-3 h-3 bg-rose-500 border-2 border-slate-900 rounded-full animate-pulse"></span>}
                  {status === 'complete' && <span className="absolute -top-1 -right-1 w-3 h-3 bg-emerald-500 border-2 border-slate-900 rounded-full"></span>}
                </button>
              );
            })}
          </div>

          <section className="glass-card rounded-3xl p-6 md:p-8 border border-white/5">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-xl font-bold text-white">Entry Nilai <span className="text-cyan-400">Semester {activeSemesterId}</span></h3>
              {activeSemesterId === 1 && (
                <button onClick={handleAddSubject} className="bg-cyan-500/10 hover:bg-cyan-500/20 text-cyan-400 p-2 rounded-lg border border-cyan-500/30 transition-all">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </button>
              )}
            </div>

            <div className="space-y-3">
              {activeSemester.subjects.length === 0 ? (
                <div className="py-12 text-center text-slate-500 italic text-sm">
                  {activeSemesterId === 1 ? 'Klik ikon plus untuk menambah mata pelajaran.' : 'Daftar mata pelajaran disinkronisasi dari Semester 1.'}
                </div>
              ) : (
                activeSemester.subjects.map((sub, idx) => (
                  <div key={sub.id} className="flex items-center gap-3 bg-slate-900/40 p-3 rounded-xl border border-white/5 hover:border-white/10 transition-colors">
                    <input 
                      type="text" 
                      value={sub.name}
                      readOnly={activeSemesterId !== 1}
                      onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      className="flex-grow bg-transparent text-white text-sm outline-none font-medium px-2"
                      placeholder="Nama Mapel"
                    />
                    <div className="flex items-center gap-2">
                      <input 
                        type="number" 
                        value={sub.score || ''}
                        min="0"
                        max="100"
                        onChange={(e) => handleUpdateSubject(sub.id, 'score', Math.min(100, Math.max(0, parseInt(e.target.value) || 0)))}
                        className="w-16 bg-slate-800 border border-white/10 rounded-lg py-1.5 text-center text-cyan-400 font-bold tech-font outline-none focus:border-cyan-500/50"
                      />
                    </div>
                    {activeSemesterId === 1 && (
                      <button onClick={() => handleDeleteSubject(sub.id)} className="text-slate-600 hover:text-rose-500 p-1">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    )}
                  </div>
                ))
              )}
            </div>
          </section>
        </div>

        {/* Calculation Trigger Section */}
        <div className="mt-12 text-center space-y-4">
          {!validation.canCalculate && (
            <div className="flex flex-col gap-1 items-center">
              {validation.hasPartial && <span className="text-rose-400 text-xs font-medium">⚠️ Nilai semester aktif belum terisi lengkap!</span>}
              {!validation.hasComplete && !validation.hasPartial && <span className="text-slate-500 text-xs">ℹ️ Isi setidaknya satu semester untuk menghitung.</span>}
              {!validation.isValidTarget && <span className="text-rose-400 text-xs font-medium">⚠️ Target rata-rata harus antara 1-100.</span>}
              {validation.semMismatch && <span className="text-rose-400 text-xs font-medium">⚠️ Semester terisi melebihi Total Target Program!</span>}
            </div>
          )}
          <button 
            disabled={!validation.canCalculate}
            onClick={() => { setShowSummaryPopup(true); }}
            className={`px-12 py-4 rounded-2xl font-bold tech-font text-lg tracking-widest transition-all ${
              validation.canCalculate 
                ? 'bg-cyan-500 text-white shadow-[0_0_30px_rgba(34,211,238,0.4)] hover:scale-105 active:scale-95 cursor-pointer' 
                : 'bg-slate-800 text-slate-600 cursor-not-allowed border border-white/5 opacity-50'
            }`}
          >
            PROSES ANALISIS
          </button>
        </div>

        {/* Summary Popup Modal */}
        {showSummaryPopup && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-xl animate-[fadeIn_0.3s_ease-out]">
            <div className="glass-card rounded-[3rem] p-10 max-w-md w-full relative shadow-[0_0_80px_rgba(0,0,0,0.8)] border-cyan-500/30 border-2 overflow-hidden animate-[popIn_0.4s_ease-out]">
              <div className="absolute -top-24 -left-24 w-64 h-64 bg-cyan-500/10 blur-[100px] rounded-full"></div>

              <button 
                onClick={() => setShowSummaryPopup(false)}
                className="absolute top-8 right-8 text-slate-500 hover:text-white transition-colors bg-white/5 p-2 rounded-full"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>

              <div className="text-center relative z-10">
                <div className="inline-block px-4 py-1.5 rounded-full border border-cyan-500/30 bg-cyan-500/10 text-cyan-400 text-[10px] font-black tracking-[0.3em] mb-8">
                  CALCULATION_SUCCESS
                </div>

                <h4 className="text-slate-400 text-xs uppercase tracking-widest mb-3 font-bold">Rata-rata Total</h4>
                <div className="text-8xl font-black text-white tech-font mb-4 tracking-tighter drop-shadow-[0_0_25px_rgba(34,211,238,0.4)]">
                  {overallAvg.toFixed(1)}
                </div>

                <div className="space-y-4 mb-10">
                  <div className="flex flex-col gap-1 items-center">
                    <span className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Dihitung Dari</span>
                    <span className="text-xs text-slate-200 font-bold bg-white/5 px-3 py-1 rounded-lg border border-white/10">
                      Semester: {completeSemesters.map(s => s.id).join(', ')}
                    </span>
                  </div>

                  <div className="flex flex-col gap-1 items-center">
                    <span className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Akumulasi Skor</span>
                    <span className="text-2xl font-black text-cyan-400 tech-font">
                      {totalScore} <span className="text-slate-600 text-sm font-normal">pts</span>
                    </span>
                  </div>
                </div>

                <div className={`text-sm font-black mb-10 px-6 py-3 rounded-2xl border ${getStatus(overallAvg)} shadow-inner`}>
                   {overallAvg >= data.targetAvg ? 'GOAL_STATUS: OPTIMIZED' : 'GOAL_STATUS: RECOVERY_MODE'}
                </div>

                <button 
                  onClick={() => { setShowSummaryPopup(false); setShowResults(true); }}
                  className="w-full py-5 bg-cyan-500 text-white rounded-[1.5rem] font-black text-xs uppercase tracking-[0.2em] hover:bg-cyan-400 transition-all shadow-2xl active:scale-95 border-b-4 border-cyan-700"
                >
                  Lihat Laporan Detail
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Detailed Results View */}
        {showResults && (
          <div className="mt-16 space-y-12 animate-[fadeIn_0.6s_ease-out]">
            <h2 className="text-2xl font-black text-white text-center flex items-center justify-center gap-6">
              <div className="h-px w-16 bg-gradient-to-r from-transparent to-cyan-500/50"></div>
              DETAILED ANALYSIS
              <div className="h-px w-16 bg-gradient-to-l from-transparent to-cyan-500/50"></div>
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {data.semesters.map(sem => {
                const status = getSemesterStatus(sem);
                const avg = calculateSemesterAverage(sem);
                return (
                  <div key={sem.id} className="glass-card rounded-2xl p-6 border border-white/5 hover:border-cyan-500/20 transition-all group relative overflow-hidden">
                    {status === 'complete' && <div className="absolute top-0 right-0 w-16 h-16 bg-cyan-500/5 blur-xl -mr-8 -mt-8 rounded-full"></div>}
                    <div className="flex justify-between items-start mb-5 relative z-10">
                      <span className="text-[10px] text-slate-500 font-black uppercase tracking-[0.2em]">Sem {sem.id}</span>
                      {status === 'empty' ? (
                        <span className="text-[10px] bg-slate-800 text-slate-600 px-3 py-1 rounded-lg border border-white/5 font-bold">WAITING</span>
                      ) : (
                        <div className="text-right">
                          <span className="text-cyan-400 font-black tech-font text-xl block leading-none">{avg.toFixed(1)}</span>
                          <span className="text-[8px] text-slate-600 font-bold uppercase tracking-widest">AVRG</span>
                        </div>
                      )}
                    </div>
                    <div className="space-y-2 opacity-50 group-hover:opacity-100 transition-opacity">
                      {status === 'empty' ? (
                        <div className="h-1 bg-slate-900 rounded-full w-full"></div>
                      ) : (
                        sem.subjects.map(sub => (
                          <div key={sub.id} className="flex justify-between text-[10px] text-slate-400 font-medium">
                            <span className="truncate max-w-[120px]">{sub.name || 'Mapel'}</span>
                            <span className="text-white font-bold">{sub.score}</span>
                          </div>
                        ))
                      )}
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="glass-card rounded-3xl p-8 text-center relative overflow-hidden md:col-span-1 border-t-4 border-cyan-500 shadow-2xl">
                <h4 className="text-slate-500 text-[10px] uppercase tracking-widest mb-3 font-black">Overall Performance</h4>
                <div className="text-7xl font-black text-white tech-font drop-shadow-2xl">{overallAvg.toFixed(1)}</div>
                <div className="mt-4 flex flex-col gap-1">
                  <span className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Total Skor</span>
                  <span className="text-2xl font-black text-cyan-400 tech-font">{totalScore}</span>
                </div>
              </div>

              <div className="glass-card rounded-3xl p-8 flex flex-col justify-center md:col-span-2 bg-gradient-to-br from-[#0f172a] to-[#0a0f1d] border border-white/10 relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 p-4 opacity-5">
                   <svg className="w-24 h-24" fill="white" viewBox="0 0 24 24"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
                </div>
                <h4 className="text-slate-500 text-[10px] uppercase tracking-widest mb-6 font-black">Target & Prediction Analysis</h4>
                <div className="flex flex-col sm:flex-row sm:items-center gap-8 relative z-10">
                  <div className="text-center sm:text-left bg-emerald-500/10 p-5 rounded-2xl border border-emerald-500/20">
                    <div className="text-5xl font-black text-emerald-400 tech-font">{neededAvg.toFixed(1)}</div>
                    <p className="text-[9px] text-emerald-500/70 mt-2 uppercase font-black tracking-widest">Required Avg per Sem</p>
                  </div>
                  <div className="flex-grow text-center sm:text-left">
                    <p className="text-sm text-slate-300 italic leading-relaxed font-medium">
                      "Untuk mengamankan target <b>{data.targetAvg}</b> di akhir semester {data.totalSemestersTarget}, pertahankan rata-rata minimal <b>{neededAvg.toFixed(1)}</b> pada sisa periode akademik Anda."
                    </p>
                  </div>
                </div>
              </div>
            </div>

            <div className="glass-card rounded-[2.5rem] p-10 mb-12 border border-white/5 shadow-inner">
              <h4 className="text-white font-black mb-8 text-[11px] uppercase tracking-[0.4em] text-center opacity-70">SUBJECT_STABILITY_INDEX</h4>
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {subjectAverages.map(item => (
                  <div key={item.id} className="bg-slate-900/80 border border-white/5 p-5 rounded-[2rem] text-center group hover:bg-cyan-500/10 hover:border-cyan-500/40 transition-all duration-300 cursor-default">
                    <p className="text-[9px] text-slate-600 truncate mb-2 uppercase font-bold tracking-widest group-hover:text-cyan-400 transition-colors">{item.name || 'SUBJECT'}</p>
                    <div className="h-px w-4 bg-slate-800 mx-auto mb-2"></div>
                    <p className="tech-font font-black text-white text-2xl group-hover:scale-125 transition-transform duration-500">{item.avg.toFixed(1)}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-white/5 py-16 bg-slate-950/50 backdrop-blur-md">
        <div className="max-w-4xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-10">
          <div className="text-center md:text-left">
            <div className="flex items-center gap-3 justify-center md:justify-start mb-2">
              <div className="w-5 h-5 bg-cyan-500 rounded flex items-center justify-center font-black text-[10px] text-slate-900">D</div>
              <p className="text-white font-black tracking-[0.3em] tech-font text-sm uppercase">Website by Dafid</p>
            </div>
            <p className="text-slate-600 text-[9px] uppercase tracking-[0.4em] font-bold">AI_POWERED ACADEMIC_HUB v3.0</p>
          </div>
          <a 
            href="https://dapidhub.my.id" 
            target="_blank" 
            rel="noopener noreferrer"
            className="group px-10 py-4 bg-[#111827] border border-cyan-500/20 rounded-2xl font-black text-white transition-all hover:border-cyan-400 text-[10px] tracking-[0.3em] shadow-2xl relative overflow-hidden"
          >
            <div className="absolute inset-0 bg-cyan-500/5 group-hover:bg-cyan-500/10 transition-colors"></div>
            <span className="relative flex items-center gap-3">CONNECT_TO <span className="text-cyan-400">Dapidhub</span></span>
          </a>
        </div>
        <div className="text-center mt-16 text-[8px] uppercase tracking-[1em] text-slate-800 font-black opacity-30">
          PRECISION • ANALYTICS • FUTURE_DRIVEN
        </div>
      </footer>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes popIn {
          from { opacity: 0; transform: scale(0.8); }
          to { opacity: 1; transform: scale(1); }
        }
        .scrollbar-hide::-webkit-scrollbar {
          display: none;
        }
        .scrollbar-hide {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </div>
  );
};

export default App;

export interface Subject {
  id: string;
  name: string;
  score: number;
}

export interface Semester {
  id: number;
  subjects: Subject[];
}

export interface AppData {
  userName: string;
  semesters: Semester[];
  targetAvg: number;
  totalSemestersTarget: number;
}

export enum StatusColor {
  SAFE = 'text-emerald-400 border-emerald-400/30 bg-emerald-400/10',
  WARNING = 'text-amber-400 border-amber-400/30 bg-amber-400/10',
  DANGER = 'text-rose-400 border-rose-400/30 bg-rose-400/10'
}

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';

const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) setData(saved);
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Adjust semesters array when totalSemestersTarget changes
  useEffect(() => {
    if (!isLoaded) return;
    const target = data.totalSemestersTarget;
    if (target < 1 || target > 12) return;

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < target) {
        // Add semesters
        const toAdd = target - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0 })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > target) {
        // Truncate semesters
        return { ...prev, semesters: currentSems.slice(0, target) };
      }
      return prev;
    });

    // Ensure active semester is valid
    if (activeSemesterId > target) {
      setActiveSemesterId(1);
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || data.semesters[0] || INITIAL_DATA.semesters[0],
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = (semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  };

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const completeSemesters = data.semesters.filter(s => getSemesterStatus(s) === 'complete');
    const hasComplete = completeSemesters.length > 0;

    const isValidTarget = data.targetAvg >= 1 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget >= 1 && data.totalSemestersTarget <= 12;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount 
    };
  }, [data]);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const subjectAverages = useMemo(() => {
    const masterSubjects = data.semesters[0]?.subjects || [];
    return masterSubjects.map(masterSub => {
      let sum = 0;
      let count = 0;
      completeSemesters.forEach(sem => {
        const sub = sem.subjects.find(s => s.id === masterSub.id);
        if (sub && sub.score > 0) {
          sum += sub.score;
          count++;
        }
      });
      return {
        id: masterSub.id,
        name: masterSub.name || 'Mapel Tanpa Nama',
        avg: count > 0 ? sum / count : 0
      };
    });
  }, [data.semesters, completeSemesters]);

  const completedCount = completeSemesters.length;

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completedCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completedCount, completeSemesters]);

  const getStatus = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    const newId = generateId();
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    const newSemesters = data.semesters.map(s => {
      if (field === 'name') {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
        };
      }
      if (s.id === activeSemesterId) {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
        };
      }
      return s;
    });
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: s.subjects.filter(sub => sub.id !== subId)
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const triggerAnalysis = () => {
    setIsCalculating(true);
    setTimeout(() => {
      setIsCalculating(false);
      setShowSummaryPopup(true);
    }, 2000);
  };

  return (
    <div className="min-h-screen pb-20 transition-all duration-500 bg-[#060b18] text-slate-200">
      {/* Dynamic Header with Scanning Effect */}
      <header className="border-b border-white/5 glass-card sticky top-0 z-40 overflow-hidden">
        <div className="absolute h-0.5 bg-cyan-500/30 w-full top-0 left-0 animate-[scan_3s_linear_infinite]"></div>
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-cyan-600 to-cyan-400 flex items-center justify-center shadow-[0_0_20px_rgba(34,211,238,0.4)] border border-white/20">
              <span className="text-slate-950 font-black text-xl">R</span>
            </div>
            <h1 className="text-xl font-black tracking-tighter text-white">
              FUTURE <span className="text-cyan-400">RAPOR</span>
            </h1>
          </div>
          <div className="flex items-center gap-6 text-[10px] tech-font text-slate-500 font-bold uppercase tracking-widest">
            <div className="hidden sm:flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-cyan-500 animate-pulse"></span>
              SYS_STABLE
            </div>
            <div className="flex items-center gap-2 border-l border-white/10 pl-6">
               <span className="text-white">ID: {data.userName ? data.userName.substring(0, 10).toUpperCase() : 'ANON'}</span>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8">
        {/* Profile & Program Config */}
        <section className="grid grid-cols-1 lg:grid-cols-3 gap-4 mb-8">
          <div className="glass-card rounded-2xl p-4 lg:col-span-1 border border-white/5 group hover:border-cyan-500/20 transition-all">
            <label className="text-[9px] text-slate-500 uppercase tracking-widest mb-1 font-black block">Nama Siswa</label>
            <input 
              type="text" 
              value={data.userName}
              onChange={(e) => setData({ ...data, userName: e.target.value })}
              className="bg-transparent text-lg font-bold tech-font text-white outline-none w-full placeholder:text-slate-800"
              placeholder="Masukan Nama..."
            />
          </div>
          <div className="glass-card rounded-2xl p-4 border border-white/5 flex flex-col justify-center">
            <label className="text-[9px] text-slate-500 uppercase tracking-widest mb-1 font-black block">Target Rata-rata</label>
            <div className="flex items-center gap-2">
              <input 
                type="number" 
                value={data.targetAvg || ''}
                onChange={(e) => { 
                  const v = e.target.value === '' ? 0 : Number(e.target.value);
                  setData({ ...prev => ({ ...prev, targetAvg: v }) }); 
                  setShowResults(false); 
                }}
                className={`bg-transparent text-2xl font-black tech-font outline-none w-full ${!validation.isValidTarget ? 'text-rose-500' : 'text-cyan-400'}`}
                placeholder="0-100"
              />
              <span className="text-slate-600 font-black">%</span>
            </div>
          </div>
          <div className="glass-card rounded-2xl p-4 border-l-4 border-cyan-500 border-t border-r border-b border-white/5">
            <label className="text-[9px] text-slate-500 uppercase tracking-widest mb-1 font-black block">Total Semester Program</label>
            <div className="flex items-center gap-2">
              <input 
                type="number" 
                value={data.totalSemestersTarget || ''}
                onChange={(e) => { 
                  const v = e.target.value === '' ? 0 : Number(e.target.value);
                  setData(prev => ({ ...prev, totalSemestersTarget: v })); 
                  setShowResults(false); 
                }}
                className={`bg-transparent text-2xl font-black tech-font outline-none w-full ${!validation.isValidSemCount ? 'text-rose-500' : 'text-white'}`}
                placeholder="1-12"
              />
              <span className="text-slate-600 font-black">SEM</span>
            </div>
          </div>
        </section>

        {/* Semester Selection */}
        <div className="mb-8 space-y-4">
          <div className="flex overflow-x-auto gap-2 pb-2 scrollbar-hide no-scrollbar">
            {data.semesters.map(sem => {
              const status = getSemesterStatus(sem);
              return (
                <button
                  key={sem.id}
                  onClick={() => setActiveSemesterId(sem.id)}
                  className={`flex-shrink-0 px-8 py-3.5 rounded-2xl transition-all relative border ${
                    activeSemesterId === sem.id 
                      ? 'bg-cyan-500 text-slate-950 border-cyan-400 font-black shadow-[0_0_20px_rgba(34,211,238,0.3)]' 
                      : 'glass-card border-white/5 text-slate-500 hover:text-white font-bold'
                  }`}
                >
                  <span className="text-xs uppercase tracking-tighter">Semester {sem.id}</span>
                  {status === 'partial' && <span className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-rose-500 border-2 border-slate-950 rounded-full animate-pulse shadow-lg"></span>}
                  {status === 'complete' && <span className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-emerald-500 border-2 border-slate-950 rounded-full shadow-lg"></span>}
                </button>
              );
            })}
          </div>

          {/* Entry Card */}
          <section className="glass-card rounded-[2.5rem] p-8 border border-white/5 relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-64 h-64 bg-cyan-500/5 blur-[100px] rounded-full group-hover:bg-cyan-500/10 transition-colors"></div>

            <div className="flex items-center justify-between mb-10 relative z-10">
              <div>
                <h3 className="text-2xl font-black text-white tracking-tighter uppercase">Data Entry <span className="text-cyan-400">#S{activeSemesterId}</span></h3>
                <p className="text-[10px] text-slate-500 uppercase tracking-[0.3em] font-bold mt-1">Input performance metrics here</p>
              </div>
              {activeSemesterId === 1 && (
                <button 
                  onClick={handleAddSubject} 
                  className="bg-cyan-500 text-slate-950 p-2.5 rounded-xl hover:bg-cyan-400 transition-all shadow-lg active:scale-95 border-b-4 border-cyan-700 font-black"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
                </button>
              )}
            </div>

            <div className="space-y-3 relative z-10">
              {!activeSemester || activeSemester.subjects.length === 0 ? (
                <div className="py-20 text-center">
                  <div className="inline-block p-6 rounded-3xl bg-white/5 border border-white/5 mb-4 opacity-40">
                    <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>
                  </div>
                  <p className="text-slate-600 text-sm font-black uppercase tracking-widest italic">
                    {activeSemesterId === 1 ? 'Klik icon + untuk menambah mapel' : 'Mapel disinkronkan dari semester 1'}
                  </p>
                </div>
              ) : (
                activeSemester.subjects.map((sub, idx) => (
                  <div key={sub.id} className="flex items-center gap-4 bg-[#0d1526]/80 p-4 rounded-2xl border border-white/5 hover:border-cyan-500/30 transition-all group/item shadow-inner">
                    <div className="text-[10px] tech-font text-slate-700 font-bold w-6">{(idx + 1).toString().padStart(2, '0')}</div>
                    <input 
                      type="text" 
                      value={sub.name}
                      readOnly={activeSemesterId !== 1}
                      onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      className="flex-grow bg-transparent text-white text-sm outline-none font-bold uppercase tracking-tight placeholder:text-slate-800"
                      placeholder="NAMA MATA PELAJARAN..."
                    />
                    <div className="flex items-center gap-3">
                      <div className="relative">
                        <input 
                          type="number" 
                          value={sub.score || ''}
                          min="0"
                          max="100"
                          onChange={(e) => {
                            const val = e.target.value === '' ? 0 : Math.min(100, Math.max(0, parseInt(e.target.value) || 0));
                            handleUpdateSubject(sub.id, 'score', val);
                          }}
                          className="w-16 bg-slate-950 border border-white/10 rounded-xl py-2 text-center text-cyan-400 font-black tech-font outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500/50 transition-all text-sm"
                        />
                      </div>
                      {activeSemesterId === 1 && (
                        <button onClick={() => handleDeleteSubject(sub.id)} className="text-slate-700 hover:text-rose-500 p-2 rounded-lg hover:bg-rose-500/10 transition-all opacity-40 group-hover/item:opacity-100">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>
        </div>

        {/* Action Button */}
        <div className="mt-14 text-center">
          {!validation.canCalculate && (
            <div className="mb-6 flex flex-col gap-2 items-center text-[10px] font-black uppercase tracking-[0.2em]">
              {validation.hasPartial && <span className="text-rose-500 animate-pulse">Status: INCOMPLETE_DATA detected</span>}
              {!validation.hasComplete && !validation.hasPartial && <span className="text-slate-600">Status: WAITING_FOR_INPUT</span>}
              {!validation.isValidTarget && <span className="text-rose-500">Status: TARGET_OUT_OF_RANGE</span>}
              {!validation.isValidSemCount && <span className="text-rose-500">Status: SEM_TARGET_OUT_OF_RANGE</span>}
            </div>
          )}

          <button 
            disabled={!validation.canCalculate || isCalculating}
            onClick={triggerAnalysis}
            className={`group relative px-16 py-5 rounded-2xl font-black tech-font text-lg tracking-[0.3em] uppercase transition-all overflow-hidden ${
              validation.canCalculate && !isCalculating
                ? 'bg-cyan-500 text-slate-950 shadow-[0_0_40px_rgba(34,211,238,0.4)] hover:scale-105 active:scale-95 cursor-pointer' 
                : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-white/5 opacity-50'
            }`}
          >
            {isCalculating ? (
              <span className="flex items-center gap-3">
                <svg className="animate-spin h-5 w-5 text-slate-950" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                CALCULATING...
              </span>
            ) : (
              'Proses Analisis'
            )}
            <div className="absolute inset-0 bg-white/20 -translate-x-full group-hover:translate-x-full transition-transform duration-700 skew-x-12"></div>
          </button>
        </div>

        {/* Results Components (Summary Popup & Detail) */}
        {showSummaryPopup && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-2xl animate-[fadeIn_0.3s_ease-out]">
            <div className="glass-card rounded-[3.5rem] p-12 max-w-md w-full relative shadow-[0_0_100px_rgba(0,0,0,0.8)] border-cyan-500/20 border-2 overflow-hidden animate-[popIn_0.4s_ease-out]">
              <div className="absolute top-0 left-0 w-full h-1 bg-cyan-500/30 animate-[scan_2s_linear_infinite]"></div>

              <button 
                onClick={() => setShowSummaryPopup(false)}
                className="absolute top-10 right-10 text-slate-600 hover:text-white transition-colors bg-white/5 p-2 rounded-full border border-white/10"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>

              <div className="text-center relative z-10">
                <div className="inline-block px-5 py-2 rounded-full border border-emerald-500/30 bg-emerald-500/5 text-emerald-400 text-[9px] font-black tracking-[0.4em] mb-10">
                  REPORT_GENERATED_SUCCESSFULLY
                </div>

                <h2 className="text-white text-3xl font-black tracking-tighter mb-1 uppercase">{data.userName || 'STRANGER'}</h2>
                <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.2em] mb-8 italic">Academic Profile Summary</p>

                <div className="space-y-6 mb-12">
                   <div>
                    <h4 className="text-slate-500 text-[9px] uppercase tracking-widest mb-1 font-black">Overall Average</h4>
                    <div className="text-8xl font-black text-white tech-font tracking-tighter drop-shadow-[0_0_20px_rgba(34,211,238,0.5)]">
                      {overallAvg.toFixed(1)}
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 p-4 rounded-[1.5rem] border border-white/10">
                      <span className="text-[8px] text-slate-500 uppercase font-black block mb-1">Total Score</span>
                      <span className="text-2xl font-black text-cyan-400 tech-font">{totalScore}</span>
                    </div>
                    <div className="bg-white/5 p-4 rounded-[1.5rem] border border-white/10">
                      <span className="text-[8px] text-slate-500 uppercase font-black block mb-1">Data Source</span>
                      <span className="text-[10px] font-black text-slate-200">SEM {completeSemesters.map(s => s.id).join(', ')}</span>
                    </div>
                  </div>
                </div>

                <div className={`text-xs font-black mb-10 px-8 py-4 rounded-[2rem] border ${getStatus(overallAvg)} shadow-inner uppercase tracking-widest`}>
                   {overallAvg >= data.targetAvg ? 'System: Status_Optimized' : 'System: Recovery_Required'}
                </div>

                <button 
                  onClick={() => { setShowSummaryPopup(false); setShowResults(true); }}
                  className="w-full py-6 bg-cyan-500 text-slate-950 rounded-[2rem] font-black text-xs uppercase tracking-[0.4em] hover:bg-cyan-400 transition-all shadow-2xl active:scale-95 border-b-8 border-cyan-700"
                >
                  View Details
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Details Section */}
        {showResults && (
          <div className="mt-20 space-y-16 animate-[fadeIn_0.6s_ease-out] mb-20">
            <div className="text-center">
               <h2 className="text-3xl font-black text-white tracking-tighter uppercase mb-2">Deep Intelligence <span className="text-cyan-400">Analysis</span></h2>
               <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.3em] italic">Comprehensive performance breakdown</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {data.semesters.map(sem => {
                const status = getSemesterStatus(sem);
                const avg = calculateSemesterAverage(sem);
                return (
                  <div key={sem.id} className="glass-card rounded-3xl p-6 border border-white/5 hover:border-cyan-500/30 transition-all group relative overflow-hidden bg-gradient-to-b from-transparent to-slate-950/40">
                    <div className="flex justify-between items-start mb-6">
                      <span className="text-[10px] text-slate-600 font-black uppercase tracking-[0.2em] bg-slate-950 px-3 py-1 rounded-lg">SEM_{sem.id}</span>
                      {status === 'empty' ? (
                        <span className="text-[8px] text-slate-800 font-black tracking-widest">IDLE_STATE</span>
                      ) : (
                        <div className="text-right">
                          <span className="text-cyan-400 font-black tech-font text-2xl block leading-none">{avg.toFixed(1)}</span>
                          <span className="text-[7px] text-slate-700 font-black uppercase tracking-[0.2em]">GRADE_AVG</span>
                        </div>
                      )}
                    </div>
                    <div className="space-y-2.5 opacity-40 group-hover:opacity-100 transition-opacity">
                      {status === 'empty' ? (
                        <div className="h-1 bg-slate-900 rounded-full w-full opacity-20"></div>
                      ) : (
                        sem.subjects.map(sub => (
                          <div key={sub.id} className="flex justify-between text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                            <span className="truncate max-w-[130px]">{sub.name || 'UNNAMED_MAPEL'}</span>
                            <span className="text-white font-black">{sub.score}</span>
                          </div>
                        ))
                      )}
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="glass-card rounded-[3rem] p-10 text-center relative overflow-hidden md:col-span-1 border-t-4 border-cyan-500 shadow-2xl bg-[#0d1526]">
