export default App;

import { AppData, Semester } from './types';

export const calculateSemesterAverage = (semester: Semester): number => {
  if (!semester || semester.subjects.length === 0) return 0;
  const sum = semester.subjects.reduce((acc, sub) => acc + sub.score, 0);
  return sum / semester.subjects.length;
};

export const calculateOverallAverage = (semesters: Semester[]): number => {
  if (semesters.length === 0) return 0;
  const sumOfAverages = semesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
  return sumOfAverages / semesters.length;
};

export const STORAGE_KEY = 'future_rapor_v4_data';

export const saveToStorage = (data: AppData) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
};

export const loadFromStorage = (): AppData | null => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) return null;
  try {
    const parsed = JSON.parse(data);
    // Ensure all required fields exist
    return {
      userName: parsed.userName || '',
      semesters: parsed.semesters || [],
      targetAvg: parsed.targetAvg || 85,
      totalSemestersTarget: parsed.totalSemestersTarget || 6
    };
  } catch (e) {
    return null;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';

const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      // Only show welcome if name is missing
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  // Save Data
  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Adjust semesters array when totalSemestersTarget changes
  useEffect(() => {
    if (!isLoaded) return;
    const target = Math.max(0, data.totalSemestersTarget);

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < target) {
        // Add semesters
        const toAdd = target - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          // Sync subjects from Semester 1 if exists
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0 })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > target) {
        // Truncate semesters
        return { ...prev, semesters: currentSems.slice(0, target) };
      }
      return prev;
    });

    // Ensure active semester is valid
    if (activeSemesterId > target && target > 0) {
      setActiveSemesterId(1);
    } else if (target === 0) {
      setActiveSemesterId(0);
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = (semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  };

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const completeSemesters = data.semesters.filter(s => getSemesterStatus(s) === 'complete');
    const hasComplete = completeSemesters.length > 0;

    const isValidTarget = data.targetAvg > 0 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget > 0 && data.totalSemestersTarget <= 20;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount 
    };
  }, [data]);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const subjectAverages = useMemo(() => {
    const masterSubjects = data.semesters[0]?.subjects || [];
    return masterSubjects.map(masterSub => {
      let sum = 0;
      let count = 0;
      completeSemesters.forEach(sem => {
        const sub = sem.subjects.find(s => s.id === masterSub.id);
        if (sub && sub.score > 0) {
          sum += sub.score;
          count++;
        }
      });
      return {
        id: masterSub.id,
        name: masterSub.name || 'Mapel',
        avg: count > 0 ? sum / count : 0
      };
    });
  }, [data.semesters, completeSemesters]);

  const completedCount = completeSemesters.length;

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completedCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completedCount, completeSemesters]);

  const getStatus = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    const newId = generateId();
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    const newSemesters = data.semesters.map(s => {
      if (field === 'name') {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
        };
      }
      if (s.id === activeSemesterId) {
        return {
          ...s,
          subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
        };
      }
      return s;
    });
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    const newSemesters = data.semesters.map(s => ({
      ...s,
      subjects: s.subjects.filter(sub => sub.id !== subId)
    }));
    setData({ ...data, semesters: newSemesters });
    setShowResults(false);
  };

  const triggerAnalysis = () => {
    setIsCalculating(true);
    setTimeout(() => {
      setIsCalculating(false);
      setShowSummaryPopup(true);
    }, 2500);
  };

  return (
    <div className="min-h-screen pb-20 transition-all duration-500 bg-[#060b18] text-slate-200 selection:bg-cyan-500/30">
      {/* Welcome Modal */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-3xl animate-[fadeIn_0.5s_ease-out]">
          <div className="glass-card rounded-[3.5rem] p-12 max-w-lg w-full relative shadow-[0_0_80px_rgba(34,211,238,0.2)] border-cyan-500/30 border-2 overflow-hidden animate-[popIn_0.6s_ease-out]">
            <div className="absolute top-0 left-0 w-full h-1 bg-cyan-500/50 animate-[scan_4s_linear_infinite]"></div>
            <div className="text-center">
              <div className="w-16 h-16 bg-cyan-500 rounded-2xl mx-auto mb-8 flex items-center justify-center shadow-[0_0_30px_rgba(34,211,238,0.5)]">
                <span className="text-slate-950 font-black text-3xl">R</span>
              </div>
              <h2 className="text-4xl font-black text-white tracking-tighter mb-4 uppercase">Selamat Datang</h2>
              <p className="text-slate-400 text-sm font-bold uppercase tracking-[0.2em] mb-10 leading-relaxed italic">
                Platform Analisis Akademik Masa Depan Anda. <br/>Mulai dengan memasukan nama identitas Anda.
              </p>

              <div className="relative mb-12">
                <input 
                  type="text" 
                  value={data.userName}
                  onChange={(e) => setData(prev => ({ ...prev, userName: e.target.value }))}
                  className="w-full bg-white/5 border-2 border-white/10 rounded-3xl py-6 px-10 text-center text-xl font-bold tech-font text-white outline-none focus:border-cyan-500/50 transition-all placeholder:text-slate-800"
                  placeholder="SIAPA NAMA ANDA?"
                  onKeyDown={(e) => e.key === 'Enter' && data.userName && setShowWelcome(false)}
                />
              </div>

              <button 
                onClick={() => data.userName && setShowWelcome(false)}
                disabled={!data.userName}
                className={`w-full py-6 rounded-3xl font-black text-xs uppercase tracking-[0.5em] transition-all ${
                  data.userName 
                    ? 'bg-cyan-500 text-slate-950 shadow-[0_0_40px_rgba(34,211,238,0.4)] hover:scale-105 border-b-8 border-cyan-700 active:scale-95' 
                    : 'bg-slate-900 text-slate-700 opacity-50 cursor-not-allowed border border-white/5'
                }`}
              >
                Inisialisasi Sistem
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Dynamic Header */}
      <header className="border-b border-white/5 glass-card sticky top-0 z-40 overflow-hidden">
        <div className="absolute h-0.5 bg-cyan-500/30 w-full top-0 left-0 animate-[scan_3s_linear_infinite]"></div>
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-cyan-600 to-cyan-400 flex items-center justify-center shadow-[0_0_20px_rgba(34,211,238,0.4)] border border-white/20">
              <span className="text-slate-950 font-black text-xl">R</span>
            </div>
            <h1 className="text-xl font-black tracking-tighter text-white">
              FUTURE <span className="text-cyan-400">RAPOR</span>
