                      <p className="text-slate-600 text-sm font-black uppercase tracking-widest">
                        {activeSemesterId === 1 ? 'Belum Ada Mata Pelajaran' : 'Mapel diatur di Semester 1'}
                      </p>
                    </div>
                  ) : (
                    activeSemester.subjects.map((sub, idx) => (
                      <div key={sub.id} className="flex items-center gap-5 bg-[#0d1526]/60 p-5 rounded-[1.5rem] border border-white/5 hover:border-cyan-500/40 transition-all group/item shadow-inner">
                        <div className="text-xs tech-font text-slate-800 font-black w-8">{(idx + 1).toString().padStart(2, '0')}</div>
                        <input 
                          type="text" 
                          value={sub.name}
                          readOnly={activeSemesterId !== 1}
                          onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)}
                          className={`flex-grow bg-transparent text-white text-base outline-none font-bold uppercase tracking-tight placeholder:text-slate-800 transition-all ${activeSemesterId !== 1 ? 'opacity-60' : 'focus:text-cyan-400'}`}
                          placeholder="MATA PELAJARAN..."
                        />
                        <div className="flex items-center gap-4">
                          <div className="relative">
                            <input 
                              type="number" 
                              value={sub.score || ''}
                              min="0"
                              max="100"
                              onChange={(e) => {
                                const val = e.target.value === '' ? 0 : Math.min(100, Math.max(0, parseInt(e.target.value) || 0));
                                handleUpdateSubject(sub.id, 'score', val);
                              }}
                              className="w-20 bg-slate-950 border-2 border-white/10 rounded-[1rem] py-3 text-center text-cyan-400 font-black tech-font outline-none focus:border-cyan-500 focus:ring-4 focus:ring-cyan-500/20 transition-all text-lg"
                            />
                            {sub.score === 0 && <div className="absolute -top-1 -right-1 w-2 h-2 bg-rose-500 rounded-full"></div>}
                          </div>
                          {activeSemesterId === 1 && (
                            <button onClick={() => handleDeleteSubject(sub.id)} className="text-slate-700 hover:text-rose-500 p-2.5 rounded-xl hover:bg-rose-500/10 transition-all opacity-20 group-hover/item:opacity-100">
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                            </button>
                          )}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </>
            )}
          </section>
        </div>

        {/* Action Button */}
        <div className="mt-16 text-center">
          {!validation.canCalculate && (
            <div className="mb-8 flex flex-col gap-2 items-center text-[10px] font-black uppercase tracking-[0.3em] bg-slate-900/50 py-4 rounded-2xl border border-white/5 max-w-sm mx-auto">
              {validation.hasPartial && <span className="text-rose-500 flex items-center gap-2 animate-pulse"><span className="w-2 h-2 bg-rose-500 rounded-full"></span> ERR: INCOMPLETE_DATA</span>}
              {!validation.hasComplete && !validation.hasPartial && <span className="text-slate-600 flex items-center gap-2"><span className="w-2 h-2 bg-slate-800 rounded-full"></span> STATUS: IDLE_WAITING</span>}
              {!validation.isValidTarget && <span className="text-rose-500 flex items-center gap-2"><span className="w-2 h-2 bg-rose-500 rounded-full"></span> ERR: TARGET_INVALID</span>}
              {!validation.isValidSemCount && <span className="text-rose-500 flex items-center gap-2"><span className="w-2 h-2 bg-rose-500 rounded-full"></span> ERR: SEM_RANGE_INVALID</span>}
            </div>
          )}

          <button 
            disabled={!validation.canCalculate || isCalculating}
            onClick={triggerAnalysis}
            className={`group relative px-20 py-7 rounded-[2rem] font-black tech-font text-xl tracking-[0.4em] uppercase transition-all overflow-hidden ${
              validation.canCalculate && !isCalculating
                ? 'bg-cyan-500 text-slate-950 shadow-[0_0_50px_rgba(34,211,238,0.4)] hover:scale-110 active:scale-95 cursor-pointer border-b-8 border-cyan-700' 
                : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-white/5 opacity-40'
            }`}
          >
            {isCalculating ? (
              <span className="flex items-center gap-4">
                <svg className="animate-spin h-6 w-6 text-slate-950" viewBox="0 0 24 24">
                  <circle className="opacity-20" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-80" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Processing...
              </span>
            ) : (
              'Kalkulasi Hasil'
            )}
            <div className="absolute inset-0 bg-white/20 -translate-x-full group-hover:translate-x-full transition-transform duration-1000 skew-x-12"></div>
          </button>
        </div>

        {/* Results Components (Summary Popup & Detail) */}
        {showSummaryPopup && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl animate-[fadeIn_0.3s_ease-out]">
            <div className="glass-card rounded-[4rem] p-14 max-w-md w-full relative shadow-[0_0_120px_rgba(34,211,238,0.3)] border-cyan-500/40 border-2 overflow-hidden animate-[popIn_0.4s_ease-out]">
