                <div className={`text-xs font-black mb-12 px-10 py-5 rounded-[2.5rem] border-2 ${getStatus(overallAvg)} shadow-[inset_0_0_20px_rgba(0,0,0,0.5)] uppercase tracking-[0.2em]`}>
