                            <span className="text-white font-black">{sub.score}</span>
                          </div>
                        ))
                      )}
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
              <div className="glass-card rounded-[3.5rem] p-12 text-center relative overflow-hidden lg:col-span-1 border-t-8 border-cyan-500 shadow-2xl bg-[#0b1222]">
                <h4 className="text-slate-600 text-[10px] uppercase tracking-[0.4em] mb-6 font-black">Performance Base</h4>
                <div className="text-8xl font-black text-white tech-font drop-shadow-[0_0_20px_rgba(255,255,255,0.2)] mb-8">{overallAvg.toFixed(1)}</div>
                <div className="flex flex-col gap-4 pt-10 border-t border-white/5">
                  <span className="text-[9px] text-slate-700 uppercase font-black tracking-[0.5em]">Total Data Points</span>
                  <span className="text-4xl font-black text-cyan-400 tech-font">{totalScore} <span className="text-xs text-slate-700">pts</span></span>
