              <div className="glass-card rounded-[3.5rem] p-12 flex flex-col justify-center lg:col-span-2 border border-white/10 shadow-2xl bg-gradient-to-br from-[#0a0f1d] to-slate-950 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-12 opacity-[0.03] group-hover:opacity-[0.05] transition-opacity">
                   <svg className="w-64 h-64" fill="white" viewBox="0 0 24 24"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
                </div>
                <h4 className="text-slate-600 text-[10px] uppercase tracking-[0.4em] mb-10 font-black">Strategic Roadmap</h4>
                <div className="flex flex-col sm:flex-row sm:items-center gap-12 relative z-10">
                  <div className="text-center sm:text-left bg-cyan-500/5 p-10 rounded-[3rem] border-2 border-cyan-500/10 shadow-inner">
                    <div className="text-7xl font-black text-cyan-400 tech-font tracking-tighter">{neededAvg.toFixed(1)}</div>
                    <p className="text-[9px] text-cyan-500/50 mt-4 uppercase font-black tracking-[0.5em]">Goal Threshold</p>
                  </div>
                  <div className="flex-grow text-center sm:text-left">
                    <p className="text-lg text-slate-300 italic leading-relaxed font-medium border-l-4 border-cyan-500/40 pl-10 max-w-sm mx-auto sm:mx-0">
                      "Anda perlu mempertahankan rata-rata minimal <b className="text-white underline decoration-cyan-500/50">{neededAvg.toFixed(1)}</b> di semester sisa untuk mencapai target <b className="text-cyan-400">{data.targetAvg}%</b>."
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {/* Subject stability index */}
            <div className="glass-card rounded-[4rem] p-14 border border-white/5 bg-[#080d19] shadow-inner">
              <h4 className="text-slate-700 font-black mb-12 text-[10px] uppercase tracking-[0.8em] text-center">Stability_Metric_Cluster</h4>
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-8">
                {subjectAverages.map(item => (
                  <div key={item.id} className="bg-slate-950/80 border-2 border-white/5 p-8 rounded-[3rem] text-center group hover:bg-cyan-500/10 hover:border-cyan-500/40 transition-all duration-700 cursor-default">
                    <p className="text-[9px] text-slate-800 truncate mb-4 uppercase font-black tracking-widest group-hover:text-cyan-400 transition-colors">{item.name || 'SUBJECT'}</p>
                    <div className="h-1 w-8 bg-slate-900 mx-auto mb-5 group-hover:w-16 group-hover:bg-cyan-500/50 transition-all"></div>
                    <p className="tech-font font-black text-white text-4xl group-hover:scale-125 transition-transform duration-700">{item.avg.toFixed(1)}</p>
                  </div>
                ))}
              </div>
