        )}
      </main>

      {/* Footer Section */}
      <footer className="mt-32 border-t border-white/5 py-24 bg-slate-950/80 backdrop-blur-3xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500/10 to-transparent"></div>
        <div className="max-w-4xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-16">
          <div className="text-center md:text-left group cursor-pointer">
            <div className="flex items-center gap-4 justify-center md:justify-start mb-6">
              <div className="w-8 h-8 bg-cyan-500 rounded-xl flex items-center justify-center font-black text-[14px] text-slate-950 shadow-[0_0_25px_rgba(34,211,238,0.5)]">D</div>
              <p className="text-white font-black tracking-[0.5em] tech-font text-base uppercase group-hover:text-cyan-400 transition-all">By Dafid</p>
            </div>
            <p className="text-slate-800 text-[10px] uppercase tracking-[0.8em] font-black">Future Intel Hub v5.0.0</p>
          </div>

          <div className="flex flex-col items-center md:items-end gap-10">
             <a 
