              target="_blank" 
              rel="noopener noreferrer"
              className="group px-14 py-6 bg-slate-900 border border-white/10 rounded-[2rem] font-black text-white transition-all hover:border-cyan-400 hover:text-cyan-400 text-[11px] tracking-[0.5em] shadow-2xl relative overflow-hidden active:scale-95 hover:shadow-[0_0_50px_rgba(34,211,238,0.2)]"
            >
              <div className="absolute inset-0 bg-cyan-500/5 translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
              <span className="relative flex items-center gap-4">GO_TO_HUB <span className="text-white group-hover:text-cyan-400">Dapidhub</span></span>
