export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  // Persistence logic
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Handle dynamic semester adjustment
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(0, data.totalSemestersTarget);

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0 })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > targetCount) {
        return { ...prev, semesters: currentSems.slice(0, targetCount) };
      }
      return prev;
    });

    if (activeSemesterId > targetCount && targetCount > 0) {
      setActiveSemesterId(1);
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);
  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    const isValidTarget = data.targetAvg > 0 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget > 0;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount 
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const getStatusClass = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    const newId = generateId();
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
      }))
    }));
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => {
        if (field === 'name') {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
          };
        }
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
          };
        }
        return s;
      })
    }));
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => sub.id !== subId)
      }))
    }));
    setShowResults(false);
  };

  const triggerAnalysis = () => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setTimeout(() => {
      setIsCalculating(false);
      setShowSummaryPopup(true);
    }, 1800);
  };

  const handleExportPDF = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);

    try {
      await new Promise(resolve => setTimeout(resolve, 500));

      const canvas = await html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#060b18',
        logging: false,
        useCORS: true,
        ignoreElements: (element) => element.id === 'export-button-container'
      });

      const imgData = canvas.toDataURL('image/png');
      const pdfWidth = 450;
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'px',
        format: [pdfWidth, pdfHeight]
      });

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Rapor_Analytics_${data.userName || 'Student'}_${new Date().toLocaleDateString()}.pdf`);
    } catch (error) {
      console.error('PDF Export Failed:', error);
      alert('Gagal mengekspor PDF. Silakan coba lagi.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="min-h-screen pb-12 transition-all duration-700 bg-[#060b18] text-slate-200 selection:bg-cyan-500/30 overflow-x-hidden">

      {/* Welcome Experience */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl animate-[fadeIn_0.5s_ease-out]">
          <div className="glass-card rounded-[2rem] md:rounded-[4rem] p-6 md:p-14 max-w-lg w-full relative shadow-[0_0_80px_rgba(34,211,238,0.2)] border-cyan-500/30 border-2 overflow-hidden animate-[popIn_0.6s_ease-out]">
            <div className="absolute top-0 left-0 w-full h-1 bg-cyan-500/50 animate-[scan_4s_linear_infinite]"></div>
            <div className="text-center">
              <div className="w-14 h-14 md:w-20 md:h-20 bg-cyan-500 rounded-2xl md:rounded-3xl mx-auto mb-6 md:mb-10 flex items-center justify-center shadow-[0_0_40px_rgba(34,211,238,0.6)] border border-white/20">
                <span className="text-slate-950 font-black text-2xl md:text-4xl">R</span>
              </div>
              <h2 className="text-2xl md:text-5xl font-black text-white tracking-tighter mb-4 uppercase leading-none">Smart Rapor</h2>
              <p className="text-slate-400 text-[10px] md:text-sm font-bold uppercase tracking-[0.2em] mb-8 md:mb-10 leading-relaxed italic opacity-80">
                Next-Gen Academic Analytics Engine. <br/>Tentukan profil Anda untuk memulai.
              </p>

              <div className="relative mb-8 md:mb-12">
                <input 
                  type="text" 
                  value={data.userName}
                  onChange={(e) => setData(prev => ({ ...prev, userName: e.target.value }))}
                  className="w-full bg-slate-900/50 border-2 border-white/10 rounded-2xl md:rounded-[2rem] py-4 md:py-7 px-6 md:px-12 text-center text-base md:text-2xl font-bold tech-font text-white outline-none focus:border-cyan-500/50 transition-all placeholder:text-slate-800"
                  placeholder="SIAPA NAMA ANDA?"
                  onKeyDown={(e) => e.key === 'Enter' && data.userName && setShowWelcome(false)}
                />
              </div>

              <button 
                onClick={() => data.userName && setShowWelcome(false)}
                disabled={!data.userName}
                className={`w-full py-4 md:py-7 rounded-2xl md:rounded-[2rem] font-black text-[10px] md:text-sm uppercase tracking-[0.4em] md:tracking-[0.5em] transition-all relative overflow-hidden ${
                  data.userName 
                    ? 'bg-cyan-500 text-slate-950 shadow-[0_15px_40px_rgba(34,211,238,0.3)] hover:scale-[1.02] border-b-4 md:border-b-8 border-cyan-700 active:scale-95' 
                    : 'bg-slate-900 text-slate-700 opacity-50 cursor-not-allowed border border-white/5'
                }`}
              >
                Inisialisasi Sistem
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Usage Guide */}
      {showGuide && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-2xl animate-[fadeIn_0.3s_ease-out]">
          <div className="glass-card rounded-[2rem] md:rounded-[3.5rem] p-6 md:p-14 max-w-2xl w-full relative shadow-2xl border-white/10 border-2 overflow-y-auto max-h-[85vh]">
            <button 
              onClick={() => setShowGuide(false)}
              className="absolute top-6 right-6 md:top-8 md:right-8 text-slate-500 hover:text-white transition-colors"
            >
              <svg className="w-6 h-6 md:w-8 md:h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <h2 className="text-xl md:text-3xl font-black text-cyan-400 mb-6 md:mb-8 uppercase tracking-widest border-l-4 border-cyan-500 pl-4 md:pl-6">Operasi Sistem</h2>
            <div className="space-y-4 md:space-y-6 text-xs md:text-base text-slate-300 leading-relaxed font-medium">
              <div className="flex gap-4 md:gap-5 items-start">
                <div className="w-8 h-8 md:w-10 md:h-10 rounded-lg md:rounded-xl bg-cyan-500/10 text-cyan-400 flex items-center justify-center font-black flex-shrink-0 border border-cyan-500/20 shadow-inner text-[10px] md:text-sm">01</div>
                <p>Konfigurasi <b>Target Rata-rata</b> akhir dan <b>Total Semester</b> yang akan ditempuh.</p>
              </div>
              <div className="flex gap-4 md:gap-5 items-start">
                <div className="w-8 h-8 md:w-10 md:h-10 rounded-lg md:rounded-xl bg-cyan-500/10 text-cyan-400 flex items-center justify-center font-black flex-shrink-0 border border-cyan-500/20 shadow-inner text-[10px] md:text-sm">02</div>
                <p>Pada <b>Semester 1</b>, definisikan seluruh mata pelajaran. Daftar ini akan disinkronkan otomatis.</p>
              </div>
              <div className="flex gap-4 md:gap-5 items-start">
                <div className="w-8 h-8 md:w-10 md:h-10 rounded-lg md:rounded-xl bg-cyan-500/10 text-cyan-400 flex items-center justify-center font-black flex-shrink-0 border border-cyan-500/20 shadow-inner text-[10px] md:text-sm">03</div>
                <p>Input nilai pada setiap semester yang telah selesai.</p>
              </div>
              <div className="flex gap-4 md:gap-5 items-start">
                <div className="w-8 h-8 md:w-10 md:h-10 rounded-lg md:rounded-xl bg-cyan-500/10 text-cyan-400 flex items-center justify-center font-black flex-shrink-0 border border-cyan-500/20 shadow-inner text-[10px] md:text-sm">04</div>
                <p>Gunakan tombol <b>"Analisis Hasil"</b> untuk mendapatkan proyeksi nilai minimal sisa semester.</p>
              </div>
            </div>
            <button 
              onClick={() => setShowGuide(false)}
              className="mt-8 md:mt-12 w-full py-4 md:py-5 bg-white/5 border border-white/10 rounded-2xl font-black uppercase tracking-[0.2em] md:tracking-[0.3em] text-[10px] md:text-xs hover:bg-cyan-500 hover:text-slate-950 transition-all shadow-xl active:scale-95"
            >
              System Ready
            </button>
          </div>
        </div>
      )}

      {/* Navbar */}
      <header className="border-b border-white/5 glass-card sticky top-0 z-40 overflow-hidden backdrop-blur-3xl">
        <div className="absolute h-px bg-cyan-500/20 w-full bottom-0 left-0"></div>
        <div className="max-w-6xl mx-auto px-4 md:px-6 h-16 md:h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 md:gap-4">
