              />
              <span className={`text-lg md:text-xl font-black tech-font mb-1 md:mb-2 ${!validation.isValidTarget ? 'text-rose-500/50' : 'text-cyan-500/30'}`}>%</span>
            </div>
          </div>

          <div className={`glass-card rounded-2xl md:rounded-3xl p-5 md:p-8 border transition-all relative overflow-hidden group border-white/5 border-l-4 md:border-l-8 border-l-cyan-500`}>
