                    <div className="inline-block px-2 py-0.5 rounded-full border border-cyan-500/20 bg-cyan-500/5 text-cyan-400 text-[6px] md:text-[9px] font-black tracking-widest mt-2 uppercase">Core_Input_Active</div>
                  </div>
                  {activeSemesterId === 1 && (
                    <button 
                      onClick={handleAddSubject} 
                      className="w-full sm:w-auto bg-cyan-500 text-slate-950 px-5 md:px-8 py-3 md:py-4 rounded-xl md:rounded-2xl hover:bg-cyan-400 transition-all shadow-xl active:scale-95 border-b-4 md:border-b-8 border-cyan-700 font-black flex items-center justify-center gap-2 md:gap-4 group/btn"
