                      <svg className="w-4 h-4 md:w-6 md:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
                      <span className="text-[8px] md:text-xs uppercase tracking-[0.1em] md:tracking-[0.2em]">Add_Subject</span>
                    </button>
