                </div>

                <div className="space-y-3 md:space-y-4 relative z-10">
                  {activeSemester.subjects.length === 0 ? (
                    <div className="py-12 md:py-24 text-center border-2 md:border-4 border-dashed border-white/5 rounded-2xl md:rounded-[3rem] bg-white/5">
