                              onChange={(e) => {
                                const val = e.target.value === '' ? 0 : Math.min(100, Math.max(0, parseInt(e.target.value) || 0));
                                handleUpdateSubject(sub.id, 'score', val);
                              }}
                              className="w-10 md:w-20 bg-slate-950 border md:border-2 border-white/10 rounded-lg md:rounded-2xl py-2 md:py-3 text-center text-cyan-400 font-black tech-font outline-none focus:border-cyan-500 transition-all text-xs md:text-xl"
                              placeholder="0"
                            />
                            {activeSemesterId === 1 && (
                              <button onClick={() => handleDeleteSubject(sub.id)} className="text-slate-700 hover:text-rose-500 p-1.5 md:p-2 transition-all">
