                              </button>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </>
            ) : (
               <div className="h-[200px] flex items-center justify-center">
                  <p className="text-slate-700 text-[10px] uppercase font-black tracking-widest tech-font">Pilih_Semester_Diatas</p>
               </div>
