              validation.canCalculate && !isCalculating
                ? 'bg-cyan-500 text-slate-950 shadow-[0_15px_35px_rgba(34,211,238,0.3)] hover:scale-[1.02] active:scale-[0.98] border-b-4 md:border-b-8 border-cyan-700' 
                : 'bg-slate-900/50 text-slate-800 cursor-not-allowed border border-white/5 opacity-50'
