                <div className="grid grid-cols-2 gap-3 md:gap-5 mb-8">
                  <div className="bg-white/5 p-4 md:p-6 rounded-2xl border border-white/5">
                    <span className="text-[6px] md:text-[8px] text-slate-600 uppercase font-black block mb-1">Total Poin</span>
                    <span className="text-xl md:text-3xl font-black text-cyan-400 tech-font">{totalScore}</span>
