                    <span className="text-[10px] md:text-lg font-black text-slate-200 tech-font">{completeSemesters.length} <span className="text-[6px] md:text-[8px] text-slate-600">SEM</span></span>
                  </div>
                </div>

                <div className={`text-[8px] md:text-xs font-black mb-8 px-6 md:px-8 py-4 md:py-5 rounded-2xl md:rounded-[2rem] border-2 ${getStatusClass(overallAvg)} uppercase tracking-[0.3em]`}>
                   {overallAvg >= data.targetAvg ? 'Status: Target_Secure' : 'Status: Boost_Plan_Active'}
