               <div className="absolute top-1/2 left-0 w-full h-px bg-white/5 -z-10"></div>
               <h2 className="text-xl md:text-4xl font-black text-white tracking-tighter uppercase px-6 md:px-12 bg-[#060b18] inline-block border-x border-white/5">Analytical <span className="text-cyan-400">Roadmap</span></h2>
            </div>

            {/* Export Button Section */}
            <div id="export-button-container" className="flex justify-center">
