                  <>
                    <svg className="w-4 h-4 md:w-6 md:h-6 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M9 19l3 3m0 0l3-3m-3 3V10" /></svg>
                    <span className="text-[8px] md:text-[10px] tech-font uppercase tracking-[0.3em] font-black text-cyan-400">Export_PDF</span>
                  </>
                )}
              </button>
