                const status = getSemesterStatus(sem);
                const avg = calculateSemesterAverage(sem);
                return (
                  <div key={sem.id} className="glass-card rounded-[1.5rem] md:rounded-[2.5rem] p-6 md:p-10 border border-white/5 bg-gradient-to-br from-transparent to-slate-950/60 transition-all">
