                      <span className="text-[8px] md:text-[10px] text-slate-700 font-black uppercase tracking-[0.2em] bg-slate-950 px-3 py-1 rounded-lg">SEM_{sem.id.toString().padStart(2, '0')}</span>
                      {status === 'complete' && (
                        <div className="text-right">
                          <span className="text-cyan-400 font-black tech-font text-2xl md:text-3xl block leading-none">{avg.toFixed(1)}</span>
                        </div>
                      )}
