                        sem.subjects.map(sub => (
                          <div key={sub.id} className="flex justify-between text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-tight">
                            <span className="truncate max-w-[120px] md:max-w-[150px]">{sub.name || 'MAPEL'}</span>
                            <span className="text-white font-black">{sub.score}</span>
