                <h4 className="text-slate-600 text-[8px] md:text-[10px] uppercase tracking-[0.4em] mb-6 md:mb-8 font-black">Hasil_Kumulatif</h4>
                <div className="text-7xl md:text-[8rem] font-black text-white tech-font drop-shadow-2xl mb-8 leading-none">{overallAvg.toFixed(1)}</div>
                <div className="pt-8 md:pt-10 border-t border-white/5">
                  <span className="text-2xl md:text-4xl font-black text-cyan-400 tech-font">{totalScore} <span className="text-[8px] md:text-xs text-slate-700">PTS</span></span>
