                <div className="flex flex-col sm:flex-row sm:items-center gap-10 md:gap-12">
                  <div className="text-center sm:text-left bg-cyan-500/5 p-8 md:p-10 rounded-3xl border border-cyan-500/10">
                    <div className="text-5xl md:text-7xl font-black text-cyan-400 tech-font tracking-tighter leading-none">{neededAvg.toFixed(1)}</div>
                    <p className="text-[7px] md:text-[9px] text-cyan-500/40 mt-3 md:mt-4 uppercase font-black tracking-widest">Min_Goal_Needed</p>
                  </div>
                  <div className="flex-grow text-center sm:text-left">
                    <p className="text-sm md:text-xl text-slate-300 italic leading-relaxed font-medium border-l-2 md:border-l-4 border-cyan-500/30 pl-6 md:pl-10">
                      "Dibutuhkan rata-rata <b className="text-white">{neededAvg.toFixed(1)}</b> pada semester tersisa untuk mengamankan target <b className="text-cyan-400">{data.targetAvg}%</b>."
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
