            </div>
          </div>
        </div>
      )}

      {/* Usage Guide */}
      {showGuide && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-2xl animate-[fadeIn_0.3s_ease-out]">
          <div className="glass-card rounded-[2rem] md:rounded-[3.5rem] p-6 md:p-14 max-w-2xl w-full relative shadow-2xl border-white/10 border-2 overflow-y-auto max-h-[85vh]">
            <button 
