  "requestFramePermissions": []
}

export interface Subject {
  id: string;
  name: string;
  score: number;
}

export interface Semester {
  id: number;
  subjects: Subject[];
}

export interface AppData {
  userName: string;
  semesters: Semester[];
  targetAvg: number;
  totalSemestersTarget: number;
}

export enum StatusColor {
  SAFE = 'text-emerald-400 border-emerald-400/30 bg-emerald-400/10',
  WARNING = 'text-amber-400 border-amber-400/30 bg-amber-400/10',
  DANGER = 'text-rose-400 border-rose-400/30 bg-rose-400/10'
}

import { AppData, Semester } from './types';

export const calculateSemesterAverage = (semester: Semester): number => {
  if (!semester || semester.subjects.length === 0) return 0;
  const sum = semester.subjects.reduce((acc, sub) => acc + sub.score, 0);
  return sum / semester.subjects.length;
};

export const calculateOverallAverage = (semesters: Semester[]): number => {
  if (semesters.length === 0) return 0;
  const sumOfAverages = semesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
  return sumOfAverages / semesters.length;
};

export const STORAGE_KEY = 'smart_rapor_optimized_v1';

export const saveToStorage = (data: AppData) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
};

export const loadFromStorage = (): AppData | null => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) return null;
  try {
    const parsed = JSON.parse(data);
    return {
      userName: parsed.userName || '',
      semesters: parsed.semesters || [],
      targetAvg: parsed.targetAvg || 85,
      totalSemestersTarget: parsed.totalSemestersTarget || 6
    };
  } catch (e) {
    return null;
  }
};

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0 })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > targetCount) {
        return { ...prev, semesters: currentSems.slice(0, targetCount) };
      }
      return prev;
    });

    if (activeSemesterId > targetCount) {
      setActiveSemesterId(1);
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);
  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    const isValidTarget = data.targetAvg > 0 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget > 0;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount 
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const getStatusClass = (val: number) => {
    if (val >= data.targetAvg) return StatusColor.SAFE;
    if (val >= data.targetAvg - 5) return StatusColor.WARNING;
    return StatusColor.DANGER;
  };

  const handleAddSubject = () => {
    const newId = generateId();
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
      }))
    }));
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => {
        if (field === 'name') {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
          };
        }
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
          };
        }
        return s;
      })
    }));
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => sub.id !== subId)
      }))
    }));
    setShowResults(false);
  };

  const triggerAnalysis = () => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setTimeout(() => {
      setIsCalculating(false);
      setShowSummaryPopup(true);
    }, 1800);
  };

  const handleExportPDF = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 500));
      const canvas = await html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#060b18',
        logging: false,
        useCORS: true,
        ignoreElements: (element) => element.id === 'export-button-container'
      });
      const imgData = canvas.toDataURL('image/png');
      const pdfWidth = 450;
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'px',
        format: [pdfWidth, pdfHeight]
      });
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Rapor_${data.userName || 'Analisis'}_${new Date().toLocaleDateString()}.pdf`);
    } catch (error) {
      console.error('Export Error:', error);
      alert('Ekspor PDF gagal.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-[#060b18]">

      {/* Welcome Modal */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 md:p-6 bg-slate-950/95 backdrop-blur-3xl animate-[fadeIn_0.5s_ease-out]">
          <div className="glass-card rounded-[1.5rem] md:rounded-[3rem] p-6 md:p-12 w-full max-w-lg shadow-[0_0_80px_rgba(34,211,238,0.2)] border-cyan-500/30 border animate-[popIn_0.6s_ease-out] relative">
            <div className="text-center">
              <div className="w-16 h-16 md:w-20 md:h-20 bg-cyan-500 rounded-2xl mx-auto mb-6 flex items-center justify-center shadow-[0_0_30px_rgba(34,211,238,0.5)] border border-white/20">
                <span className="text-slate-950 font-black text-3xl md:text-4xl">R</span>
              </div>
              <h2 className="text-2xl md:text-4xl font-black text-white tracking-tighter mb-2 uppercase">Smart Rapor</h2>
              <p className="text-slate-400 text-xs md:text-sm uppercase tracking-widest mb-10 opacity-70">Sistem Analisis Akademik</p>
              <div className="mb-10">
                <input 
                  type="text" 
                  value={data.userName}
                  onChange={(e) => setData(prev => ({ ...prev, userName: e.target.value }))}
                  className="w-full bg-slate-900/50 border border-white/10 rounded-xl md:rounded-2xl py-4 px-6 text-center text-lg font-bold tech-font text-white outline-none focus:border-cyan-500 transition-all placeholder:text-slate-800"
                  placeholder="MASUKKAN NAMA ANDA"
                  onKeyDown={(e) => e.key === 'Enter' && data.userName && setShowWelcome(false)}
                />
              </div>
              <button 
                onClick={() => data.userName && setShowWelcome(false)}
                disabled={!data.userName}
                className={`w-full py-4 md:py-6 rounded-xl md:rounded-2xl font-black uppercase tracking-[0.3em] transition-all text-xs md:text-sm ${
                  data.userName ? 'bg-cyan-500 text-slate-950 shadow-lg hover:brightness-110 active:scale-95' : 'bg-slate-900 text-slate-700 opacity-50'
                }`}
              >
                Mulai Analisis
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Guide Modal */}
      {showGuide && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-2xl animate-[fadeIn_0.3s_ease-out]">
          <div className="glass-card rounded-[2rem] p-8 max-w-2xl w-full border-white/10 border relative max-h-[90vh] overflow-y-auto">
            <button onClick={() => setShowGuide(false)} className="absolute top-6 right-6 text-slate-500 hover:text-white"><svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg></button>
            <h2 className="text-2xl font-black text-cyan-400 mb-8 uppercase tracking-widest border-l-4 border-cyan-500 pl-4">Cara Kerja Sistem</h2>
            <div className="space-y-6 text-sm text-slate-300">
              {[
                "Atur target rata-rata akhir dan total semester.",
                "Di Semester 1, tambahkan semua mata pelajaran.",
                "Isi nilai di setiap semester yang telah selesai.",
                "Klik 'Analisis Hasil' untuk proyeksi sisa semester."
              ].map((step, i) => (
                <div key={i} className="flex gap-4">
                  <div className="w-8 h-8 rounded-lg bg-cyan-500/10 text-cyan-400 flex items-center justify-center font-black border border-cyan-500/20 shrink-0">0{i+1}</div>
                  <p>{step}</p>
                </div>
              ))}
            </div>
            <button onClick={() => setShowGuide(false)} className="mt-10 w-full py-4 bg-cyan-500 text-slate-950 rounded-xl font-black uppercase tracking-widest text-xs">Mengerti</button>
          </div>
        </div>
