      {/* Header */}
      <header className="sticky top-0 z-40 glass-card border-b border-white/5 backdrop-blur-2xl">
        <div className="max-w-6xl mx-auto px-4 md:px-8 h-16 md:h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-cyan-500 rounded-xl flex items-center justify-center shadow-lg border border-white/20"><span className="text-slate-950 font-black text-xl">R</span></div>
            <h1 className="text-lg md:text-2xl font-black tracking-tighter text-white">FUTURE <span className="text-cyan-400">RAPOR</span></h1>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={() => setShowGuide(true)} className="hidden sm:block text-[10px] tech-font text-slate-500 uppercase tracking-widest hover:text-cyan-400">MANUAL</button>
