              <span className="text-white font-black text-[10px] md:text-xs truncate max-w-[80px] group-hover:text-cyan-400 transition-colors uppercase">{data.userName || 'GUEST'}</span>
              <div className="w-8 h-8 bg-slate-800 rounded-full flex items-center justify-center text-cyan-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg></div>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-5xl mx-auto w-full px-4 md:px-8 py-6 md:py-12">

        {/* Mobile Guide Button */}
        <button onClick={() => setShowGuide(true)} className="sm:hidden w-full mb-6 py-3 bg-cyan-500/5 border border-cyan-500/10 rounded-xl text-[9px] font-black uppercase text-cyan-400 flex items-center justify-center gap-2">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg> PETUNJUK PENGGUNAAN
