            <label className="text-[9px] text-slate-500 uppercase font-black mb-2 block tracking-widest">Target Akhir (%)</label>
            <div className="flex items-end gap-2">
              <input type="number" inputMode="decimal" value={data.targetAvg || ''} onChange={(e) => setData(prev => ({ ...prev, targetAvg: Math.min(100, parseFloat(e.target.value) || 0) }))} className={`bg-transparent text-3xl md:text-5xl font-black tech-font outline-none w-full ${!validation.isValidTarget ? 'text-rose-500' : 'text-cyan-400'}`} placeholder="00"/>
