          <div className="glass-card rounded-2xl p-6 border border-white/5 border-l-4 border-l-cyan-500">
            <label className="text-[9px] text-slate-500 uppercase font-black mb-2 block tracking-widest">Total Semester</label>
            <div className="flex items-end gap-2">
              <input type="number" inputMode="numeric" value={data.totalSemestersTarget || ''} onChange={(e) => setData(prev => ({ ...prev, totalSemestersTarget: Math.min(12, parseInt(e.target.value) || 0) }))} className="bg-transparent text-3xl md:text-5xl font-black tech-font outline-none w-full text-white" placeholder="00"/>
              <span className="text-lg font-black tech-font text-slate-700 pb-1">SEM</span>
            </div>
          </div>
        </section>

        {/* Semester Selection */}
        <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar mb-8">
          {data.semesters.map(sem => {
            const status = getSemesterStatus(sem);
            const active = activeSemesterId === sem.id;
            return (
              <button key={sem.id} onClick={() => setActiveSemesterId(sem.id)} className={`flex-shrink-0 min-w-[90px] md:min-w-[140px] px-4 py-4 rounded-xl md:rounded-2xl transition-all border-2 relative ${active ? 'bg-cyan-500 text-slate-950 border-cyan-400 font-black shadow-lg scale-[1.02]' : 'glass-card border-white/5 text-slate-500 hover:text-white'}`}>
                <span className="text-[8px] md:text-[10px] uppercase font-bold block opacity-60">Sem</span>
                <span className="text-lg md:text-2xl tech-font leading-tight">{sem.id.toString().padStart(2, '0')}</span>
                {status === 'complete' && <div className="absolute -top-1.5 -right-1.5 w-4 h-4 md:w-5 md:h-5 bg-emerald-500 rounded-full border-2 border-[#060b18] flex items-center justify-center text-[10px] text-slate-950">✓</div>}
                {status === 'partial' && <div className="absolute -top-1.5 -right-1.5 w-4 h-4 md:w-5 md:h-5 bg-rose-500 rounded-full border-2 border-[#060b18] flex items-center justify-center text-[10px] text-white animate-pulse">!</div>}
              </button>
            );
          })}
        </div>

        {/* Input Table */}
        <section className="glass-card rounded-[2rem] p-6 md:p-10 mb-10 border-white/5 relative overflow-hidden">
          {activeSemester ? (
            <>
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-10 relative z-10">
                <div>
                  <h3 className="text-xl md:text-3xl font-black text-white uppercase tracking-tighter">Semester <span className="text-cyan-400">{activeSemesterId}</span></h3>
                  <div className="text-[8px] text-cyan-500/50 uppercase font-black tracking-widest mt-1">Status: {getSemesterStatus(activeSemester).toUpperCase()}</div>
                </div>
                {activeSemesterId === 1 && (
                  <button onClick={handleAddSubject} className="w-full sm:w-auto bg-cyan-500 text-slate-950 px-6 py-3 rounded-xl font-black flex items-center justify-center gap-2 text-xs hover:brightness-110 active:scale-95 shadow-lg border-b-4 border-cyan-700 uppercase tracking-widest">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg> Mapel
                  </button>
                )}
              </div>

              <div className="space-y-3 relative z-10">
                {activeSemester.subjects.length === 0 ? (
                  <div className="py-12 text-center border-2 border-dashed border-white/5 rounded-2xl bg-white/5">
                    <p className="text-slate-600 text-xs font-bold uppercase tracking-widest px-4 leading-relaxed">Daftar mata pelajaran kosong.{activeSemesterId !== 1 && ' Tambahkan mata pelajaran di Semester 01.'}</p>
                  </div>
                ) : (
                  activeSemester.subjects.map((sub, i) => (
                    <div key={sub.id} className="flex items-center gap-3 bg-slate-900/60 p-4 rounded-xl border border-white/5 hover:border-cyan-500/30 transition-all group">
                      <span className="text-[10px] tech-font text-slate-700 font-bold w-6">{(i+1).toString().padStart(2, '0')}</span>
                      <input type="text" value={sub.name} readOnly={activeSemesterId !== 1} onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)} className={`flex-grow bg-transparent text-white font-bold uppercase text-xs md:text-base outline-none tracking-tight ${activeSemesterId !== 1 ? 'opacity-40' : 'focus:text-cyan-400'}`} placeholder="Mata Pelajaran..."/>
                      <div className="flex items-center gap-2">
                        <input type="number" inputMode="numeric" value={sub.score || ''} onChange={(e) => handleUpdateSubject(sub.id, 'score', Math.min(100, Math.max(0, parseInt(e.target.value) || 0)))} className="w-12 md:w-20 bg-slate-950 border border-white/10 rounded-lg py-2 text-center text-cyan-400 font-black tech-font outline-none focus:border-cyan-500 text-xs md:text-lg" placeholder="0"/>
                        {activeSemesterId === 1 && (
                          <button onClick={() => handleDeleteSubject(sub.id)} className="p-2 text-slate-700 hover:text-rose-500 transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                        )}
                      </div>
                    </div>
                  ))
                )}
              </div>
            </>
          ) : <div className="py-20 text-center text-slate-700 font-black tech-font uppercase tracking-widest">Select_Semester</div>}
        </section>

        {/* Action Button */}
        <div className="max-w-xl mx-auto text-center px-4 mb-20">
          {!validation.canCalculate && (
            <div className="mb-6 space-y-1">
              {validation.hasPartial && <p className="text-[8px] md:text-[10px] text-rose-500 font-bold uppercase tracking-widest animate-pulse">⚠ LENGKAPI DATA SEMESTER</p>}
              {!validation.isValidTarget && <p className="text-[8px] md:text-[10px] text-rose-400 font-bold uppercase tracking-widest">⚠ TARGET HARUS DIISI</p>}
            </div>
          )}
          <button disabled={!validation.canCalculate || isCalculating} onClick={triggerAnalysis} className={`w-full py-5 md:py-8 rounded-2xl md:rounded-3xl font-black tech-font text-base md:text-xl uppercase tracking-[0.4em] transition-all relative overflow-hidden ${validation.canCalculate && !isCalculating ? 'bg-cyan-500 text-slate-950 shadow-2xl hover:brightness-110 active:scale-95 border-b-8 border-cyan-700' : 'bg-slate-900 text-slate-800 border border-white/5 opacity-50'}`}>
            {isCalculating ? 'Processing...' : 'Analisis Hasil'}
          </button>
        </div>

        {/* Results Modal */}
        {showSummaryPopup && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/98 backdrop-blur-3xl animate-[fadeIn_0.3s_ease-out]">
            <div className="glass-card rounded-[2.5rem] md:rounded-[4rem] p-8 md:p-14 max-w-lg w-full relative border-2 border-cyan-500/30 animate-[popIn_0.5s_ease-out] overflow-y-auto max-h-[90vh]">
              <button onClick={() => setShowSummaryPopup(false)} className="absolute top-8 right-8 text-slate-600 hover:text-white transition-all"><svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg></button>
              <div className="text-center pt-4">
                <div className="inline-block px-6 py-1.5 rounded-full border border-emerald-500/40 bg-emerald-500/10 text-emerald-400 text-[9px] font-black uppercase tracking-widest mb-8">Snapshot Selesai</div>
                <h2 className="text-white text-3xl md:text-5xl font-black tracking-tighter mb-2 uppercase truncate">{data.userName}</h2>
                <div className="bg-slate-950/80 p-8 md:p-12 rounded-[2.5rem] border border-white/5 mb-8 shadow-xl">
                  <span className="text-slate-600 text-[9px] uppercase font-black block mb-2 tracking-widest">Rata-rata Kumulatif</span>
                  <div className="text-7xl md:text-9xl font-black text-white tech-font leading-none">{overallAvg.toFixed(1)}</div>
                </div>
                <div className="grid grid-cols-2 gap-4 mb-10">
                  <div className="bg-white/5 p-4 rounded-2xl border border-white/5"><span className="text-[7px] text-slate-600 uppercase font-black block mb-1">Total Poin</span><span className="text-xl md:text-3xl font-black text-cyan-400 tech-font">{totalScore}</span></div>
                  <div className="bg-white/5 p-4 rounded-2xl border border-white/5"><span className="text-[7px] text-slate-600 uppercase font-black block mb-1">Semester</span><span className="text-xl md:text-3xl font-black text-slate-200 tech-font">{completeSemesters.length}</span></div>
                </div>
                <button onClick={() => { setShowSummaryPopup(false); setShowResults(true); }} className="w-full py-5 md:py-8 bg-cyan-500 text-slate-950 rounded-[1.5rem] md:rounded-[2.5rem] font-black text-xs md:text-sm uppercase tracking-widest hover:brightness-110 shadow-xl border-b-8 border-cyan-700">Laporan Detail</button>
              </div>
