              </div>
              <div className="glass-card rounded-[3rem] p-10 flex flex-col justify-center border border-white/5 bg-slate-950/80 shadow-2xl lg:col-span-2">
                <h4 className="text-slate-600 text-[10px] uppercase tracking-widest mb-8 font-black">Proyeksi Strategis</h4>
                <div className="flex flex-col md:flex-row items-center gap-10">
                  <div className="text-center md:text-left bg-cyan-500/5 p-8 rounded-3xl border border-cyan-500/10 shrink-0">
