                    <p className="text-[8px] text-cyan-500/40 mt-3 uppercase font-black tracking-widest">Min. Rata-rata Sisa</p>
                  </div>
                  <div className="text-center md:text-left">
                    <p className="text-base md:text-xl text-slate-300 italic leading-relaxed border-l-4 border-cyan-500/30 pl-6">
                      "Dibutuhkan rata-rata minimal <b className="text-white">{neededAvg.toFixed(1)}</b> pada semester sisa untuk mengamankan target <b className="text-cyan-400">{data.targetAvg}%</b>."
                    </p>
                  </div>
