          <div>
            <div className="flex items-center gap-3 justify-center md:justify-start mb-4">
              <div className="w-8 h-8 bg-cyan-500 rounded-lg flex items-center justify-center font-black text-slate-950">D</div>
              <p className="text-white font-black tracking-widest tech-font uppercase">By Dafid</p>
            </div>
            <p className="text-slate-800 text-[8px] uppercase tracking-widest font-black opacity-40">Academic Intel Hub v8.0.0_ULTRA</p>
          </div>
          <a href="https://dapidhub.my.id" target="_blank" rel="noopener noreferrer" className="px-10 py-4 bg-slate-900 border border-white/10 rounded-2xl font-black text-white hover:text-cyan-400 hover:border-cyan-400 transition-all text-[9px] tracking-widest uppercase">Connect Dapidhub</a>
