};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0 })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > targetCount) {
        return { ...prev, semesters: currentSems.slice(0, targetCount) };
      }
      return prev;
    });

    if (activeSemesterId > targetCount) {
      setActiveSemesterId(1);
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);
  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    const isValidTarget = data.targetAvg > 0 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget > 0;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount 
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const handleAddSubject = () => {
    const newId = generateId();
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
      }))
    }));
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => {
        if (field === 'name') {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
          };
        }
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
          };
        }
        return s;
      })
    }));
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => sub.id !== subId)
      }))
    }));
    setShowResults(false);
  };

  const triggerAnalysis = () => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setTimeout(() => {
      setIsCalculating(false);
      setShowSummaryPopup(true);
    }, 1800);
  };

  const handleExportPDF = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 500));
      const canvas = await html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#060b18',
        logging: false,
        useCORS: true,
        ignoreElements: (element) => element.id === 'export-button-container'
      });
      const imgData = canvas.toDataURL('image/png');
      const pdfWidth = 450;
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'px',
        format: [pdfWidth, pdfHeight]
      });
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Rapor_${data.userName || 'Analisis'}_${new Date().toLocaleDateString()}.pdf`);
    } catch (error) {
      console.error('Export Error:', error);
      alert('Ekspor PDF gagal.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-[#060b18] text-slate-200">

      {/* Modals & Overlays */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-2xl animate-[fadeIn_0.5s_ease-out]">
          <div className="glass-card rounded-[2rem] md:rounded-[3rem] p-8 md:p-12 w-full max-w-lg animate-[popIn_0.6s_ease-out] relative">
            <div className="text-center">
              <div className="w-16 h-16 md:w-24 md:h-24 bg-cyan-500 rounded-2xl mx-auto mb-8 flex items-center justify-center shadow-[0_0_30px_rgba(34,211,238,0.4)] border border-white/20">
                <span className="text-slate-950 font-black text-4xl md:text-5xl">R</span>
              </div>
              <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter mb-4 uppercase">Smart Rapor</h2>
              <p className="text-slate-400 text-xs md:text-sm uppercase tracking-widest mb-10 opacity-60 font-medium">Next-Gen Analytics Terminal</p>
              <div className="mb-10 group">
                <input 
                  type="text" 
                  value={data.userName}
                  onChange={(e) => setData(prev => ({ ...prev, userName: e.target.value }))}
                  className="w-full bg-slate-900/40 border border-white/10 rounded-xl md:rounded-2xl py-5 px-8 text-center text-xl font-bold tech-font text-white outline-none focus:border-cyan-500/50 transition-all placeholder:text-slate-800"
                  placeholder="IDENTIFY YOURSELF"
                  onKeyDown={(e) => e.key === 'Enter' && data.userName && setShowWelcome(false)}
                />
              </div>
              <button 
                onClick={() => data.userName && setShowWelcome(false)}
                disabled={!data.userName}
                className={`w-full py-5 md:py-7 rounded-xl md:rounded-2xl font-black uppercase tracking-[0.4em] transition-all text-xs md:text-sm ${
                  data.userName ? 'bg-cyan-500 text-slate-950 shadow-xl hover:scale-[1.02] active:scale-95' : 'bg-slate-900 text-slate-700 opacity-50 cursor-not-allowed'
                }`}
              >
                ACCESS SYSTEM
              </button>
            </div>
          </div>
        </div>
      )}

      {showGuide && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-xl animate-[fadeIn_0.3s_ease-out]">
          <div className="glass-card rounded-[2rem] p-8 md:p-12 max-w-2xl w-full border-white/10 border relative max-h-[90vh] overflow-y-auto">
            <button onClick={() => setShowGuide(false)} className="absolute top-8 right-8 text-slate-500 hover:text-white transition-colors">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <h2 className="text-2xl md:text-3xl font-black text-cyan-400 mb-10 uppercase tracking-widest border-l-4 border-cyan-500 pl-6">System Protocol</h2>
            <div className="space-y-8 text-slate-300">
              {[
                { title: "Configuration", desc: "Define your ultimate average target and program duration." },
                { title: "Initialization", desc: "Register your subjects in Semester 01 to synchronize the structure." },
                { title: "Input Flow", desc: "Update scores periodically as you complete each semester module." },
                { title: "Projections", desc: "Execute 'Analysis' to unlock future minimum requirements." }
              ].map((item, i) => (
                <div key={i} className="flex gap-6 items-start">
                  <div className="w-10 h-10 rounded-xl bg-cyan-500/10 text-cyan-400 flex items-center justify-center font-black border border-cyan-500/20 shrink-0 text-sm">0{i+1}</div>
                  <div>
                    <h4 className="text-white font-black uppercase tracking-wider text-sm mb-1">{item.title}</h4>
                    <p className="text-xs md:text-sm opacity-70 leading-relaxed">{item.desc}</p>
                  </div>
                </div>
              ))}
            </div>
            <button onClick={() => setShowGuide(false)} className="mt-12 w-full py-5 bg-white/5 hover:bg-cyan-500 hover:text-slate-950 text-white border border-white/10 rounded-xl font-black uppercase tracking-[0.3em] text-[10px] md:text-xs transition-all">TERMINATE_MODAL</button>
          </div>
        </div>
      )}

      {/* Navigation */}
      <header className="sticky top-0 z-40 glass-card border-b border-white/5 backdrop-blur-3xl">
        <div className="max-w-7xl mx-auto px-4 sm:px-8 h-18 sm:h-22 flex items-center justify-between">
          <div className="flex items-center gap-4 group cursor-pointer" onClick={() => window.scrollTo({top:0, behavior:'smooth'})}>
            <div className="w-10 h-10 sm:w-12 sm:h-12 bg-cyan-500 rounded-xl flex items-center justify-center shadow-lg border border-white/20 transition-transform group-hover:scale-110">
              <span className="text-slate-950 font-black text-xl sm:text-2xl">R</span>
            </div>
            <h1 className="text-xl sm:text-2xl font-black tracking-tighter text-white uppercase">
              FUTURE <span className="text-cyan-400">RAPOR</span>
            </h1>
          </div>
          <div className="flex items-center gap-4 sm:gap-8">
            <button onClick={() => setShowGuide(true)} className="hidden md:block text-[10px] tech-font text-slate-500 uppercase tracking-widest font-black hover:text-cyan-400 transition-colors">PROTOCOL_GUIDE</button>
            <div onClick={() => setShowWelcome(true)} className="flex items-center gap-3 border-l border-white/10 pl-4 sm:pl-8 cursor-pointer group">
              <div className="hidden sm:block text-right">
                <p className="text-[7px] font-black text-slate-500 uppercase tracking-widest">USER_ID</p>
                <p className="text-xs font-black text-white group-hover:text-cyan-400 transition-colors uppercase truncate max-w-[120px]">{data.userName || 'ANONYMOUS'}</p>
              </div>
              <div className="w-9 h-9 sm:w-11 sm:h-11 bg-slate-900 border border-white/10 rounded-full flex items-center justify-center text-cyan-400 group-hover:border-cyan-500/50 transition-all">
                <svg className="w-4 h-4 sm:w-5 sm:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-grow max-w-6xl mx-auto w-full px-4 sm:px-8 py-8 sm:py-16">

        {/* Responsive Mobile Guide Shortcut */}
        <div className="md:hidden mb-8">
          <button onClick={() => setShowGuide(true)} className="w-full py-4 bg-cyan-500/5 border border-cyan-500/20 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] text-cyan-400 flex items-center justify-center gap-3">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg> SYSTEM MANUAL
          </button>
        </div>

        {/* Global Parameters Section */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6 sm:gap-8 mb-12">
          <div className={`glass-card rounded-[2rem] p-8 border transition-all hover:scale-[1.01] ${!validation.isValidTarget ? 'border-rose-500/40 bg-rose-500/5' : 'border-white/5'}`}>
            <label className="text-[10px] text-slate-500 uppercase font-black mb-4 block tracking-[0.3em]">Cumulative Target</label>
            <div className="flex items-end gap-3">
              <input 
                type="number" 
                inputMode="decimal" 
                value={data.targetAvg || ''} 
                onChange={(e) => setData(prev => ({ ...prev, targetAvg: Math.min(100, parseFloat(e.target.value) || 0) }))} 
                className={`bg-transparent text-5xl sm:text-7xl font-black tech-font outline-none w-full placeholder:text-slate-900 ${!validation.isValidTarget ? 'text-rose-500' : 'text-cyan-400 focus:text-cyan-300'}`} 
                placeholder="00"
              />
              <span className="text-2xl font-black tech-font text-slate-700 pb-3">%</span>
            </div>
          </div>
          <div className="glass-card rounded-[2rem] p-8 border border-white/5 border-l-8 border-l-cyan-500 hover:scale-[1.01] transition-all">
            <label className="text-[10px] text-slate-500 uppercase font-black mb-4 block tracking-[0.3em]">Program Span</label>
            <div className="flex items-end gap-3">
              <input 
                type="number" 
                inputMode="numeric" 
                value={data.totalSemestersTarget || ''} 
                onChange={(e) => setData(prev => ({ ...prev, totalSemestersTarget: Math.min(12, parseInt(e.target.value) || 0) }))} 
                className="bg-transparent text-5xl sm:text-7xl font-black tech-font outline-none w-full text-white focus:text-cyan-400 placeholder:text-slate-900" 
                placeholder="00"
              />
              <span className="text-2xl font-black tech-font text-slate-700 pb-3">SEM</span>
            </div>
          </div>
        </section>

        {/* Semester Selection Hub */}
        <div className="flex gap-3 overflow-x-auto pb-6 mb-12 no-scrollbar scroll-smooth snap-x">
          {data.semesters.map(sem => {
            const status = getSemesterStatus(sem);
            const active = activeSemesterId === sem.id;
            return (
              <button 
                key={sem.id} 
                onClick={() => setActiveSemesterId(sem.id)} 
                className={`flex-shrink-0 min-w-[100px] sm:min-w-[160px] px-6 py-5 rounded-[1.5rem] sm:rounded-[2rem] transition-all border-2 relative snap-start ${active ? 'bg-cyan-500 text-slate-950 border-cyan-400 font-black shadow-[0_10px_25px_rgba(34,211,238,0.3)] scale-[1.05] z-10' : 'glass-card border-white/5 text-slate-500 hover:text-white hover:bg-white/5'}`}
              >
                <span className={`text-[8px] sm:text-[10px] uppercase font-black block mb-1 opacity-70 ${active ? 'text-slate-950' : ''}`}>MODULE</span>
                <span className="text-xl sm:text-3xl tech-font leading-none">{sem.id.toString().padStart(2, '0')}</span>
                {status === 'complete' && <div className="absolute -top-2 -right-2 w-5 h-5 sm:w-7 sm:h-7 bg-emerald-500 rounded-full border-4 border-[#060b18] flex items-center justify-center text-[10px] sm:text-sm text-slate-950">✓</div>}
                {status === 'partial' && <div className="absolute -top-2 -right-2 w-5 h-5 sm:w-7 sm:h-7 bg-rose-500 rounded-full border-4 border-[#060b18] flex items-center justify-center text-[12px] text-white animate-pulse">!</div>}
              </button>
            );
          })}
        </div>

        {/* Dynamic Entry Unit */}
        <section className="glass-card rounded-[2.5rem] sm:rounded-[4rem] p-8 sm:p-16 mb-16 border-white/5 relative overflow-hidden group">
