            <svg className="w-32 h-32 sm:w-48 sm:h-48" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/></svg>
          </div>

          {activeSemester ? (
            <>
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 mb-12 relative z-10">
                <div>
                  <h3 className="text-3xl sm:text-5xl font-black text-white uppercase tracking-tighter leading-none mb-2">Semester <span className="text-cyan-400">{activeSemesterId}</span></h3>
