                  </div>
                </div>
                {activeSemesterId === 1 && (
                  <button onClick={handleAddSubject} className="w-full sm:w-auto bg-cyan-500 text-slate-950 px-10 py-5 rounded-2xl font-black flex items-center justify-center gap-3 text-xs sm:text-sm hover:brightness-110 active:scale-95 shadow-[0_10px_20px_rgba(34,211,238,0.2)] border-b-8 border-cyan-700 uppercase tracking-widest transition-all">
