              </div>

              <div className="space-y-4 relative z-10">
                {activeSemester.subjects.length === 0 ? (
                  <div className="py-24 text-center border-4 border-dashed border-white/5 rounded-[2.5rem] bg-white/5 group-hover:bg-white/[0.08] transition-colors">
