                  </div>
                ) : (
                  <div className="grid grid-cols-1 gap-3 sm:gap-4">
                    {activeSemester.subjects.map((sub, i) => (
                      <div key={sub.id} className="flex items-center gap-4 sm:gap-8 bg-slate-900/60 p-5 sm:p-8 rounded-2xl sm:rounded-[2rem] border border-white/5 hover:border-cyan-500/40 transition-all group/row shadow-inner">
                        <span className="text-xs sm:text-base tech-font text-slate-700 font-black w-8 sm:w-12">{(i+1).toString().padStart(2, '0')}</span>
                        <input 
                          type="text" 
                          value={sub.name} 
                          readOnly={activeSemesterId !== 1} 
                          onChange={(e) => handleUpdateSubject(sub.id, 'name', e.target.value)} 
                          className={`flex-grow bg-transparent text-white font-black uppercase text-sm sm:text-2xl outline-none tracking-tight placeholder:text-slate-800 ${activeSemesterId !== 1 ? 'opacity-40' : 'focus:text-cyan-400'}`} 
                          placeholder="MAPEL_NAME..."
                        />
                        <div className="flex items-center gap-4 sm:gap-8">
                          <input 
                            type="number" 
                            inputMode="numeric" 
                            value={sub.score || ''} 
                            onChange={(e) => handleUpdateSubject(sub.id, 'score', Math.min(100, Math.max(0, parseInt(e.target.value) || 0)))} 
                            className="w-16 sm:w-28 bg-slate-950 border-2 border-white/10 rounded-xl sm:rounded-2xl py-3 sm:py-5 text-center text-cyan-400 font-black tech-font outline-none focus:border-cyan-500 text-lg sm:text-3xl shadow-inner transition-all" 
                            placeholder="0"
                          />
                          {activeSemesterId === 1 && (
                            <button onClick={() => handleDeleteSubject(sub.id)} className="p-3 text-slate-700 hover:text-rose-500 transition-all hover:scale-125">
                              <svg className="w-6 h-6 sm:w-8 sm:h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                            </button>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </>
          ) : <div className="py-32 text-center text-slate-800 font-black tech-font uppercase tracking-[1em] opacity-30">TERMINAL_STANDBY</div>}
        </section>

        {/* Processing Trigger */}
        <div className="max-w-2xl mx-auto text-center px-4 mb-32">
          <div className="mb-10 min-h-[40px]">
            {!validation.canCalculate && (
              <div className="flex flex-col items-center gap-3">
                {validation.hasPartial && <p className="text-[10px] text-rose-500 font-black uppercase tracking-[0.4em] animate-pulse">LENGKAPI DATA SELURUH MODULE</p>}
                {!validation.isValidTarget && <p className="text-[10px] text-rose-400 font-black uppercase tracking-[0.4em]">INVALID_TARGET_CONFIG</p>}
                {!validation.hasComplete && !validation.hasPartial && <p className="text-[10px] text-slate-700 font-black uppercase tracking-[0.4em]">WAITING_FOR_DATA_STREAM</p>}
              </div>
            )}
          </div>
          <button 
            disabled={!validation.canCalculate || isCalculating} 
            onClick={triggerAnalysis} 
            className={`w-full py-8 sm:py-12 rounded-[2rem] sm:rounded-[3rem] font-black tech-font text-xl sm:text-3xl uppercase tracking-[0.5em] transition-all relative overflow-hidden group ${validation.canCalculate && !isCalculating ? 'bg-cyan-500 text-slate-950 shadow-[0_20px_50px_rgba(34,211,238,0.4)] hover:brightness-110 active:scale-95 border-b-[12px] border-cyan-700' : 'bg-slate-900 text-slate-800 border border-white/5 opacity-50 cursor-not-allowed'}`}
          >
            <div className="absolute inset-0 bg-white/10 -translate-x-full group-hover:translate-x-full transition-transform duration-1000 ease-in-out"></div>
            {isCalculating ? 'ANALYST_BOOTING...' : 'RUN_ANALYTICS'}
          </button>
        </div>

        {/* Results Modal Portal */}
        {showSummaryPopup && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/98 backdrop-blur-3xl animate-[fadeIn_0.3s_ease-out]">
            <div className="glass-card rounded-[3rem] sm:rounded-[5rem] p-10 sm:p-20 max-w-2xl w-full relative border-2 border-cyan-500/30 animate-[popIn_0.5s_ease-out] overflow-y-auto max-h-[95vh] shadow-[0_0_100px_rgba(34,211,238,0.15)]">
              <button onClick={() => setShowSummaryPopup(false)} className="absolute top-10 right-10 text-slate-600 hover:text-white transition-all scale-150"><svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg></button>
              <div className="text-center pt-8">
                <div className="inline-block px-10 py-2.5 rounded-full border-2 border-emerald-500/40 bg-emerald-500/10 text-emerald-400 text-[10px] font-black uppercase tracking-[0.5em] mb-12">SUCCESS_SNAPSHOT</div>
                <h2 className="text-white text-4xl sm:text-6xl font-black tracking-tighter mb-4 uppercase truncate leading-none">{data.userName}</h2>
                <div className="bg-slate-950/80 p-10 sm:p-20 rounded-[3rem] sm:rounded-[4.5rem] border-2 border-white/5 mb-12 shadow-2xl group">
                  <span className="text-slate-600 text-[10px] sm:text-[12px] uppercase font-black block mb-4 tracking-[0.5em] group-hover:text-cyan-500 transition-colors">CUMULATIVE_INDEX</span>
                  <div className="text-8xl sm:text-[11rem] font-black text-white tech-font leading-none drop-shadow-[0_0_30px_rgba(255,255,255,0.2)]">{overallAvg.toFixed(1)}</div>
                </div>
                <div className="grid grid-cols-2 gap-6 sm:gap-10 mb-16">
                  <div className="bg-white/5 p-6 sm:p-10 rounded-3xl border border-white/5"><span className="text-[10px] text-slate-600 uppercase font-black block mb-2 tracking-widest">TOTAL_PTS</span><span className="text-3xl sm:text-5xl font-black text-cyan-400 tech-font">{totalScore}</span></div>
                  <div className="bg-white/5 p-6 sm:p-10 rounded-3xl border border-white/5"><span className="text-[10px] text-slate-600 uppercase font-black block mb-2 tracking-widest">MODULES_DONE</span><span className="text-3xl sm:text-5xl font-black text-slate-200 tech-font">{completeSemesters.length}</span></div>
                </div>
                <button onClick={() => { setShowSummaryPopup(false); setShowResults(true); }} className="w-full py-8 sm:py-10 bg-cyan-500 text-slate-950 rounded-[2rem] sm:rounded-[3rem] font-black text-sm sm:text-lg uppercase tracking-[0.5em] hover:brightness-110 shadow-[0_20px_40px_rgba(34,211,238,0.2)] border-b-[10px] border-cyan-700 transition-all active:scale-95">REVEAL_FULL_REPORT</button>
              </div>
            </div>
          </div>
        )}

        {/* Detailed Analytics Interface */}
        {showResults && (
          <div ref={reportRef} className="mt-24 sm:mt-48 space-y-24 sm:space-y-40 animate-[fadeIn_0.8s_ease-out] mb-64 px-2">
            <div className="text-center relative py-16">
               <div className="absolute top-1/2 left-0 w-full h-px bg-white/10 -z-10"></div>
               <h2 className="text-3xl sm:text-6xl font-black text-white tracking-tighter uppercase px-12 sm:px-24 bg-[#060b18] inline-block border-x-4 border-white/10">SYSTEM <span className="text-cyan-400">BLUEPRINT</span></h2>
            </div>

            <div id="export-button-container" className="flex justify-center pb-12">
              <button onClick={handleExportPDF} disabled={isExporting} className="flex items-center gap-6 bg-slate-900/80 border-2 border-cyan-500/20 px-12 py-6 rounded-2xl hover:bg-cyan-500/10 hover:border-cyan-500/50 transition-all text-cyan-400 font-black uppercase text-xs sm:text-sm tracking-[0.4em] group active:scale-95 shadow-2xl">
                <svg className="w-6 h-6 sm:w-8 sm:h-8 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M9 19l3 3m0 0l3-3m-3 3V10" /></svg>
                {isExporting ? 'ENCODING_REPORT...' : 'GENERATE_REPORT_PDF'}
              </button>
            </div>

            {/* Individual Module Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 sm:gap-12">
              {data.semesters.map(sem => {
                const status = getSemesterStatus(sem);
                const avg = calculateSemesterAverage(sem);
                return (
                  <div key={sem.id} className="glass-card rounded-[3rem] p-8 sm:p-12 border border-white/5 hover:border-cyan-500/50 hover:translate-y-[-10px] transition-all group duration-500">
                    <div className="flex justify-between items-start mb-10">
                      <span className="text-[10px] text-slate-700 font-black uppercase tracking-[0.3em] bg-slate-950 px-5 py-2 rounded-xl group-hover:text-cyan-500 transition-colors">MOD_{sem.id.toString().padStart(2, '0')}</span>
                      {status === 'complete' && <div className="text-right"><span className="text-white font-black tech-font text-3xl sm:text-4xl block leading-none drop-shadow-lg">{avg.toFixed(1)}</span></div>}
                    </div>
                    <div className="space-y-3 opacity-40 group-hover:opacity-100 transition-all duration-700">
                      {status === 'empty' ? <p className="text-[10px] text-slate-800 font-black uppercase tracking-widest py-10 text-center">PENDING_LINK</p> : sem.subjects.map(s => (
                        <div key={s.id} className="flex justify-between text-[11px] sm:text-xs text-slate-500 uppercase tracking-tight font-black border-b border-white/[0.03] pb-2 group-hover:border-white/10">
                          <span className="truncate max-w-[140px] sm:max-w-[180px] group-hover:text-slate-300 transition-colors">{s.name || 'UNIDENTIFIED'}</span>
                          <span className="text-white group-hover:text-cyan-400 transition-colors">{s.score}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Strategic Summary Panels */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 sm:gap-16">
              <div className="glass-card rounded-[4rem] p-12 sm:p-20 text-center border-t-[12px] border-cyan-500 bg-[#0a0f1d] shadow-3xl lg:col-span-1 hover:scale-[1.02] transition-transform duration-500">
                <h4 className="text-slate-600 text-[12px] uppercase tracking-[0.6em] mb-10 font-black">OVERALL_INDEX</h4>
                <div className="text-8xl sm:text-[10rem] font-black text-white tech-font mb-6 leading-none tracking-tighter">{overallAvg.toFixed(1)}</div>
                <div className="pt-12 border-t-2 border-white/5 font-black tech-font text-cyan-400 text-4xl sm:text-5xl">{totalScore} <span className="text-[12px] text-slate-800 tracking-[0.5em] block sm:inline mt-2 sm:mt-0">PTS_EARNED</span></div>
              </div>
              <div className="glass-card rounded-[4rem] p-12 sm:p-24 flex flex-col justify-center border border-white/5 bg-slate-950/90 shadow-3xl lg:col-span-2 relative overflow-hidden group/strat">
                <div className="absolute top-0 right-0 w-64 h-64 bg-cyan-500/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
                <h4 className="text-slate-600 text-[12px] uppercase tracking-[0.6em] mb-12 font-black relative z-10">STRATEGIC_PROJECTION</h4>
                <div className="flex flex-col md:flex-row items-center gap-12 sm:gap-20 relative z-10">
                  <div className="text-center md:text-left bg-cyan-500/5 p-10 rounded-[3rem] border-2 border-cyan-500/10 shrink-0 group-hover/strat:border-cyan-500/30 transition-all">
                    <div className="text-7xl sm:text-[10rem] font-black text-cyan-400 tech-font leading-none tracking-tighter drop-shadow-[0_0_20px_rgba(34,211,238,0.3)]">{neededAvg.toFixed(1)}</div>
                    <p className="text-[10px] text-cyan-500/40 mt-6 uppercase font-black tracking-[0.5em]">MIN_THRESHOLD_REQUIRED</p>
                  </div>
                  <div className="text-center md:text-left max-w-md">
                    <p className="text-lg sm:text-2xl text-slate-400 italic font-medium leading-relaxed border-l-4 sm:border-l-8 border-cyan-500/20 pl-8 sm:pl-12 group-hover/strat:text-slate-200 transition-colors">
                      "Execute with a minimum average of <b className="text-white text-xl sm:text-3xl font-black not-italic mx-2">{neededAvg.toFixed(1)}</b> in remaining modules to secure your <b className="text-cyan-400 text-xl sm:text-3xl font-black not-italic mx-2">{data.targetAvg}%</b> objective."
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Futuristic Footer */}
      <footer className="mt-40 border-t border-white/5 py-24 sm:py-32 bg-slate-950/95 text-center md:text-left">
        <div className="max-w-7xl mx-auto px-8 sm:px-16 flex flex-col md:flex-row items-center justify-between gap-16">
          <div>
            <div className="flex items-center gap-4 justify-center md:justify-start mb-6">
              <div className="w-10 h-10 bg-cyan-500 rounded-xl flex items-center justify-center font-black text-slate-950 shadow-lg">D</div>
              <p className="text-white font-black tracking-[0.6em] tech-font uppercase text-lg">By Dafid</p>
            </div>
            <p className="text-slate-800 text-[10px] uppercase tracking-[0.6em] font-black opacity-40">Academic Intel Network v8.2.5_ENTERPRISE</p>
            <p className="text-slate-800 text-[8px] uppercase tracking-[0.4em] font-black opacity-20 mt-2">SECURE_TRANSMISSION_ACTIVE</p>
          </div>
          <div className="flex flex-col sm:flex-row items-center gap-6">
            <a href="https://dapidhub.my.id" target="_blank" rel="noopener noreferrer" className="px-12 py-5 bg-slate-900 border border-white/10 rounded-2xl font-black text-white hover:text-cyan-400 hover:border-cyan-400 hover:shadow-[0_0_30px_rgba(34,211,238,0.2)] transition-all text-[11px] tracking-[0.4em] uppercase group">
              CONNECT <span className="text-cyan-500 group-hover:text-white transition-colors">DAPIDHUB</span>
            </a>
          </div>
        </div>
        <div className="text-center mt-24 text-[8px] sm:text-[12px] uppercase tracking-[2.5em] text-slate-900 font-black opacity-5 px-8 select-none">PERFORMANCE • PRECISION • PREDICTION • PROTOCOL</div>
      </footer>

      <style>{`
        @keyframes fadeIn { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes popIn { from { opacity: 0; transform: scale(0.95) translateY(50px); } to { opacity: 1; transform: scale(1) translateY(0); } }

        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #060b18; }
        ::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
        ::-webkit-scrollbar-thumb:hover { background: #334155; }

        ::selection { background: rgba(34, 211, 238, 0.3); color: white; }

        .shadow-3xl { box-shadow: 0 40px 100px -20px rgba(0, 0, 0, 0.8); }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject, StatusColor } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);
  const [showGuide, setShowGuide] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (saved.userName) setShowWelcome(false);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Sinkronisasi jumlah semester
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0 })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > targetCount) {
        return { ...prev, semesters: currentSems.slice(0, targetCount) };
      }
      return prev;
    });

    if (activeSemesterId > targetCount) {
      setActiveSemesterId(1);
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);
  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    const isValidTarget = data.targetAvg > 0 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget > 0;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount 
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const handleAddSubject = () => {
    const newId = generateId();
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
      }))
    }));
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => {
        if (field === 'name') {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, name: value as string } : sub)
          };
        }
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
          };
        }
        return s;
      })
    }));
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => sub.id !== subId)
      }))
    }));
    setShowResults(false);
  };

  const triggerAnalysis = () => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setTimeout(() => {
      setIsCalculating(false);
      setShowSummaryPopup(true);
    }, 1500);
  };

  const handleExportPDF = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 500));
      const canvas = await html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#030712',
        logging: false,
        useCORS: true,
        ignoreElements: (element) => element.id === 'export-button-container'
      });
      const imgData = canvas.toDataURL('image/png');
      const pdfWidth = 450;
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'px',
        format: [pdfWidth, pdfHeight]
      });
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Rapor_${data.userName || 'Siswa'}.pdf`);
    } catch (error) {
      console.error('Export Error:', error);
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen text-slate-100 selection:bg-cyan-500/30">

      {/* Modal Selamat Datang */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-3xl">
          <div className="glass-card rounded-[2.5rem] p-8 md:p-12 w-full max-w-lg text-center animate-in">
            <div className="w-20 h-20 bg-gradient-to-br from-cyan-400 to-indigo-500 rounded-3xl mx-auto mb-8 flex items-center justify-center shadow-2xl shadow-cyan-500/20">
              <span className="text-white font-black text-4xl">R</span>
            </div>
            <h2 className="text-3xl md:text-4xl font-extrabold text-white mb-3">Selamat Datang!</h2>
            <p className="text-slate-400 mb-10 text-sm leading-relaxed">Mari kita rencanakan kesuksesan nilai Anda. Masukkan nama Anda untuk memulai.</p>
            <div className="mb-8">
              <input 
                type="text" 
                value={data.userName}
                onChange={(e) => setData(prev => ({ ...prev, userName: e.target.value }))}
                className="w-full bg-slate-900/50 border border-white/10 rounded-2xl py-5 px-6 text-center text-xl font-bold text-white outline-none focus:border-cyan-500 transition-all placeholder:text-slate-700"
                placeholder="Nama Lengkap Anda"
                onKeyDown={(e) => e.key === 'Enter' && data.userName && setShowWelcome(false)}
              />
            </div>
            <button 
              onClick={() => data.userName && setShowWelcome(false)}
              disabled={!data.userName}
              className={`w-full py-5 rounded-2xl font-extrabold uppercase tracking-widest transition-all ${
