            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-cyan-500/10 to-transparent animate-[scan_2s_infinite]"></div>
            <div className="absolute top-0 left-0 w-full h-1 bg-cyan-400 shadow-[0_0_15px_rgba(34,211,238,1)] animate-[scan_2s_infinite]"></div>
            <div className="flex items-center justify-center h-full">
              <svg className="w-20 h-20 text-cyan-500 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
            </div>
          </div>
          <div className="mt-8 text-center">
            <p className="text-cyan-400 font-bold tech-font tracking-[0.3em] animate-pulse">
              AI SCANNING: {scanProgress.current}/{scanProgress.total}
            </p>
            <p className="mt-2 text-slate-500 text-[10px] uppercase tracking-widest">Menganalisis lembar rapor ke sistem...</p>
          </div>
        </div>
      )}

      {/* Modal Welcome */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl">
          <div className="glass-card rounded-[2rem] p-6 md:p-12 w-full max-w-md text-center animate-in shadow-2xl">
            <div className="w-16 h-16 bg-gradient-to-br from-cyan-400 to-indigo-500 rounded-2xl mx-auto mb-6 flex items-center justify-center shadow-lg">
              <span className="text-white font-black text-3xl">R</span>
            </div>
            <h2 className="text-2xl md:text-3xl font-extrabold text-white mb-2">Halo Siswa!</h2>
            <p className="text-slate-400 mb-8 text-sm md:text-base">Siap untuk melihat masa depan akademikmu?</p>
