              <button onClick={handleExportPDF} disabled={isExporting} className="flex items-center gap-3 bg-slate-900 border border-white/10 px-6 py-3 rounded-xl hover:bg-cyan-500/10 transition-all text-cyan-400 font-bold uppercase text-[10px] tracking-widest group">
                <svg className="w-5 h-5 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                {isExporting ? 'Generating PDF...' : 'Ekspor Laporan PDF'}
              </button>
            </div>

            {/* Statistik Utama */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
              <div className="glass-card rounded-[2.5rem] p-10 text-center border-t-4 border-cyan-500 bg-[#0a0f1d] lg:col-span-1 shadow-2xl">
                <h4 className="text-slate-600 text-[10px] uppercase tracking-widest mb-6 font-black">Rerata Sekarang</h4>
                <div className="text-6xl md:text-7xl font-black text-white tech-font leading-none mb-4">{overallAvg.toFixed(1)}</div>
                <div className="text-[10px] font-bold text-cyan-400 uppercase tracking-widest">{totalScore} Poin Dikumpulkan</div>
              </div>
              <div className="glass-card rounded-[2.5rem] p-8 md:p-12 flex flex-col justify-center border border-white/5 bg-slate-950/80 lg:col-span-2 shadow-2xl">
                <h4 className="text-slate-600 text-[10px] uppercase tracking-widest mb-8 font-black">Misi Masa Depan</h4>
                <div className="flex flex-col md:flex-row items-center gap-8 md:gap-12">
                  <div className="text-center md:text-left bg-cyan-500/10 p-8 rounded-[2rem] border border-cyan-500/20 shrink-0">
                    <div className="text-6xl md:text-7xl font-black text-cyan-400 tech-font leading-none">{neededAvg.toFixed(1)}</div>
                    <p className="text-[9px] text-cyan-500/60 mt-2 uppercase font-black tracking-widest">Rerata Per Smt Sisa</p>
                  </div>
                  <div className="text-center md:text-left">
                    <p className="text-sm md:text-lg text-slate-300 italic leading-relaxed border-l-2 md:border-l-4 border-cyan-500/30 pl-6 md:pl-8">
                      "Untuk mencapai target <b className="text-cyan-400">{data.targetAvg}%</b>, kamu wajib mempertahankan rata-rata <b className="text-white">{neededAvg.toFixed(1)}</b> di setiap sisa semester."
                    </p>
                    {neededAvg > 100 && (
                      <p className="mt-4 text-xs font-bold text-rose-500 uppercase tracking-widest bg-rose-500/10 p-3 rounded-xl border border-rose-500/20">
                        ⚠️ Peringatan: Target terlalu tinggi. Dibutuhkan nilai di atas 100.
                      </p>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* PETA TARGET PER MATA PELAJARAN (NEW FEATURE) */}
            <div className="space-y-10">
              <div className="flex items-center gap-4">
                <div className="h-px bg-white/5 flex-grow"></div>
                <h3 className="text-lg md:text-2xl font-black text-white uppercase tracking-tighter">Peta Target <span className="text-indigo-400">Per Mapel</span></h3>
                <div className="h-px bg-white/5 flex-grow"></div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {data.semesters[0].subjects.map((subTemplate) => {
                  const targetScore = Math.ceil(neededAvg);
                  const isRisky = targetScore > 90;
                  const isImpossible = targetScore > 100;

                  return (
                    <div key={subTemplate.id} className="glass-card rounded-3xl p-6 border-l-4 border-l-indigo-500 hover:scale-[1.02] transition-transform">
                      <div className="flex justify-between items-start mb-4">
                        <h5 className="text-xs font-black text-slate-300 uppercase truncate max-w-[70%]">{subTemplate.name}</h5>
                        <div className={`text-[8px] font-bold px-2 py-1 rounded uppercase ${isImpossible ? 'bg-rose-500 text-white' : isRisky ? 'bg-amber-500 text-slate-950' : 'bg-cyan-500/20 text-cyan-400'}`}>
                          {isImpossible ? 'Mustahil' : isRisky ? 'Prioritas' : 'Normal'}
                        </div>
                      </div>

                      <div className="space-y-3">
                        {remainingSemestersList.map(sem => (
                          <div key={sem.id} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0">
                            <span className="text-[10px] text-slate-600 font-bold">Semester {sem.id}</span>
                            <div className="flex items-center gap-2">
                               <span className={`tech-font text-lg font-black ${isImpossible ? 'text-rose-500' : 'text-white'}`}>{targetScore}</span>
                               <span className="text-[8px] text-slate-700 font-bold uppercase">Min</span>
                            </div>
                          </div>
                        ))}
                      </div>
                      <div className="mt-4 pt-4 border-t border-white/5 flex items-center gap-2">
                        <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></div>
                        <p className="text-[9px] text-slate-500 italic">Target skor minimal tiap periode</p>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Riwayat Semester */}
            <div className="space-y-10">
              <div className="flex items-center gap-4">
                <div className="h-px bg-white/5 flex-grow"></div>
                <h3 className="text-lg md:text-2xl font-black text-white uppercase tracking-tighter">Riwayat <span className="text-slate-500">Semester</span></h3>
                <div className="h-px bg-white/5 flex-grow"></div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
                {data.semesters.map(sem => {
                  const status = getSemesterStatus(sem);
                  const avg = calculateSemesterAverage(sem);
                  return (
                    <div key={sem.id} className={`glass-card rounded-[2rem] p-6 md:p-8 border border-white/5 transition-all ${status === 'complete' ? 'opacity-100' : 'opacity-40 grayscale'}`}>
                      <div className="flex justify-between items-center mb-6">
                        <span className="text-[10px] text-slate-600 font-black uppercase tracking-widest">Semester {sem.id}</span>
                        {status === 'complete' && <span className="text-cyan-400 font-black tech-font text-xl md:text-2xl">{avg.toFixed(1)}</span>}
                      </div>
                      <div className="space-y-2">
                        {status === 'empty' ? (
                          <p className="text-[9px] text-slate-800 font-black uppercase text-center py-4 italic">Belum ada data</p>
                        ) : (
                          sem.subjects.map(s => (
                            <div key={s.id} className="flex justify-between text-[10px] text-slate-400 uppercase font-bold">
                              <span className="truncate pr-2">{s.name || 'Mata Pelajaran'}</span>
                              <span className={`${s.score >= calculateOverallAverage(completeSemesters) ? 'text-white' : 'text-rose-400'} shrink-0`}>{s.score}</span>
                            </div>
                          ))
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="mt-20 border-t border-white/5 py-12 md:py-20 bg-slate-950 text-center px-4">
        <div className="max-w-6xl mx-auto flex flex-col md:flex-row items-center justify-between gap-10">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-cyan-500 rounded-lg flex items-center justify-center font-black text-slate-950 shadow-md">D</div>
            <p className="text-white font-extrabold tracking-widest uppercase text-sm">Dafid Analytics</p>
          </div>
          <div className="flex flex-col gap-2">
            <p className="text-slate-700 text-[9px] md:text-[10px] uppercase tracking-[0.4em] font-black">AI Grade Engine v10.0.0 (Experimental)</p>
            <p className="text-slate-800 text-[8px] uppercase font-bold">Terintegrasi dengan Google Gemini 3 Flash</p>
          </div>
          <a href="https://dapidhub.my.id" target="_blank" rel="noopener noreferrer" className="px-6 py-2 rounded-full border border-cyan-500/30 text-cyan-500 hover:bg-cyan-500 hover:text-slate-950 transition-all text-[10px] font-black uppercase tracking-widest">Visit Developer</a>
        </div>
      </footer>

      <style>{`
        @keyframes scan {
          0% { top: 0%; opacity: 0; }
          10% { opacity: 1; }
          90% { opacity: 1; }
          100% { top: 100%; opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';
import { GoogleGenAI, Type } from "@google/genai";

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState({ current: 0, total: 0 });
  const [showWelcome, setShowWelcome] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0, id: generateId() })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > targetCount) {
        return { ...prev, semesters: currentSems.slice(0, targetCount) };
      }
      return prev;
    });

    if (activeSemesterId > targetCount) {
      setActiveSemesterId(1);
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);
  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const remainingSemestersList = useMemo(() => {
    return data.semesters.filter(s => getSemesterStatus(s) !== 'complete');
  }, [data.semesters, getSemesterStatus]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    const isValidTarget = data.targetAvg > 0 && data.targetAvg <= 100;
    const isValidSemCount = data.totalSemestersTarget > 0;

    return { 
      hasPartial, 
      hasComplete, 
      isValidTarget, 
      isValidSemCount, 
      canCalculate: !hasPartial && hasComplete && isValidTarget && isValidSemCount 
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const handleAddSubject = () => {
    const newId = generateId();
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: generateId(), name: '', score: 0 }]
      }))
    }));
    setShowResults(false);
  };

  const handleClearSemester = () => {
    if (!window.confirm("Hapus semua data di semester ini?")) return;

    setData(prev => {
      // Jika menghapus Semester 1, hapus di SEMUA semester (karena S1 adalah template)
      if (activeSemesterId === 1) {
        return {
          ...prev,
          semesters: prev.semesters.map(s => ({ ...s, subjects: [] }))
        };
      }

      // Jika semester lain, cukup hapus nilai di semester tersebut
      return {
        ...prev,
        semesters: prev.semesters.map(s => 
          s.id === activeSemesterId ? { ...s, subjects: [] } : s
        )
      };
    });
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => {
        // Logika Sinkronisasi Nama: Jika mengedit nama di Semester 1, update di SEMUA semester
        if (activeSemesterId === 1 && field === 'name') {
          const targetSub = prev.semesters.find(sem => sem.id === 1)?.subjects.find(sub => sub.id === subId);
          if (targetSub) {
            return {
              ...s,
              subjects: s.subjects.map(sub => 
                sub.name === targetSub.name || sub.id === subId 
                  ? { ...sub, name: value as string } 
                  : sub
              )
            };
          }
        }

        // Update Normal (Nilai atau Nama di semester selain 1)
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
          };
        }
        return s;
      })
    }));
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string, subName: string) => {
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => {
        // Logika Sinkronisasi Hapus: Jika hapus di Semester 1, hapus di SEMUA semester
        if (activeSemesterId === 1) {
          return {
            ...s,
            subjects: s.subjects.filter(sub => sub.name !== subName && sub.id !== subId)
          };
        }

        // Hapus spesifik hanya di semester aktif jika bukan semester 1
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.filter(sub => sub.id !== subId)
          };
        }
        return s;
      })
    }));
    setShowResults(false);
  };

  const handleScanImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsScanning(true);
    setScanProgress({ current: 0, total: files.length });

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let allDetectedSubjects: any[] = [];

    try {
      for (let i = 0; i < files.length; i++) {
        setScanProgress({ current: i + 1, total: files.length });
        const file = files[i];

        const base64 = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
          reader.readAsDataURL(file);
        });

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: [
            {
              parts: [
                { inlineData: { data: base64, mimeType: file.type } },
                { text: "Extract subjects and their respective numeric scores/grades from this report card image. Return ONLY a JSON object with a 'subjects' array containing objects with 'name' (string) and 'score' (number). If scores are missing, omit the subject." }
              ]
            }
          ],
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                subjects: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      score: { type: Type.NUMBER }
                    },
                    required: ["name", "score"]
                  }
                }
              },
              required: ["subjects"]
            }
          }
        });

        const result = JSON.parse(response.text || '{"subjects":[]}');
        if (result.subjects) {
          allDetectedSubjects = [...allDetectedSubjects, ...result.subjects];
        }
      }

      setData(prev => {
        const newSemesters = prev.semesters.map(s => {
          if (s.id === activeSemesterId) {
            const currentSubjects = [...s.subjects];
            allDetectedSubjects.forEach(newSub => {
              const existingIndex = currentSubjects.findIndex(cs => 
                cs.name.toLowerCase().replace(/\s/g, '') === newSub.name.toLowerCase().replace(/\s/g, '')
              );
              if (existingIndex > -1) {
                currentSubjects[existingIndex].score = newSub.score;
              } else {
                currentSubjects.push({ id: generateId(), name: newSub.name, score: newSub.score });
              }
            });
            return { ...s, subjects: currentSubjects };
          }
          return s;
        });

        if (activeSemesterId === 1) {
          const semester1 = newSemesters.find(s => s.id === 1);
          if (semester1) {
            return {
              ...prev,
              semesters: newSemesters.map(s => {
                if (s.id === 1) return s;
                const updatedS = { ...s };
                const sSubjects = [...s.subjects];
                semester1.subjects.forEach(s1Sub => {
                  const exists = sSubjects.find(sub => sub.name === s1Sub.name);
                  if (!exists) {
                    sSubjects.push({ id: generateId(), name: s1Sub.name, score: 0 });
                  }
                });
                updatedS.subjects = sSubjects;
                return updatedS;
              })
            };
          }
        }
        return { ...prev, semesters: newSemesters };
      });
    } catch (error) {
      console.error("AI Scan Error:", error);
      alert("Gagal memproses gambar.");
    } finally {
      setIsScanning(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const triggerAnalysis = () => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setTimeout(() => {
      setIsCalculating(false);
      setShowSummaryPopup(true);
    }, 1200);
  };

  const handleExportPDF = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 500));
      const canvas = await html2canvas(reportRef.current, {
        scale: 2,
        backgroundColor: '#030712',
        logging: false,
        useCORS: true,
        ignoreElements: (element) => element.id === 'export-button-container'
      });
      const imgData = canvas.toDataURL('image/png');
      const pdfWidth = 450;
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'px',
        format: [pdfWidth, pdfHeight]
      });
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Rapor_Lengkap_${data.userName || 'Siswa'}.pdf`);
    } catch (error) {
      console.error('Export Error:', error);
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen text-slate-100 selection:bg-cyan-500/30">

      {/* Scanning Animation Overlay */}
      {isScanning && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-slate-950/90 backdrop-blur-md">
          <div className="relative w-64 h-64 md:w-80 md:h-80 border-2 border-cyan-500/20 rounded-3xl overflow-hidden shadow-[0_0_50px_rgba(34,211,238,0.2)]">
            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-cyan-500/10 to-transparent animate-[scan_2s_infinite]"></div>
            <div className="absolute top-0 left-0 w-full h-1 bg-cyan-400 shadow-[0_0_15px_rgba(34,211,238,1)] animate-[scan_2s_infinite]"></div>
            <div className="flex items-center justify-center h-full">
              <svg className="w-20 h-20 text-cyan-500 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
            </div>
          </div>
          <div className="mt-8 text-center">
            <p className="text-cyan-400 font-bold tech-font tracking-[0.3em] animate-pulse">
              AI SCANNING: {scanProgress.current}/{scanProgress.total}
            </p>
            <p className="mt-2 text-slate-500 text-[10px] uppercase tracking-widest">Sinkronisasi data antar semester...</p>
          </div>
        </div>
      )}

      {/* Modal Welcome */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl">
          <div className="glass-card rounded-[2rem] p-6 md:p-12 w-full max-w-md text-center animate-in shadow-2xl">
            <div className="w-16 h-16 bg-gradient-to-br from-cyan-400 to-indigo-500 rounded-2xl mx-auto mb-6 flex items-center justify-center shadow-lg">
              <span className="text-white font-black text-3xl">R</span>
            </div>
            <h2 className="text-2xl md:text-3xl font-extrabold text-white mb-2">Halo Siswa!</h2>
            <p className="text-slate-400 mb-8 text-sm md:text-base">Siap untuk melihat masa depan akademikmu?</p>
            <input 
              type="text" 
              value={data.userName}
              onChange={(e) => setData(prev => ({ ...prev, userName: e.target.value }))}
              className="w-full bg-slate-900/50 border border-white/10 rounded-xl py-4 px-6 text-center text-lg font-bold text-white outline-none focus:border-cyan-500 mb-6 transition-all"
              placeholder="Siapa namamu?"
              onKeyDown={(e) => e.key === 'Enter' && data.userName && setShowWelcome(false)}
            />
            <button 
              onClick={() => data.userName && setShowWelcome(false)}
              disabled={!data.userName}
