             </div>
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-white/5 py-20 bg-slate-950 text-center px-6">
         <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center gap-10">
            <div className="flex items-center gap-3">
               <div className="w-8 h-8 bg-cyan-500 rounded-lg flex items-center justify-center font-black text-slate-950">D</div>
               <p className="text-white font-black tracking-widest uppercase text-sm">Dafid Analytics</p>
            </div>
            <div className="text-slate-800 text-[9px] font-black uppercase tracking-[0.4em]">Integrated Grade Intelligence v11.0.1</div>
            <a href="https://dapidhub.my.id" target="_blank" rel="noopener noreferrer" className="px-8 py-3 rounded-full border border-cyan-500/20 text-cyan-500 hover:bg-cyan-500 hover:text-slate-950 transition-all font-black uppercase text-[10px] tracking-widest">Developer Hub</a>
         </div>
      </footer>

      <style>{`
        @keyframes scan {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(200%); }
        }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';
import { GoogleGenAI, Type } from "@google/genai";

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showSummaryPopup, setShowSummaryPopup] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState({ current: 0, total: 0 });
  const [showWelcome, setShowWelcome] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Sync total semesters count
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      const currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0, id: generateId() })) || [] 
        }));
        return { ...prev, semesters: [...currentSems, ...newSems] };
      } else if (currentSems.length > targetCount) {
        return { ...prev, semesters: currentSems.slice(0, targetCount) };
      }
      return prev;
    });
  }, [data.totalSemestersTarget, isLoaded]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const averagesHistory = useMemo(() => 
    completeSemesters.map(s => calculateSemesterAverage(s)),
  [completeSemesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const diagnosticInsight = useMemo(() => {
    if (averagesHistory.length < 2) return { label: 'Data Terbatas', color: 'text-slate-500', icon: 'M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z' };
    const last = averagesHistory[averagesHistory.length - 1];
    const prev = averagesHistory[averagesHistory.length - 2];
    const diff = last - prev;
    if (diff > 0.5) return { label: 'Tren Meningkat', color: 'text-emerald-400', icon: 'M13 7h8m0 0v8m0-8l-8 8-4-4-6 6' };
    if (diff < -0.5) return { label: 'Tren Menurun', color: 'text-rose-400', icon: 'M13 17h8m0 0V9m0 8l-8-8-4 4-6-6' };
    return { label: 'Tren Stabil', color: 'text-cyan-400', icon: 'M5 12h14' };
  }, [averagesHistory]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    return { 
      canCalculate: !hasPartial && hasComplete && data.targetAvg > 0 && data.totalSemestersTarget > 0,
      hasPartial
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const handleAddSubject = () => {
    const newId = generateId();
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: generateId(), name: '', score: 0 }]
      }))
    }));
    setShowResults(false);
  };

  const handleClearSemester = () => {
    if (!window.confirm("Hapus semua data di semester ini? Tindakan ini tidak bisa dibatalkan.")) return;
    setData(prev => {
      if (activeSemesterId === 1) {
        return { ...prev, semesters: prev.semesters.map(s => ({ ...s, subjects: [] })) };
      }
      return {
        ...prev,
        semesters: prev.semesters.map(s => s.id === activeSemesterId ? { ...s, subjects: [] } : s)
      };
    });
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const newSemesters = prev.semesters.map(s => {
        // Jika edit S1 Nama -> Sinkron ke semua
        if (activeSemesterId === 1 && field === 'name') {
          const subjectsInS1 = prev.semesters[0].subjects;
          const targetIndex = subjectsInS1.findIndex(sub => sub.id === subId);
          if (targetIndex !== -1) {
            return {
              ...s,
              subjects: s.subjects.map((sub, idx) => idx === targetIndex ? { ...sub, name: value as string } : sub)
            };
          }
        }
        // Update nilai hanya di semester aktif
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
          };
        }
        return s;
      });
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const subjectsInS1 = prev.semesters[0].subjects;
      const targetIndex = subjectsInS1.findIndex(sub => sub.id === subId);

      const newSemesters = prev.semesters.map(s => {
        if (activeSemesterId === 1) {
          // Hapus di semua semester berdasarkan posisi index
          return {
            ...s,
            subjects: s.subjects.filter((_, idx) => idx !== targetIndex)
          };
        }
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.filter(sub => sub.id !== subId)
          };
        }
        return s;
      });
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  // Fixed Gemini API implementation following developer guidelines
  const handleScanImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    setScanProgress({ current: 0, total: files.length });

    // Create ai instance inside the function to ensure the correct API key is used
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let allDetected: any[] = [];

    try {
      for (let i = 0; i < files.length; i++) {
        setScanProgress({ current: i + 1, total: files.length });
        const base64 = await new Promise<string>(r => {
          const reader = new FileReader();
          reader.onloadend = () => r((reader.result as string).split(',')[1]);
          reader.readAsDataURL(files[i]);
        });

        // Using responseSchema for better structured output as per guidelines
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64, mimeType: files[i].type } },
              { text: "Ekstrak nama mata pelajaran dan nilai dari gambar rapor ini. Pastikan nilai berupa angka numeric 0-100." }
            ]
          },
          config: { 
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                subjects: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      score: { type: Type.NUMBER }
                    },
                    required: ["name", "score"]
                  }
                }
              },
              required: ["subjects"]
            }
          }
        });

        const text = response.text;
        if (text) {
          const result = JSON.parse(text);
          if (result.subjects && Array.isArray(result.subjects)) {
            allDetected = [...allDetected, ...result.subjects];
          }
        }
      }

      setData(prev => {
        const updatedSemesters = prev.semesters.map(s => {
          if (s.id === activeSemesterId) {
            const current = [...s.subjects];
            allDetected.forEach(item => {
              const idx = current.findIndex(c => c.name.toLowerCase().replace(/\s/g,'') === item.name.toLowerCase().replace(/\s/g,''));
              if (idx > -1) current[idx].score = item.score;
              else current.push({ id: generateId(), name: item.name, score: item.score });
            });
            return { ...s, subjects: current };
          }
          return s;
        });
        // Sync template if scan was on S1
        if (activeSemesterId === 1) {
          const s1 = updatedSemesters[0];
          return {
            ...prev,
            semesters: updatedSemesters.map(s => {
              if (s.id === 1) return s;
              const newSubs = [...s.subjects];
              s1.subjects.forEach(template => {
                if (!newSubs.find(sub => sub.name === template.name)) {
                  newSubs.push({ ...template, score: 0, id: generateId() });
                }
              });
              return { ...s, subjects: newSubs };
            })
          };
        }
        return { ...prev, semesters: updatedSemesters };
      });
    } catch (err) { 
      console.error(err);
      alert("Scan Gagal"); 
    } finally { 
      setIsScanning(false); 
    }
  };

  // Fixed the missing triggerAnalysis function
  const triggerAnalysis = useCallback(() => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    // Simulate complex calculation process for UX
    setTimeout(() => {
      setIsCalculating(false);
      setShowResults(true);
      // Wait for the DOM to update with results section
      setTimeout(() => {
        reportRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);
    }, 1200);
  }, [validation.canCalculate]);

  const renderCurve = () => {
    if (averagesHistory.length < 2) return null;
    const width = 400;
    const height = 150;
    const padding = 20;
    const points = averagesHistory.map((val, i) => ({
      x: padding + (i * (width - 2 * padding) / (averagesHistory.length - 1)),
      y: height - padding - ((val - 60) * (height - 2 * padding) / 40) // Normalize between 60-100
    }));
    const d = `M ${points[0].x} ${points[0].y} ` + points.slice(1).map(p => `L ${p.x} ${p.y}`).join(' ');
    const areaD = d + ` L ${points[points.length-1].x} ${height} L ${points[0].x} ${height} Z`;

    return (
      <div className="w-full bg-slate-900/50 rounded-3xl p-6 border border-white/5 relative overflow-hidden group">
        <div className="absolute top-4 left-6 flex items-center gap-2">
          <div className={`w-2 h-2 rounded-full bg-cyan-400 animate-ping`}></div>
          <span className="text-[10px] font-black uppercase text-cyan-400 tracking-widest">Live Academic Curve</span>
        </div>
        <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto drop-shadow-[0_0_10px_rgba(34,211,238,0.3)]">
          <defs>
            <linearGradient id="grad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#22d3ee" stopOpacity="0.2" />
              <stop offset="100%" stopColor="#22d3ee" stopOpacity="0" />
            </linearGradient>
          </defs>
          <path d={areaD} fill="url(#grad)" />
          <path d={d} fill="none" stroke="#22d3ee" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
          {points.map((p, i) => (
            <circle key={i} cx={p.x} cy={p.y} r="4" fill="#030712" stroke="#22d3ee" strokeWidth="2" />
          ))}
        </svg>
        <div className="flex justify-between mt-4 px-2">
           {completeSemesters.map(s => <span key={s.id} className="text-[8px] font-bold text-slate-600 uppercase">SMT {s.id}</span>)}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col min-h-screen text-slate-100 selection:bg-cyan-500/30">

      {isScanning && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-slate-950/90 backdrop-blur-md">
           <div className="w-48 h-1 bg-slate-900 rounded-full overflow-hidden mb-4">
              <div className="h-full bg-cyan-400 animate-[scan_1.5s_infinite]"></div>
           </div>
           <p className="tech-font text-cyan-400 animate-pulse text-xs tracking-[0.2em]">SINKRONISASI AI: {scanProgress.current}/{scanProgress.total}</p>
        </div>
      )}

      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl">
          <div className="glass-card rounded-[2.5rem] p-10 w-full max-w-md text-center animate-in">
            <h2 className="text-3xl font-black text-white mb-6">Halo, Siswa!</h2>
            <input type="text" value={data.userName} onChange={e => setData(prev => ({ ...prev, userName: e.target.value }))} className="w-full bg-slate-900 border border-white/10 rounded-2xl py-4 px-6 text-center text-lg font-bold text-white outline-none focus:border-cyan-500 mb-6" placeholder="Namamu" />
            <button onClick={() => data.userName && setShowWelcome(false)} className="w-full py-4 bg-cyan-500 text-slate-950 rounded-2xl font-black uppercase tracking-widest shadow-lg">Lanjutkan</button>
          </div>
        </div>
      )}

      <header className="sticky top-0 z-40 glass-card border-b border-white/5 backdrop-blur-xl h-20 flex items-center px-6">
        <div className="max-w-6xl mx-auto w-full flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-cyan-500 rounded-xl flex items-center justify-center font-black text-slate-950 text-xl">S</div>
             <h1 className="text-xl font-black">Smart<span className="text-cyan-400">Rapor</span></h1>
          </div>
          <div onClick={() => setShowWelcome(true)} className="flex items-center gap-3 cursor-pointer group">
             <span className="text-xs font-bold text-slate-500 group-hover:text-white transition-colors">{data.userName || 'Tamu'}</span>
             <div className="w-10 h-10 rounded-full bg-slate-800 border border-white/10 flex items-center justify-center text-cyan-400">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" strokeLinecap="round" /></svg>
             </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-6xl mx-auto w-full px-6 py-12">
        <section className="mb-12 animate-in">
           <h2 className="text-4xl md:text-6xl font-black mb-4">Analisis <span className="text-cyan-400">Akademik.</span></h2>
           <p className="text-slate-400 max-w-xl leading-relaxed">Kelola nilai rapor Anda dengan kecerdasan AI. Gunakan Semester 1 sebagai acuan mata pelajaran untuk seluruh periode studi.</p>
        </section>

        <section className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12 animate-in">
           <div className="glass-card p-8 rounded-3xl border-l-8 border-cyan-500">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Target Rata-Rata</span>
              <div className="flex items-end gap-2">
                 <input type="number" value={data.targetAvg || ''} onChange={e => setData(prev => ({ ...prev, targetAvg: parseFloat(e.target.value) || 0 }))} className="bg-transparent text-5xl font-black tech-font text-white w-full outline-none" />
                 <span className="text-slate-700 font-bold pb-2">%</span>
              </div>
           </div>
           <div className="glass-card p-8 rounded-3xl border-l-8 border-indigo-500">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Total Semester</span>
              <div className="flex items-end gap-2">
                 <input type="number" value={data.totalSemestersTarget || ''} onChange={e => setData(prev => ({ ...prev, totalSemestersTarget: parseInt(e.target.value) || 0 }))} className="bg-transparent text-5xl font-black tech-font text-white w-full outline-none" />
                 <span className="text-slate-700 font-bold pb-2">SEM</span>
              </div>
           </div>
           <div className="md:col-span-1">
              {renderCurve()}
           </div>
        </section>

        <div className="flex gap-4 overflow-x-auto pb-6 no-scrollbar mb-8 animate-in">
           {data.semesters.map(s => {
             const active = activeSemesterId === s.id;
             const status = getSemesterStatus(s);
             return (
               <button key={s.id} onClick={() => setActiveSemesterId(s.id)} className={`relative flex-shrink-0 px-8 py-6 rounded-2xl border transition-all ${active ? 'bg-cyan-500 text-slate-950 border-cyan-400 scale-105 z-10 shadow-xl' : 'glass-card text-slate-500'}`}>
                 <span className="text-[9px] font-bold uppercase block mb-1 opacity-60">Smt</span>
                 <span className={`text-2xl font-black tech-font ${active ? 'text-slate-950' : 'text-white'}`}>{s.id}</span>
                 {status === 'complete' && <div className="absolute -top-1 -right-1 w-5 h-5 bg-emerald-500 rounded-full border-2 border-[#030712] flex items-center justify-center text-[10px] text-slate-950 font-bold">✓</div>}
               </button>
             );
           })}
        </div>

        <section className="glass-card rounded-[2.5rem] p-8 md:p-12 mb-12 animate-in">
           {activeSemester ? (
             <>
               <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
                  <div>
                    <h3 className="text-3xl font-black">Semester {activeSemesterId}</h3>
                    {activeSemesterId === 1 && <span className="text-[10px] font-bold text-amber-500 uppercase tracking-widest bg-amber-500/10 px-3 py-1 rounded-full border border-amber-500/20">Master Template</span>}
                  </div>
                  <div className="flex flex-wrap gap-3 w-full md:w-auto">
                    <button onClick={() => fileInputRef.current?.click()} className="flex-1 md:flex-none px-6 py-3 bg-white/5 border border-white/10 rounded-xl font-bold text-[10px] uppercase tracking-widest hover:bg-white/10 transition-all flex items-center justify-center gap-2">
                       <svg className="w-4 h-4 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" strokeWidth="2" strokeLinecap="round" /></svg>
                       AI Scan
                    </button>
                    <input type="file" ref={fileInputRef} onChange={handleScanImage} multiple className="hidden" accept="image/*" />
                    <button onClick={handleClearSemester} className="px-6 py-3 border border-rose-500/30 text-rose-500 rounded-xl font-bold text-[10px] uppercase tracking-widest hover:bg-rose-500/10 transition-all">Clear All</button>
                    {activeSemesterId === 1 && (
                      <button onClick={handleAddSubject} className="flex-1 md:flex-none px-8 py-3 bg-cyan-500 text-slate-950 rounded-xl font-black text-[10px] uppercase tracking-widest hover:scale-105 transition-all shadow-lg">Tambah Mapel</button>
                    )}
                  </div>
               </div>

               <div className="grid gap-3">
                 {activeSemester.subjects.length === 0 ? (
                   <div className="py-20 text-center border-2 border-dashed border-white/5 rounded-3xl bg-white/5">
                      <p className="text-slate-600 font-bold uppercase text-xs tracking-widest">Gunakan AI Scan atau Tambah Mapel di Semester 1</p>
                   </div>
                 ) : activeSemester.subjects.map((sub, i) => (
                   <div key={sub.id} className="flex items-center gap-4 bg-slate-900/40 p-4 rounded-2xl border border-white/5 hover:border-cyan-500/30 transition-all group">
                      <span className="tech-font text-slate-700 font-bold text-xs w-6">{(i+1).toString().padStart(2,'0')}</span>
                      <input type="text" value={sub.name} readOnly={activeSemesterId !== 1} onChange={e => handleUpdateSubject(sub.id, 'name', e.target.value)} className={`flex-grow bg-transparent font-bold outline-none text-sm md:text-base ${activeSemesterId === 1 ? 'focus:text-cyan-400' : 'opacity-50 cursor-not-allowed'}`} placeholder="Mata Pelajaran" />
                      <div className="flex items-center gap-3">
                         <input type="number" value={sub.score || ''} onChange={e => handleUpdateSubject(sub.id, 'score', Math.min(100, parseInt(e.target.value) || 0))} className="w-16 md:w-24 bg-slate-950 border border-white/10 rounded-xl py-2 text-center text-cyan-400 font-bold tech-font text-lg md:text-xl outline-none focus:border-cyan-500" placeholder="0" />
                         {activeSemesterId === 1 && (
                           <button onClick={() => handleDeleteSubject(sub.id)} className="p-2 text-slate-700 hover:text-rose-500 transition-colors">
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" strokeWidth="2" strokeLinecap="round" /></svg>
                           </button>
                         )}
                      </div>
                   </div>
                 ))}
               </div>
             </>
           ) : <div className="py-20 text-center">Semester tidak ditemukan</div>}
        </section>

        <div className="max-w-xl mx-auto mb-20 text-center">
           <button disabled={!validation.canCalculate || isCalculating} onClick={triggerAnalysis} className={`w-full py-6 rounded-3xl font-black text-lg uppercase tracking-[0.3em] transition-all ${validation.canCalculate ? 'bg-gradient-to-r from-cyan-500 to-indigo-500 text-slate-950 shadow-2xl hover:brightness-110 active:scale-95' : 'bg-slate-900 text-slate-700 opacity-50 cursor-not-allowed border border-white/5'}`}>
              {isCalculating ? 'Menganalisis...' : 'Proses Analisis'}
           </button>
           {!validation.canCalculate && <p className="mt-4 text-[10px] text-amber-500 font-bold uppercase tracking-widest opacity-60">Lengkapi data semester yang telah dilalui untuk memulai</p>}
        </div>

        {showResults && (
          <div ref={reportRef} className="space-y-24 animate-in pb-32">
             <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="glass-card p-10 rounded-[3rem] text-center border-t-4 border-cyan-500 bg-slate-950 shadow-2xl">
                   <span className="text-slate-600 text-[10px] font-black uppercase tracking-widest mb-6 block">Status Akademik</span>
                   <div className={`flex items-center justify-center gap-3 mb-4 ${diagnosticInsight.color}`}>
                      <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d={diagnosticInsight.icon} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>
                      <span className="text-2xl font-black tech-font">{diagnosticInsight.label}</span>
                   </div>
                   <div className="text-6xl font-black tech-font mb-2">{overallAvg.toFixed(1)}</div>
                   <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Rerata Kumulatif</p>
                </div>

                <div className="glass-card p-10 rounded-[3rem] lg:col-span-2 flex flex-col justify-center border-t-4 border-indigo-500 shadow-2xl relative overflow-hidden">
                   <div className="absolute top-0 right-0 p-8 opacity-10">
                      <svg className="w-32 h-32" fill="currentColor" viewBox="0 0 24 24"><path d="M13 2L3 14h9v8l10-12h-9l10-10z" /></svg>
                   </div>
                   <h4 className="text-slate-600 text-[10px] font-black uppercase tracking-widest mb-8">Target Pencapaian Akhir</h4>
                   <div className="flex flex-col md:flex-row items-center gap-10">
                      <div className="p-8 bg-cyan-500/10 rounded-[2rem] border border-cyan-500/20 text-center">
                         <div className="text-6xl font-black text-cyan-400 tech-font">{neededAvg.toFixed(1)}</div>
                         <p className="text-[9px] font-black text-cyan-500/60 uppercase mt-2 tracking-widest">Target Minimal Sisa Smt</p>
                      </div>
                      <div className="flex-grow text-center md:text-left">
                         <p className="text-lg text-slate-300 italic leading-relaxed border-l-4 border-cyan-500/30 pl-8">"Anda perlu mempertahankan performa minimal <b className="text-white">{neededAvg.toFixed(1)}</b> di setiap sisa semester untuk mencapai target rata-rata <b className="text-cyan-400">{data.targetAvg}%</b>."</p>
                         {neededAvg > 100 && <p className="mt-4 text-[10px] font-bold text-rose-500 uppercase tracking-widest p-3 bg-rose-500/10 rounded-xl inline-block border border-rose-500/20">⚠️ Warning: Target Mustahil</p>}
                      </div>
                   </div>
                </div>
             </div>

             <div className="space-y-10">
                <h3 className="text-2xl font-black uppercase tracking-tighter text-center">Peta Jalan <span className="text-cyan-400">Strategis</span></h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                   {data.semesters[0].subjects.map((s, idx) => {
                     const target = Math.ceil(neededAvg);
                     return (
                       <div key={idx} className="glass-card p-8 rounded-[2rem] border-l-4 border-indigo-500 hover:scale-105 transition-transform group">
                          <div className="flex justify-between items-center mb-6">
                             <h5 className="text-xs font-black text-slate-300 uppercase truncate pr-4">{s.name}</h5>
                             <div className="px-2 py-1 bg-cyan-500/10 text-cyan-400 text-[8px] font-bold rounded uppercase">Target</div>
                          </div>
                          <div className="space-y-3">
                             {data.semesters.filter(sem => getSemesterStatus(sem) !== 'complete').map(sem => (
                               <div key={sem.id} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0">
                                  <span className="text-[10px] font-bold text-slate-600">SMT {sem.id}</span>
                                  <span className="tech-font text-xl font-black text-white">{target}</span>
                               </div>
                             ))}
                          </div>
                       </div>
                     );
                   })}
                </div>
             </div>
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-white/5 py-20 bg-slate-950 text-center px-6">
         <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center gap-10">
            <div className="flex items-center gap-3">
               <div className="w-8 h-8 bg-cyan-500 rounded-lg flex items-center justify-center font-black text-slate-950">D</div>
               <p className="text-white font-black tracking-widest uppercase text-sm">Dafid Analytics</p>
            </div>
            <div className="text-slate-800 text-[9px] font-black uppercase tracking-[0.4em]">Integrated Grade Intelligence v11.0.1</div>
            <a href="https://dapidhub.my.id" target="_blank" rel="noopener noreferrer" className="px-8 py-3 rounded-full border border-cyan-500/20 text-cyan-500 hover:bg-cyan-500 hover:text-slate-950 transition-all font-black uppercase text-[10px] tracking-widest">Developer Hub</a>
         </div>
      </footer>

      <style>{`
        @keyframes scan {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(200%); }
        }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';
import { GoogleGenAI, Type } from "@google/genai";

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState({ current: 0, total: 0 });
  const [showWelcome, setShowWelcome] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Sync total semesters count & Ensure S1 is the master
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      let currentSems = [...prev.semesters];

      // Handle count mismatch
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0, id: generateId() })) || [] 
        }));
        currentSems = [...currentSems, ...newSems];
      } else if (currentSems.length > targetCount) {
        currentSems = currentSems.slice(0, targetCount);
      }

      return { ...prev, semesters: currentSems };
    });
  }, [data.totalSemestersTarget, isLoaded]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const averagesHistory = useMemo(() => 
    completeSemesters.map(s => calculateSemesterAverage(s)),
  [completeSemesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const totalScore = useMemo(() => {
    return completeSemesters.reduce((acc, sem) => 
      acc + sem.subjects.reduce((sAcc, sub) => sAcc + sub.score, 0), 0
    );
  }, [completeSemesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  // Diagnostics calculations
  const diagnosticData = useMemo(() => {
    if (averagesHistory.length < 2) return null;

    const last = averagesHistory[averagesHistory.length - 1];
    const prev = averagesHistory[averagesHistory.length - 2];
    const diff = last - prev;

    // Calculate variance for consistency
    const mean = averagesHistory.reduce((a, b) => a + b, 0) / averagesHistory.length;
    const variance = averagesHistory.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / averagesHistory.length;
    const consistency = Math.max(0, 100 - (Math.sqrt(variance) * 5));

    return {
      trend: diff > 0.5 ? 'Meningkat' : diff < -0.5 ? 'Menurun' : 'Stabil',
      trendColor: diff > 0.5 ? 'text-emerald-400' : diff < -0.5 ? 'text-rose-400' : 'text-cyan-400',
      consistency: consistency.toFixed(1),
      volatility: (Math.sqrt(variance)).toFixed(2)
    };
  }, [averagesHistory]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    return { 
      canCalculate: !hasPartial && hasComplete && data.targetAvg > 0 && data.totalSemestersTarget > 0,
      hasPartial
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const handleAddSubject = () => {
    const newName = '';
    setData(prev => ({
      ...prev,
      semesters: prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: generateId(), name: newName, score: 0 }]
      }))
    }));
    setShowResults(false);
  };

  const handleClearSemester = () => {
    if (!window.confirm("Hapus semua data di semester ini? S1 akan menghapus template global.")) return;
    setData(prev => {
      if (activeSemesterId === 1) {
        return { ...prev, semesters: prev.semesters.map(s => ({ ...s, subjects: [] })) };
      }
      return {
        ...prev,
        semesters: prev.semesters.map(s => s.id === activeSemesterId ? { ...s, subjects: [] } : s)
      };
    });
    setShowResults(false);
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      // Find the index in S1 if we are editing S1
      const s1Subs = prev.semesters[0].subjects;
      const targetIndex = s1Subs.findIndex(sub => sub.id === subId);

      const newSemesters = prev.semesters.map(s => {
        // Sync names globally if editing S1
        if (activeSemesterId === 1 && field === 'name' && targetIndex !== -1) {
          return {
            ...s,
            subjects: s.subjects.map((sub, idx) => idx === targetIndex ? { ...sub, name: value as string } : sub)
          };
        }
        // Update values only for the active semester
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub)
          };
        }
        return s;
      });
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const s1Subs = prev.semesters[0].subjects;
      const targetIndex = s1Subs.findIndex(sub => sub.id === subId);

      const newSemesters = prev.semesters.map(s => {
        if (activeSemesterId === 1 && targetIndex !== -1) {
          return {
            ...s,
            subjects: s.subjects.filter((_, idx) => idx !== targetIndex)
          };
        }
        if (s.id === activeSemesterId) {
          return {
            ...s,
            subjects: s.subjects.filter(sub => sub.id !== subId)
          };
        }
        return s;
      });
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleScanImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    setScanProgress({ current: 0, total: files.length });

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let allDetected: any[] = [];

    try {
      for (let i = 0; i < files.length; i++) {
        setScanProgress({ current: i + 1, total: files.length });
        const base64 = await new Promise<string>(r => {
          const reader = new FileReader();
          reader.onloadend = () => r((reader.result as string).split(',')[1]);
          reader.readAsDataURL(files[i]);
        });

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64, mimeType: files[i].type } },
              { text: "Ekstrak nama mata pelajaran dan nilai dari gambar rapor ini. Berikan output dalam JSON: { subjects: [{ name: string, score: number }] }" }
            ]
          },
          config: { 
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                subjects: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      score: { type: Type.NUMBER }
                    },
                    required: ["name", "score"]
                  }
                }
              },
              required: ["subjects"]
            }
          }
        });

        const result = JSON.parse(response.text || '{"subjects":[]}');
        if (result.subjects) allDetected = [...allDetected, ...result.subjects];
      }

      setData(prev => {
        const updatedSemesters = prev.semesters.map(s => {
          if (s.id === activeSemesterId) {
            const current = [...s.subjects];
            allDetected.forEach(item => {
              const idx = current.findIndex(c => c.name.toLowerCase().replace(/\s/g,'') === item.name.toLowerCase().replace(/\s/g,''));
              if (idx > -1) current[idx].score = item.score;
              else current.push({ id: generateId(), name: item.name, score: item.score });
            });
            return { ...s, subjects: current };
          }
          return s;
        });

        // Sync structure if scan was on S1
        if (activeSemesterId === 1) {
          const s1 = updatedSemesters[0];
          return {
            ...prev,
            semesters: updatedSemesters.map(s => {
              if (s.id === 1) return s;
              const newSubs = s1.subjects.map(template => {
                const existing = s.subjects.find(sub => sub.name === template.name);
                return existing ? existing : { ...template, score: 0, id: generateId() };
              });
              return { ...s, subjects: newSubs };
            })
          };
        }
        return { ...prev, semesters: updatedSemesters };
      });
    } catch (err) { 
      alert("Scan Gagal. Pastikan file gambar jelas."); 
    } finally { 
      setIsScanning(false); 
    }
  };

  const triggerAnalysis = useCallback(() => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    setTimeout(() => {
      setIsCalculating(false);
      setShowResults(true);
      reportRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 1500);
  }, [validation.canCalculate]);

  const renderCurve = () => {
    if (averagesHistory.length < 2) return (
      <div className="w-full bg-slate-900/50 rounded-3xl p-8 border border-white/5 flex items-center justify-center text-slate-600 tech-font text-[10px] uppercase tracking-widest">
        Dibutuhkan min. 2 semester untuk memplot kurva
      </div>
    );

    const width = 400;
    const height = 150;
    const padding = 20;
    const points = averagesHistory.map((val, i) => ({
      x: padding + (i * (width - 2 * padding) / (averagesHistory.length - 1)),
      y: height - padding - ((val - 60) * (height - 2 * padding) / 40)
    }));

    const d = `M ${points[0].x} ${points[0].y} ` + points.slice(1).map(p => `L ${p.x} ${p.y}`).join(' ');
    const areaD = d + ` L ${points[points.length-1].x} ${height} L ${points[0].x} ${height} Z`;

    return (
      <div className="w-full bg-slate-900/80 rounded-3xl p-6 border border-white/5 relative overflow-hidden shadow-2xl">
        <div className="flex justify-between items-start mb-4">
           <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse"></div>
              <span className="text-[10px] font-black uppercase text-cyan-400 tracking-widest">Academic Momentum</span>
           </div>
           {diagnosticData && (
             <span className={`text-[10px] font-black uppercase ${diagnosticData.trendColor}`}>{diagnosticData.trend}</span>
           )}
        </div>
        <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto drop-shadow-[0_0_15px_rgba(34,211,238,0.4)]">
          <defs>
            <linearGradient id="curveGrad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#22d3ee" stopOpacity="0.3" />
              <stop offset="100%" stopColor="#22d3ee" stopOpacity="0" />
            </linearGradient>
          </defs>
          <path d={areaD} fill="url(#curveGrad)" />
          <path d={d} fill="none" stroke="#22d3ee" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
          {points.map((p, i) => (
            <g key={i}>
              <circle cx={p.x} cy={p.y} r="5" fill="#030712" stroke="#22d3ee" strokeWidth="2" />
              <text x={p.x} y={p.y - 10} textAnchor="middle" fill="white" fontSize="8" className="tech-font">{averagesHistory[i].toFixed(1)}</text>
            </g>
          ))}
        </svg>
      </div>
    );
  };

  return (
    <div className="flex flex-col min-h-screen text-slate-100 selection:bg-cyan-500/30">

      {/* Loading AI Scan */}
      {isScanning && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-slate-950/90 backdrop-blur-md">
           <div className="relative w-20 h-20 mb-6">
              <div className="absolute inset-0 border-4 border-cyan-500/20 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-t-cyan-500 rounded-full animate-spin"></div>
           </div>
           <p className="tech-font text-cyan-400 animate-pulse text-xs tracking-[0.3em] uppercase">Processing AI Vision: {scanProgress.current}/{scanProgress.total}</p>
        </div>
      )}

      {/* Modal Welcome */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl">
