                   <div className="flex flex-col sm:flex-row items-center gap-10">
                      <div className="p-8 bg-cyan-500/10 rounded-3xl border border-cyan-500/20 text-center shadow-inner">
                         <div className="text-6xl font-black text-cyan-400 tech-font mb-1">{neededAvg.toFixed(1)}</div>
                         <p className="text-[8px] font-black text-cyan-500/60 uppercase tracking-widest">Target Sisa SMT</p>
