  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState({ current: 0, total: 0 });
  const [showWelcome, setShowWelcome] = useState(false);
  const [showFinalModal, setShowFinalModal] = useState(false);
  const [summarySemesterId, setSummarySemesterId] = useState<number | null>(null);

  const reportRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      let currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0, id: generateId() })) || [] 
        }));
        currentSems = [...currentSems, ...newSems];
      } else if (currentSems.length > targetCount) {
        currentSems = currentSems.slice(0, targetCount);
      }
      return { ...prev, semesters: currentSems };
    });
  }, [data.totalSemestersTarget, isLoaded]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const averagesHistory = useMemo(() => 
    completeSemesters.map(s => calculateSemesterAverage(s)),
  [completeSemesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const allSemestersComplete = useMemo(() => 
    completeSemesters.length === data.totalSemestersTarget,
  [completeSemesters.length, data.totalSemestersTarget]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    return { 
      canCalculate: !hasPartial && hasComplete && data.targetAvg > 0 && data.totalSemestersTarget > 0,
      hasPartial
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const diagnosticData = useMemo(() => {
    if (averagesHistory.length < 2) return null;
    const last = averagesHistory[averagesHistory.length - 1];
    const prev = averagesHistory[averagesHistory.length - 2];
    const diff = last - prev;
    const mean = averagesHistory.reduce((a, b) => a + b, 0) / averagesHistory.length;
    const variance = averagesHistory.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / averagesHistory.length;
    const consistency = Math.max(0, 100 - (Math.sqrt(variance) * 5));

    return {
      trend: diff > 0.5 ? 'Meningkat' : diff < -0.5 ? 'Menurun' : 'Stabil',
      trendColor: diff > 0.5 ? 'text-emerald-400' : diff < -0.5 ? 'text-rose-400' : 'text-cyan-400',
      consistency: consistency.toFixed(1),
      volatility: (Math.sqrt(variance)).toFixed(2)
    };
  }, [averagesHistory]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const s1 = prev.semesters[0];
      const targetIdx = s1.subjects.findIndex(sub => sub.id === subId);
      return {
        ...prev,
        semesters: prev.semesters.map(s => {
          if (activeSemesterId === 1 && field === 'name' && targetIdx !== -1) {
            return { ...s, subjects: s.subjects.map((sub, idx) => idx === targetIdx ? { ...sub, name: value as string } : sub) };
          }
          if (s.id === activeSemesterId) {
            return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
          }
          return s;
        })
      };
    });
    setShowResults(false);
  };

  const handleScanImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    setScanProgress({ current: 0, total: files.length });
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const scanPromises = Array.from(files).map(async (file: File) => {
        const base64 = await new Promise<string>(r => {
          const reader = new FileReader();
          reader.onloadend = () => r((reader.result as string).split(',')[1]);
          reader.readAsDataURL(file);
        });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: { parts: [{ inlineData: { data: base64, mimeType: file.type } }, { text: "Extract subjects and scores. Return JSON: { subjects: [{ name: string, score: number }] }" }] },
          config: { responseMimeType: "application/json", responseSchema: { type: Type.OBJECT, properties: { subjects: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, score: { type: Type.NUMBER } }, required: ["name", "score"] } } }, required: ["subjects"] } }
        });
        setScanProgress(prev => ({ ...prev, current: prev.current + 1 }));
        return JSON.parse(response.text || '{"subjects":[]}').subjects || [];
      });
      const allResultsArray = await Promise.all(scanPromises);
      const allDetected = allResultsArray.flat();
      setData(prev => {
        const updatedSems = prev.semesters.map(s => {
          if (s.id === activeSemesterId) {
            const current = [...s.subjects];
            allDetected.forEach(item => {
              const idx = current.findIndex(c => c.name.toLowerCase().replace(/\s/g,'') === item.name.toLowerCase().replace(/\s/g,''));
              if (idx > -1) { if (item.score > 0) current[idx].score = item.score; }
              else { current.push({ id: generateId(), name: item.name, score: item.score }); }
            });
            return { ...s, subjects: current };
          }
          return s;
        });
        if (activeSemesterId === 1) {
          const s1 = updatedSems[0];
          return { ...prev, semesters: updatedSems.map(s => {
            if (s.id === 1) return s;
            return { ...s, subjects: s1.subjects.map(t => {
              const ex = s.subjects.find(sub => sub.name === t.name);
              return ex ? ex : { ...t, score: 0, id: generateId() };
            })};
          })};
        }
        return { ...prev, semesters: updatedSems };
      });
    } catch (err) { alert("Scan Gagal."); } finally { setIsScanning(false); }
  };

  const triggerAnalysis = useCallback(() => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    setTimeout(() => {
      setIsCalculating(false);
      setShowResults(true);
      if (allSemestersComplete) setShowFinalModal(true);
      reportRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 1200);
  }, [validation.canCalculate, allSemestersComplete]);

  const renderModal = (title: string, content: React.ReactNode, onClose: () => void) => (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-slate-950/90 backdrop-blur-md">
      <div className="glass-card rounded-[2.5rem] w-full max-w-xl p-8 md:p-12 animate-in border-t-4 border-cyan-500 shadow-3xl">
        <div className="flex justify-between items-center mb-8">
           <h3 className="text-2xl font-black uppercase tracking-tighter">{title}</h3>
           <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-slate-400">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="2" strokeLinecap="round"/></svg>
           </button>
        </div>
        {content}
        <button onClick={onClose} className="w-full mt-8 py-4 bg-cyan-500 text-slate-950 font-black uppercase tracking-widest rounded-2xl hover:brightness-110 active:scale-95 transition-all">Tutup</button>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col min-h-screen text-slate-100 selection:bg-cyan-500/30">

      {/* AI Scanning Loader */}
      {isScanning && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-slate-950/90 backdrop-blur-xl">
           <div className="relative w-24 h-24 mb-8">
              <div className="absolute inset-0 border-4 border-cyan-500/10 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-t-cyan-500 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-2 h-2 bg-cyan-500 rounded-full animate-ping"></div>
              </div>
           </div>
           <p className="tech-font text-cyan-400 animate-pulse text-[10px] tracking-[0.4em] uppercase font-black">AI Grade Hub Vision: {scanProgress.current}/{scanProgress.total}</p>
        </div>
      )}

      {/* Final Outcome Modal */}
      {showFinalModal && renderModal(
        overallAvg >= data.targetAvg ? "SELAMAT! 🏆" : "TETAP SEMANGAT! 💪",
        <div className="text-center">
          <div className={`text-7xl font-black tech-font mb-6 ${overallAvg >= data.targetAvg ? 'text-emerald-400' : 'text-amber-400'}`}>
            {overallAvg.toFixed(1)}%
          </div>
          <p className="text-lg leading-relaxed text-slate-300">
            {overallAvg >= data.targetAvg 
              ? `Luar biasa, ${data.userName}! Kamu berhasil melampaui target ${data.targetAvg}%. Semua usaha kerasmu selama ${data.totalSemestersTarget} semester membuahkan hasil yang gemilang.`
              : `Halo ${data.userName}, meskipun nilai akhirmu sedikit di bawah target ${data.targetAvg}%, ingatlah bahwa perjalanan akademik hanyalah sebagian dari ceritamu. Teruslah belajar dan berproses!`
            }
          </p>
          <div className="mt-10 p-6 bg-white/5 rounded-3xl border border-white/10 italic text-slate-500 text-sm">
            "{overallAvg >= data.targetAvg 
              ? "Kesuksesan adalah jumlah dari usaha kecil, yang diulang hari demi hari." 
              : "Kegagalan adalah kesempatan untuk memulai lagi dengan lebih cerdas."}"
          </div>
        </div>,
        () => setShowFinalModal(false)
      )}

      {/* Semester Summary Modal */}
      {summarySemesterId !== null && (() => {
        const sem = data.semesters.find(s => s.id === summarySemesterId);
        if (!sem) return null;
        const avg = calculateSemesterAverage(sem);
        const sorted = [...sem.subjects].sort((a,b) => b.score - a.score);
        return renderModal(
          `Hasil Semester ${summarySemesterId}`,
          <div className="space-y-6">
             <div className="flex items-center justify-between p-6 bg-cyan-500/10 rounded-3xl border border-cyan-500/20">
                <span className="text-[10px] font-black uppercase text-cyan-500 tracking-widest">Rerata Semester</span>
                <span className="text-4xl font-black tech-font text-white">{avg.toFixed(1)}</span>
             </div>
             <div className="grid grid-cols-2 gap-4">
                <div className="p-5 bg-emerald-500/10 rounded-2xl border border-emerald-500/20">
                   <p className="text-[8px] font-black text-emerald-400 uppercase mb-2">Tertinggi</p>
                   <p className="text-sm font-bold truncate">{sorted[0]?.name || '-'}</p>
                   <p className="text-xl font-black tech-font">{sorted[0]?.score || 0}</p>
                </div>
                <div className="p-5 bg-rose-500/10 rounded-2xl border border-rose-500/20">
                   <p className="text-[8px] font-black text-rose-400 uppercase mb-2">Terendah</p>
                   <p className="text-sm font-bold truncate">{sorted[sorted.length-1]?.name || '-'}</p>
                   <p className="text-xl font-black tech-font">{sorted[sorted.length-1]?.score || 0}</p>
                </div>
             </div>
             <div className="bg-slate-900/50 p-6 rounded-3xl border border-white/5 max-h-40 overflow-y-auto no-scrollbar">
                <p className="text-[9px] font-black text-slate-600 uppercase mb-4 tracking-widest">Performa Mapel</p>
                {sorted.map(s => (
                  <div key={s.id} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0">
                     <span className="text-xs font-medium text-slate-400">{s.name}</span>
                     <span className={`tech-font font-bold ${s.score >= avg ? 'text-emerald-400' : 'text-rose-400'}`}>{s.score}</span>
                  </div>
                ))}
             </div>
          </div>,
          () => setSummarySemesterId(null)
        );
      })()}

      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl">
          <div className="glass-card rounded-[2.5rem] p-8 md:p-12 w-full max-w-md text-center animate-in shadow-2xl border-t-4 border-t-cyan-500">
            <h2 className="text-3xl font-black mb-2">Smart<span className="text-cyan-400">Rapor</span></h2>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.3em] font-black mb-8">Academic Future Engine</p>
            <input 
              type="text" 
              value={data.userName} 
              onChange={e => setData(prev => ({ ...prev, userName: e.target.value }))} 
              className="w-full bg-slate-900 border border-white/10 rounded-2xl py-5 px-6 text-center text-lg font-bold text-white outline-none focus:border-cyan-500 mb-6 transition-all" 
              placeholder="Siapa namamu?" 
              onKeyDown={e => e.key === 'Enter' && data.userName && setShowWelcome(false)}
            />
            <button 
              onClick={() => data.userName && setShowWelcome(false)} 
              className="w-full py-5 bg-cyan-500 text-slate-950 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:scale-[1.02] active:scale-95 transition-all"
            >
              Akses Dashboard
            </button>
          </div>
        </div>
      )}

      <header className="sticky top-0 z-40 glass-card border-b border-white/5 backdrop-blur-xl h-20 px-6 flex items-center">
        <div className="max-w-6xl mx-auto w-full flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-cyan-500 rounded-xl flex items-center justify-center font-black text-slate-950 text-xl shadow-[0_0_20px_rgba(34,211,238,0.3)]">S</div>
             <h1 className="text-xl font-black tracking-tighter">Smart<span className="text-cyan-400">Rapor</span></h1>
          </div>
          <div onClick={() => setShowWelcome(true)} className="flex items-center gap-3 cursor-pointer group bg-white/5 py-1.5 pl-3.5 pr-1.5 rounded-full border border-white/5 hover:border-cyan-500/20 transition-all">
             <div className="hidden sm:block text-right">
                <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Active User</p>
                <p className="text-xs font-bold text-white group-hover:text-cyan-400 transition-colors">{data.userName || 'Tamu'}</p>
             </div>
             <div className="w-9 h-9 rounded-full bg-slate-800 border border-white/10 flex items-center justify-center text-cyan-400 group-hover:bg-cyan-500 group-hover:text-slate-950 transition-all">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2.5" strokeLinecap="round" /></svg>
             </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-6xl mx-auto w-full px-6 py-10">
        <section className="mb-12 animate-in">
           <h2 className="text-4xl md:text-6xl font-black mb-4 tracking-tighter">Strategi <br/> <span className="text-cyan-400">Akademik.</span></h2>
           <p className="text-slate-400 max-w-xl text-sm leading-relaxed">Kelola rencana studi Anda dengan kalkulasi presisi. Semester 1 akan mensinkronisasi sisa semester Anda.</p>
        </section>

        {/* Global Stats Grid */}
        <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12 animate-in">
           <div className="glass-card p-8 rounded-[2rem] border-l-4 border-cyan-500">
              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-2">Target Akhir</span>
              <div className="flex items-end gap-2">
                 <input 
                   type="number" 
                   value={data.targetAvg || ''} 
                   onChange={e => setData(prev => ({ ...prev, targetAvg: Math.min(100, parseFloat(e.target.value) || 0) }))} 
                   className="bg-transparent text-4xl font-black tech-font text-white w-full outline-none focus:text-cyan-400 transition-colors" 
                 />
                 <span className="text-slate-700 font-bold text-xl pb-1.5">%</span>
              </div>
           </div>
           <div className="glass-card p-8 rounded-[2rem] border-l-4 border-indigo-500">
              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-2">Masa Studi</span>
              <div className="flex items-end gap-2">
                 <input 
                   type="number" 
                   value={data.totalSemestersTarget || ''} 
                   onChange={e => setData(prev => ({ ...prev, totalSemestersTarget: Math.min(12, parseInt(e.target.value) || 0) }))} 
                   className="bg-transparent text-4xl font-black tech-font text-white w-full outline-none focus:text-indigo-400 transition-colors" 
                 />
                 <span className="text-slate-700 font-bold text-xl pb-1.5">SM</span>
              </div>
           </div>
           <div className="lg:col-span-2">
              <div className="w-full bg-slate-900/80 rounded-[2rem] p-6 border border-white/5 relative overflow-hidden shadow-2xl h-full flex flex-col justify-center">
                <span className="text-[10px] font-black uppercase text-cyan-400 tracking-[0.2em] mb-4">Academic momentum</span>
                <div className="flex items-center justify-center h-20 text-slate-700 text-[10px] font-black uppercase tech-font">
                   Visual Curve Analysis Mode
                </div>
              </div>
           </div>
        </section>

        {/* Diagnostic Insight Widgets */}
        {diagnosticData && (
          <section className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10 animate-in">
            {[
              { label: 'Indeks Konsistensi', val: `${diagnosticData.consistency}%`, color: 'text-emerald-400' },
              { label: 'Skor Volatilitas', val: diagnosticData.volatility, color: 'text-amber-400' },
              { label: 'Rerata Saat Ini', val: overallAvg.toFixed(1), color: 'text-white' },
              { label: 'Prediksi Tren', val: diagnosticData.trend, color: diagnosticData.trendColor }
            ].map((item, i) => (
              <div key={i} className="glass-card p-5 rounded-2xl border border-white/5">
                 <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mb-1.5">{item.label}</p>
                 <p className={`text-xl font-black tech-font ${item.color}`}>{item.val}</p>
              </div>
            ))}
          </section>
        )}

        {/* Semester Navigation */}
        <div className="flex gap-3 overflow-x-auto pb-6 no-scrollbar mb-8 animate-in">
           {data.semesters.map(s => {
             const active = activeSemesterId === s.id;
             const status = getSemesterStatus(s);
             return (
               <button 
                key={s.id} 
                onClick={() => setActiveSemesterId(s.id)} 
                className={`relative flex-shrink-0 px-8 py-6 rounded-2xl border transition-all duration-300 ${
                  active 
                    ? 'bg-cyan-500 text-slate-950 border-cyan-400 scale-105 z-10 shadow-lg' 
                    : 'glass-card text-slate-500 hover:border-white/10'
                }`}
               >
                 <span className={`text-[9px] font-black uppercase block mb-0.5 ${active ? 'opacity-70' : 'opacity-40'}`}>Smt</span>
                 <span className={`text-2xl font-black tech-font ${active ? 'text-slate-950' : 'text-white'}`}>{s.id}</span>
                 {status === 'complete' && (
                    <div className="absolute -top-1.5 -right-1.5 w-6 h-6 bg-emerald-500 rounded-full border-2 border-slate-950 flex items-center justify-center text-[8px] text-slate-950 font-black">✓</div>
                 )}
               </button>
             );
           })}
        </div>

        {/* Main Editor Card */}
        <section className="glass-card rounded-[2.5rem] p-8 md:p-12 mb-16 animate-in">
           {activeSemester ? (
             <>
               <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 mb-10">
                  <div>
                    <h3 className="text-3xl font-black tracking-tight mb-1">Semester {activeSemesterId}</h3>
                    <div className="flex items-center gap-3">
                       {activeSemesterId === 1 && (
                         <span className="text-[9px] font-black text-amber-500 uppercase tracking-widest flex items-center gap-1.5">
                           <div className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse"></div> Master Template
                         </span>
                       )}
                       {getSemesterStatus(activeSemester) === 'complete' && (
                         <button 
                          onClick={() => setSummarySemesterId(activeSemesterId)} 
                          className="text-[9px] font-black text-cyan-400 uppercase tracking-widest hover:underline"
                         >
                           Lihat Ringkasan
                         </button>
                       )}
                    </div>
                  </div>
                  <div className="flex flex-wrap gap-3 w-full lg:w-auto">
                    <button 
                      onClick={() => fileInputRef.current?.click()} 
                      className="flex-1 lg:flex-none px-6 py-3.5 bg-white/5 border border-white/10 rounded-xl font-black text-[9px] uppercase tracking-widest hover:bg-cyan-500/10 transition-all flex items-center justify-center gap-2 group"
                    >
                       <svg className="w-4 h-4 text-cyan-400 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2.5" /><circle cx="12" cy="13" r="3" strokeWidth="2.5" /></svg>
                       AI Scan
                    </button>
                    <input type="file" ref={fileInputRef} onChange={handleScanImage} multiple className="hidden" accept="image/*" />
                    {activeSemesterId === 1 && (
                      <button onClick={() => setData(prev => ({...prev, semesters: prev.semesters.map(s => s.id === 1 ? {...s, subjects: [...s.subjects, {id: generateId(), name:'', score:0}]} : s)}))} className="flex-1 lg:flex-none px-8 py-3.5 bg-cyan-500 text-slate-950 rounded-xl font-black text-[9px] uppercase tracking-widest hover:brightness-110 shadow-lg transition-all">Tambah Mapel</button>
                    )}
                  </div>
               </div>

               <div className="grid gap-3">
                 {activeSemester.subjects.length === 0 ? (
                   <div className="py-20 text-center border-2 border-dashed border-white/5 rounded-3xl bg-white/[0.02]">
                      <p className="text-slate-600 font-black uppercase text-[10px] tracking-[0.3em]">Data Semester 1 Terlebih Dahulu</p>
                   </div>
                 ) : activeSemester.subjects.map((sub, i) => (
                   <div key={sub.id} className="flex flex-col sm:flex-row items-center gap-4 bg-slate-900/40 p-4 rounded-2xl border border-white/5 group hover:border-cyan-500/20 transition-all">
                      <div className="flex items-center gap-4 w-full sm:w-auto flex-grow">
                         <span className="tech-font text-slate-700 font-black text-xs w-6 text-center opacity-40">{(i+1).toString().padStart(2,'0')}</span>
                         <input 
                           type="text" 
                           value={sub.name} 
                           readOnly={activeSemesterId !== 1} 
                           onChange={e => handleUpdateSubject(sub.id, 'name', e.target.value)} 
                           className={`flex-grow bg-transparent font-bold outline-none text-base transition-colors ${activeSemesterId === 1 ? 'focus:text-cyan-400' : 'text-slate-500 cursor-not-allowed'}`} 
                           placeholder="Nama Mapel" 
                         />
                      </div>
                      <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-end">
                         <input 
                           type="number" 
                           value={sub.score || ''} 
                           onChange={e => handleUpdateSubject(sub.id, 'score', Math.min(100, parseInt(e.target.value) || 0))} 
                           className="w-24 bg-slate-950 border border-white/10 rounded-xl py-2.5 text-center text-cyan-400 font-black tech-font text-xl outline-none focus:border-cyan-500 transition-all" 
                           placeholder="0" 
                         />
                         {activeSemesterId === 1 && (
                           <button onClick={() => setData(prev => ({...prev, semesters: prev.semesters.map(s => ({...s, subjects: s.subjects.filter(sb => sb.id !== sub.id)}))}))} className="p-2 text-slate-700 hover:text-rose-500 hover:bg-rose-500/10 rounded-lg transition-all">
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>
                           </button>
                         )}
                      </div>
                   </div>
                 ))}
               </div>
             </>
           ) : <div className="py-20 text-center text-slate-700 tech-font font-black uppercase tracking-widest text-[10px]">Error Sistem</div>}
        </section>

        {/* Action Button */}
        <div className="max-w-xl mx-auto mb-20 text-center">
           <button 
            disabled={!validation.canCalculate || isCalculating} 
            onClick={triggerAnalysis} 
            className={`w-full py-6 rounded-3xl font-black text-lg uppercase tracking-[0.4em] transition-all duration-300 ${
              validation.canCalculate 
                ? 'bg-gradient-to-r from-cyan-500 to-indigo-500 text-slate-950 shadow-2xl hover:scale-[1.02] active:scale-95' 
                : 'bg-slate-900 text-slate-700 opacity-50 cursor-not-allowed border border-white/5'
            }`}
           >
              {isCalculating ? 'Computing Data...' : allSemestersComplete ? 'Lihat Laporan Akhir' : 'Proses Kalkulasi'}
           </button>
           {!validation.canCalculate && (
             <p className="mt-4 text-[9px] text-amber-500/60 font-black uppercase tracking-[0.3em]">Lengkapi pengisian untuk analisis</p>
           )}
        </div>

        {/* Results Analysis */}
        {showResults && (
          <div ref={reportRef} className="space-y-24 animate-in pb-40">
             <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="glass-card p-10 rounded-[3rem] text-center border-t-8 border-cyan-500 bg-slate-950 flex flex-col justify-center shadow-2xl">
                   <span className="text-slate-600 text-[9px] font-black uppercase tracking-widest mb-6 block">Kesehatan Akademik</span>
                   <div className="text-7xl font-black tech-font mb-2 text-white">{overallAvg.toFixed(1)}</div>
                   <div className="text-[10px] font-black text-cyan-400 uppercase tracking-widest py-2 bg-cyan-400/10 rounded-full border border-cyan-400/20 max-w-[160px] mx-auto">Verified Analysis</div>
                </div>

                <div className="glass-card p-10 rounded-[3rem] lg:col-span-2 border-t-8 border-indigo-500 bg-[#0a0f1d] shadow-2xl flex flex-col justify-center">
                   <h4 className="text-slate-600 text-[9px] font-black uppercase tracking-widest mb-8">Informasi Strategi</h4>
                   <div className="flex flex-col sm:flex-row items-center gap-10">
                      <div className="p-8 bg-cyan-500/10 rounded-3xl border border-cyan-500/20 text-center shadow-inner">
                         <div className="text-6xl font-black text-cyan-400 tech-font mb-1">{allSemestersComplete ? 'Done' : neededAvg.toFixed(1)}</div>
                         <p className="text-[8px] font-black text-cyan-500/60 uppercase tracking-widest">{allSemestersComplete ? 'Completed' : 'Min. Target Sisa'}</p>
                      </div>
                      <div className="flex-grow text-center sm:text-left">
                         {allSemestersComplete ? (
                           <p className="text-lg text-slate-300 italic font-medium leading-relaxed border-l-4 border-emerald-500/30 pl-8">"Selamat, {data.userName}! Seluruh masa studi telah berhasil direkap. Cek hasil akhir Anda di panel navigasi."</p>
                         ) : (
                           <p className="text-lg text-slate-300 italic font-medium leading-relaxed border-l-4 border-cyan-500/30 pl-8">"Diperlukan performa minimal <b className="text-white">{neededAvg.toFixed(1)}</b> per semester untuk menggapai target <b className="text-cyan-400">{data.targetAvg}%</b>."</p>
                         )}
                      </div>
                   </div>
                </div>
             </div>

             {/* Hide Roadmap if all complete */}
             {!allSemestersComplete && (
               <div className="space-y-10">
                  <div className="flex items-center gap-4">
                     <h3 className="text-lg font-black uppercase tracking-tighter">Roadmap <span className="text-cyan-400">Strategis</span></h3>
                     <div className="h-px bg-white/5 flex-grow"></div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                     {data.semesters[0].subjects.map((s, idx) => {
                       const target = Math.ceil(neededAvg);
                       const isCrit = target > 90;
                       return (
                         <div key={idx} className={`glass-card p-8 rounded-3xl border-l-4 transition-all hover:scale-105 group ${isCrit ? 'border-rose-500 bg-rose-500/[0.03]' : 'border-indigo-500'}`}>
                            <div className="flex justify-between items-start mb-6">
                               <h5 className="text-xs font-black text-slate-400 uppercase truncate group-hover:text-cyan-400 transition-colors">{s.name || 'Untitled'}</h5>
                               <div className={`px-2 py-0.5 text-[7px] font-black rounded uppercase ${isCrit ? 'bg-rose-500/20 text-rose-400' : 'bg-cyan-500/10 text-cyan-400'}`}>Target</div>
                            </div>
                            <div className="space-y-3">
                               {data.semesters.filter(sem => getSemesterStatus(sem) !== 'complete').map(sem => (
                                 <div key={sem.id} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0">
                                    <span className="text-[10px] font-bold text-slate-600">SMT {sem.id}</span>
                                    <span className="tech-font text-xl font-black text-white">{target}</span>
                                 </div>
                               ))}
                            </div>
                         </div>
                       );
                     })}
                  </div>
               </div>
             )}
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-white/5 py-20 bg-slate-950 text-center px-6">
         <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center gap-10">
            <div className="flex items-center gap-3">
               <div className="w-9 h-9 bg-cyan-500 rounded-xl flex items-center justify-center font-black text-slate-950 shadow-xl">D</div>
               <div className="text-left">
                  <p className="text-white font-black tracking-widest uppercase text-[11px]">Dafid Analytics</p>
                  <p className="text-[8px] text-slate-700 font-bold uppercase tracking-widest">Future systems Division</p>
               </div>
            </div>
            <div className="text-slate-800 text-[9px] font-black uppercase tracking-[0.5em] tech-font">grade_intel_v12.5.0_stable</div>
            <a href="https://dapidhub.my.id" target="_blank" className="px-8 py-3 rounded-2xl border border-cyan-500/20 text-cyan-500 hover:bg-cyan-500 hover:text-slate-950 transition-all font-black uppercase text-[9px] tracking-widest">Developer Hub</a>
         </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { GoogleGenAI, Type } from "@google/genai";

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState({ current: 0, total: 0 });
  const [showWelcome, setShowWelcome] = useState(false);
  const [showFinalModal, setShowFinalModal] = useState(false);
  const [summarySemesterId, setSummarySemesterId] = useState<number | null>(null);

  const reportRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Sync total semesters count
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      let currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: currentSems[0]?.subjects.map(s => ({ ...s, score: 0, id: generateId() })) || [] 
        }));
        currentSems = [...currentSems, ...newSems];
      } else if (currentSems.length > targetCount) {
        currentSems = currentSems.slice(0, targetCount);
      }
      return { ...prev, semesters: currentSems };
    });
  }, [data.totalSemestersTarget, isLoaded]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const averagesHistory = useMemo(() => 
    completeSemesters.map(s => calculateSemesterAverage(s)),
  [completeSemesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const allSemestersComplete = useMemo(() => 
    completeSemesters.length === data.totalSemestersTarget && completeSemesters.length > 0,
  [completeSemesters.length, data.totalSemestersTarget]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    return { 
      canCalculate: !hasPartial && hasComplete && data.targetAvg > 0 && data.totalSemestersTarget > 0,
      hasPartial
    };
  }, [data, completeSemesters, getSemesterStatus]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const s1 = prev.semesters[0];
      const targetIdx = s1.subjects.findIndex(sub => sub.id === subId);
      return {
        ...prev,
        semesters: prev.semesters.map(s => {
          if (activeSemesterId === 1 && field === 'name' && targetIdx !== -1) {
            return { ...s, subjects: s.subjects.map((sub, idx) => idx === targetIdx ? { ...sub, name: value as string } : sub) };
          }
          if (s.id === activeSemesterId) {
            return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
          }
          return s;
        })
      };
    });
    setShowResults(false);
  };

  const handleScanImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    setScanProgress({ current: 0, total: files.length });
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const scanPromises = Array.from(files).map(async (file: File) => {
        const base64 = await new Promise<string>(r => {
          const reader = new FileReader();
          reader.onloadend = () => r((reader.result as string).split(',')[1]);
          reader.readAsDataURL(file);
        });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: { parts: [{ inlineData: { data: base64, mimeType: file.type } }, { text: "Extract subjects and scores. Return JSON: { subjects: [{ name: string, score: number }] }" }] },
          config: { responseMimeType: "application/json", responseSchema: { type: Type.OBJECT, properties: { subjects: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, score: { type: Type.NUMBER } }, required: ["name", "score"] } } }, required: ["subjects"] } }
        });
        setScanProgress(prev => ({ ...prev, current: prev.current + 1 }));
        return JSON.parse(response.text || '{"subjects":[]}').subjects || [];
      });
      const allResultsArray = await Promise.all(scanPromises);
      const allDetected = allResultsArray.flat();
      setData(prev => {
        const updatedSems = prev.semesters.map(s => {
          if (s.id === activeSemesterId) {
            const current = [...s.subjects];
            allDetected.forEach(item => {
              const idx = current.findIndex(c => c.name.toLowerCase().replace(/\s/g,'') === item.name.toLowerCase().replace(/\s/g,''));
              if (idx > -1) { if (item.score > 0) current[idx].score = item.score; }
              else { current.push({ id: generateId(), name: item.name, score: item.score }); }
            });
            return { ...s, subjects: current };
          }
          return s;
        });
        if (activeSemesterId === 1) {
          const s1 = updatedSems[0];
          return { ...prev, semesters: updatedSems.map(s => {
            if (s.id === 1) return s;
            return { ...s, subjects: s1.subjects.map(t => {
              const ex = s.subjects.find(sub => sub.name === t.name);
              return ex ? ex : { ...t, score: 0, id: generateId() };
            })};
          })};
        }
        return { ...prev, semesters: updatedSems };
      });
    } catch (err) { alert("Scan Gagal."); } finally { setIsScanning(false); }
  };

  const triggerAnalysis = useCallback(() => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    setTimeout(() => {
      setIsCalculating(false);
      setShowResults(true);
      if (allSemestersComplete) {
        setShowFinalModal(true);
      }
      reportRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 1200);
  }, [validation.canCalculate, allSemestersComplete]);

  const renderModal = (title: string, content: React.ReactNode, onClose: () => void, accentColor: string = "border-cyan-500") => (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-slate-950/90 backdrop-blur-md">
      <div className={`glass-card rounded-[2.5rem] w-full max-w-xl p-8 md:p-12 animate-in border-t-8 ${accentColor} shadow-3xl`}>
        <div className="flex justify-between items-center mb-8">
           <h3 className="text-2xl font-black uppercase tracking-tighter">{title}</h3>
           <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-slate-400">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="2" strokeLinecap="round"/></svg>
           </button>
        </div>
        {content}
        <button onClick={onClose} className="w-full mt-8 py-4 bg-slate-100 text-slate-950 font-black uppercase tracking-widest rounded-2xl hover:bg-white active:scale-95 transition-all">Tutup</button>
      </div>
    </div>
  );

  const getTargetStatus = () => {
    if (overallAvg >= data.targetAvg) return { status: 'success', color: 'border-emerald-500', title: 'TARGET TERCAPAI! 🎓' };
    return { status: 'fail', color: 'border-amber-500', title: 'TERUS BERJUANG! 🔥' };
  };

  return (
    <div className="flex flex-col min-h-screen text-slate-100 selection:bg-indigo-500/30">

      {/* AI Scanning Loader */}
      {isScanning && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-slate-950/90 backdrop-blur-xl">
           <div className="relative w-24 h-24 mb-8">
              <div className="absolute inset-0 border-4 border-indigo-500/10 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-t-indigo-500 rounded-full animate-spin"></div>
           </div>
           <p className="tech-font text-indigo-400 animate-pulse text-[10px] tracking-[0.4em] uppercase font-black">Menganalisis Rapor: {scanProgress.current}/{scanProgress.total}</p>
        </div>
      )}

      {/* Final Outcome Modal */}
      {showFinalModal && renderModal(
        getTargetStatus().title,
        <div className="text-center">
          <div className={`text-8xl font-black tech-font mb-6 ${overallAvg >= data.targetAvg ? 'text-emerald-400' : 'text-amber-400'}`}>
            {overallAvg.toFixed(1)}%
          </div>
          <p className="text-xl leading-relaxed text-slate-200 mb-6">
            {overallAvg >= data.targetAvg 
              ? `Selamat ${data.userName}! Kamu adalah inspirasi. Dengan rerata ${overallAvg.toFixed(1)}%, kamu berhasil melampaui target ${data.targetAvg}%. Masa depan cerah menantimu!`
              : `Semangat ${data.userName}! Rerata akhirmu ${overallAvg.toFixed(1)}%. Meskipun belum menyentuh target ${data.targetAvg}%, ingatlah bahwa nilai hanyalah angka. Proses belajarmu adalah kemenangan yang sesungguhnya.`
            }
          </p>
          <div className={`p-8 rounded-3xl border ${overallAvg >= data.targetAvg ? 'bg-emerald-500/10 border-emerald-500/20' : 'bg-amber-500/10 border-amber-500/20'} italic text-slate-300 text-base shadow-inner`}>
            {overallAvg >= data.targetAvg 
              ? "“Pendidikan adalah senjata paling mematikan di dunia, karena dengan pendidikan, Anda dapat mengubah dunia.” — Nelson Mandela" 
              : "“Jangan takut gagal. Ketakutan akan kegagalan adalah hal yang menghentikanmu dari mencapai potensimu yang sebenarnya.” — Anonim"
            }
          </div>
        </div>,
        () => setShowFinalModal(false),
        getTargetStatus().color
      )}

      {/* Semester Summary Modal */}
      {summarySemesterId !== null && (() => {
        const sem = data.semesters.find(s => s.id === summarySemesterId);
        if (!sem) return null;
        const avg = calculateSemesterAverage(sem);
        const sorted = [...sem.subjects].sort((a,b) => b.score - a.score);
        return renderModal(
          `Statistik Semester ${summarySemesterId}`,
          <div className="space-y-6">
             <div className="flex items-center justify-between p-8 bg-indigo-500/10 rounded-[2rem] border border-indigo-500/20">
                <span className="text-[10px] font-black uppercase text-indigo-400 tracking-widest">Rerata Semester</span>
                <span className="text-5xl font-black tech-font text-white">{avg.toFixed(1)}</span>
             </div>
             <div className="grid grid-cols-2 gap-4">
                <div className="p-6 bg-emerald-500/10 rounded-2xl border border-emerald-500/20">
                   <p className="text-[9px] font-black text-emerald-400 uppercase mb-3">Nilai Tertinggi</p>
                   <p className="text-sm font-bold truncate text-slate-100">{sorted[0]?.name || '-'}</p>
                   <p className="text-2xl font-black tech-font text-emerald-400">{sorted[0]?.score || 0}</p>
                </div>
                <div className="p-6 bg-rose-500/10 rounded-2xl border border-rose-500/20">
                   <p className="text-[9px] font-black text-rose-400 uppercase mb-3">Nilai Terendah</p>
                   <p className="text-sm font-bold truncate text-slate-100">{sorted[sorted.length-1]?.name || '-'}</p>
                   <p className="text-2xl font-black tech-font text-rose-400">{sorted[sorted.length-1]?.score || 0}</p>
                </div>
             </div>
             <div className="bg-slate-900/60 p-6 rounded-[2rem] border border-white/5 max-h-56 overflow-y-auto no-scrollbar">
                <p className="text-[10px] font-black text-slate-500 uppercase mb-4 tracking-widest border-b border-white/5 pb-2">Distribusi Performa</p>
                {sorted.map(s => (
                  <div key={s.id} className="flex justify-between items-center py-3 border-b border-white/5 last:border-0 hover:bg-white/[0.02] px-2 rounded-lg transition-colors">
                     <span className="text-sm font-medium text-slate-300">{s.name}</span>
                     <div className="flex items-center gap-3">
                        <span className={`tech-font font-black ${s.score >= avg ? 'text-emerald-400' : 'text-rose-400'}`}>{s.score}</span>
                        <div className={`w-2 h-2 rounded-full ${s.score >= avg ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>
                     </div>
                  </div>
                ))}
             </div>
          </div>,
          () => setSummarySemesterId(null),
          "border-indigo-500"
        );
      })()}

      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl">
          <div className="glass-card rounded-[3rem] p-10 md:p-14 w-full max-w-lg text-center animate-in shadow-3xl border-t-8 border-indigo-500">
            <h2 className="text-4xl font-black mb-3">Smart<span className="text-indigo-400">Rapor</span></h2>
            <p className="text-slate-400 text-[11px] uppercase tracking-[0.4em] font-black mb-10">Pusat Analisis Akademik</p>
            <div className="relative mb-8">
              <input 
                type="text" 
                value={data.userName} 
                onChange={e => setData(prev => ({ ...prev, userName: e.target.value }))} 
