                           className={`flex-grow bg-transparent font-bold outline-none text-lg transition-colors ${activeSemesterId === 1 ? 'focus:text-indigo-400' : 'text-slate-400 cursor-not-allowed'}`} 
                           placeholder="Nama Mata Pelajaran" 
                         />
                      </div>
                      <div className="flex items-center gap-6 w-full sm:w-auto justify-between sm:justify-end">
                         <div className="relative">
                           <input 
                             type="number" 
                             value={sub.score || ''} 
                             onChange={e => handleUpdateSubject(sub.id, 'score', Math.min(100, parseInt(e.target.value) || 0))} 
                             className="w-28 bg-slate-950 border border-white/10 rounded-xl py-3 text-center text-indigo-400 font-black tech-font text-2xl outline-none focus:border-indigo-500 transition-all shadow-inner" 
                             placeholder="0" 
                           />
                         </div>
                         {activeSemesterId === 1 && (
                           <button onClick={() => setData(prev => ({...prev, semesters: prev.semesters.map(s => ({...s, subjects: s.subjects.filter(sb => sb.id !== sub.id)}))}))} className="p-3 text-slate-700 hover:text-rose-500 hover:bg-rose-500/10 rounded-xl transition-all">
                              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" /></svg>
                           </button>
                         )}
                      </div>
                   </div>
                 ))}
               </div>
             </>
           ) : <div className="py-24 text-center text-slate-700 tech-font font-black uppercase tracking-widest text-xs">Error Sistem Dashboard</div>}
        </section>

        {/* Action Button */}
        <div className="max-w-2xl mx-auto mb-24 text-center">
           <button 
            disabled={!validation.canCalculate || isCalculating} 
            onClick={triggerAnalysis} 
            className={`w-full py-8 rounded-[2.5rem] font-black text-xl uppercase tracking-[0.5em] transition-all duration-300 ${
              validation.canCalculate 
                ? 'bg-gradient-to-r from-indigo-500 to-cyan-500 text-white shadow-3xl hover:brightness-110 hover:scale-[1.01] active:scale-95' 
                : 'bg-slate-900 text-slate-700 opacity-50 cursor-not-allowed border border-white/5'
            }`}
           >
              {isCalculating ? 'Memproses Data...' : allSemestersComplete ? 'Lihat Hasil Akhir' : 'Kalkulasi Strategi'}
           </button>
           {!validation.canCalculate && (
             <p className="mt-6 text-[10px] text-amber-500/60 font-black uppercase tracking-[0.4em]">Selesaikan pengisian untuk memulai analisis cerdas</p>
           )}
        </div>

        {/* Results Analysis Dashboard */}
        {showResults && (
          <div ref={reportRef} className="space-y-32 animate-in pb-48">
             <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                <div className="glass-card p-12 rounded-[3.5rem] text-center border-t-8 border-indigo-500 bg-slate-950 flex flex-col justify-center shadow-3xl">
                   <span className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-8 block">Skor Kumulatif</span>
                   <div className="text-8xl font-black tech-font mb-4 text-white leading-none">{overallAvg.toFixed(1)}</div>
                   <div className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.3em] py-3 bg-indigo-500/10 rounded-full border border-indigo-500/20 max-w-[200px] mx-auto shadow-inner">Analisis Terverifikasi</div>
                </div>

                <div className="glass-card p-12 rounded-[3.5rem] lg:col-span-2 border-t-8 border-cyan-500 bg-[#0a0f1d]/80 shadow-3xl flex flex-col justify-center relative overflow-hidden">
                   <div className="absolute top-0 right-0 w-64 h-64 bg-cyan-500/5 blur-[80px] -z-10 rounded-full"></div>
                   <h4 className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-10">Status & Strategi</h4>
                   <div className="flex flex-col sm:flex-row items-center gap-12">
                      <div className="p-10 bg-indigo-500/10 rounded-[2.5rem] border border-indigo-500/20 text-center shadow-2xl relative">
                         <div className="text-7xl font-black text-indigo-400 tech-font mb-2 leading-none">{allSemestersComplete ? '100%' : `${neededAvg.toFixed(1)}%`}</div>
                         <p className="text-[9px] font-black text-indigo-500/60 uppercase tracking-widest">{allSemestersComplete ? 'Selesai' : 'Target Per Semester'}</p>
                      </div>
                      <div className="flex-grow text-center sm:text-left">
                         {allSemestersComplete ? (
                           <div className="space-y-4">
                             <p className="text-2xl text-slate-100 font-bold leading-tight">Masa studi berakhir.</p>
                             <p className="text-lg text-slate-400 italic font-medium leading-relaxed border-l-4 border-emerald-500/40 pl-8">"Selamat {data.userName}, Anda telah menyelesaikan pengisian seluruh semester. Gunakan data ini sebagai refleksi perjalanan Anda."</p>
                           </div>
                         ) : (
                           <p className="text-2xl text-slate-200 italic font-medium leading-relaxed border-l-4 border-indigo-500/40 pl-10">"Kamu butuh rerata minimal <b className="text-indigo-400">{neededAvg.toFixed(1)}%</b> untuk setiap sisa semester demi target <b className="text-white">{data.targetAvg}%</b>."</p>
                         )}
                      </div>
                   </div>
                </div>
             </div>

             {/* Roadmap section hidden when complete */}
             {!allSemestersComplete && (
               <div className="space-y-12">
                  <div className="flex items-center gap-6">
                     <h3 className="text-2xl font-black uppercase tracking-tighter">Peta <span className="text-indigo-400">Roadmap</span></h3>
                     <div className="h-px bg-white/5 flex-grow"></div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                     {data.semesters[0].subjects.map((s, idx) => {
                       const target = Math.ceil(neededAvg);
                       const isCrit = target > 90;
                       return (
                         <div key={idx} className={`glass-card p-10 rounded-[2.5rem] border-l-8 transition-all hover:scale-[1.03] group ${isCrit ? 'border-rose-500 bg-rose-500/[0.03]' : 'border-cyan-500'}`}>
                            <div className="flex justify-between items-start mb-8">
                               <h5 className="text-sm font-black text-slate-300 uppercase truncate pr-4 group-hover:text-indigo-400 transition-colors">{s.name || 'Mata Pelajaran'}</h5>
                               <div className={`px-3 py-1 text-[8px] font-black rounded-lg uppercase shadow-inner ${isCrit ? 'bg-rose-500/20 text-rose-400' : 'bg-indigo-500/10 text-indigo-400'}`}>Kritis</div>
                            </div>
                            <div className="space-y-4">
                               {data.semesters.filter(sem => getSemesterStatus(sem) !== 'complete').map(sem => (
                                 <div key={sem.id} className="flex justify-between items-center py-3 border-b border-white/5 last:border-0">
                                    <span className="text-[11px] font-bold text-slate-500">SMT {sem.id}</span>
                                    <span className="tech-font text-2xl font-black text-white">{target}</span>
                                 </div>
                               ))}
                            </div>
                         </div>
                       );
                     })}
                  </div>
               </div>
             )}
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-white/5 py-24 bg-slate-950 text-center px-8 relative overflow-hidden">
         <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-full h-1 bg-gradient-to-r from-indigo-500 via-cyan-500 to-indigo-500"></div>
         <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-12">
            <div className="flex items-center gap-4">
               <div className="w-10 h-10 bg-indigo-500 rounded-xl flex items-center justify-center font-black text-white shadow-2xl">D</div>
               <div className="text-left">
                  <p className="text-white font-black tracking-widest uppercase text-sm">Dafid Hub Analytics</p>
                  <p className="text-[9px] text-slate-600 font-bold uppercase tracking-[0.3em]">Grade Intelligence Division</p>
               </div>
            </div>
            <div className="text-slate-800 text-[10px] font-black uppercase tracking-[0.6em] tech-font">grade_sys_v12.6.0_final</div>
            <div className="flex gap-6">
               <a href="https://dapidhub.my.id" target="_blank" className="px-10 py-4 rounded-2xl border-2 border-indigo-500/20 text-indigo-400 hover:bg-indigo-500 hover:text-white transition-all font-black uppercase text-[10px] tracking-widest shadow-lg">Developer Portal</a>
            </div>
         </div>
         <p className="mt-12 text-[10px] text-slate-700 font-medium uppercase tracking-widest">&copy; 2025 Smart Rapor Ecosystem. All Rights Reserved.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  saveToStorage, 
  loadFromStorage 
} from './utils';
import { GoogleGenAI, Type } from "@google/genai";

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState({ current: 0, total: 0 });
  const [showWelcome, setShowWelcome] = useState(false);
  const [showFinalModal, setShowFinalModal] = useState(false);
  const [summarySemesterId, setSummarySemesterId] = useState<number | null>(null);

  const reportRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) saveToStorage(data);
  }, [data, isLoaded]);

  // Sync total semesters count
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);

    setData(prev => {
      let currentSems = [...prev.semesters];
      if (currentSems.length < targetCount) {
        const toAdd = targetCount - currentSems.length;
        const s1 = currentSems[0];
        const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
          id: currentSems.length + i + 1, 
          subjects: s1?.subjects.map(s => ({ ...s, score: 0, id: generateId() })) || [] 
        }));
        currentSems = [...currentSems, ...newSems];
      } else if (currentSems.length > targetCount) {
        currentSems = currentSems.slice(0, targetCount);
      }
      return { ...prev, semesters: currentSems };
    });
  }, [data.totalSemestersTarget, isLoaded]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const averagesHistory = useMemo(() => 
    completeSemesters.map(s => calculateSemesterAverage(s)),
  [completeSemesters]);

  const overallAvg = useMemo(() => calculateOverallAverage(completeSemesters), [completeSemesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, needed);
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const diagnosticData = useMemo(() => {
    if (averagesHistory.length === 0) return null;
    if (averagesHistory.length === 1) return { trend: 'STABIL', trendColor: 'text-indigo-400', consistency: 100 };

    const last = averagesHistory[averagesHistory.length - 1];
    const prev = averagesHistory[averagesHistory.length - 2];
    const diff = last - prev;

    const trend = diff > 0.2 ? 'MENINGKAT' : diff < -0.2 ? 'MENURUN' : 'STABIL';
    const trendColor = diff > 0.2 ? 'text-emerald-400' : diff < -0.2 ? 'text-rose-400' : 'text-indigo-400';

    const mean = averagesHistory.reduce((a, b) => a + b, 0) / averagesHistory.length;
    const variance = averagesHistory.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / averagesHistory.length;
    const consistency = Math.max(0, Math.min(100, Math.round(100 - (Math.sqrt(variance) * 5))));

    return { trend, trendColor, consistency };
  }, [averagesHistory]);

  const allSemestersComplete = useMemo(() => 
    completeSemesters.length === data.totalSemestersTarget && completeSemesters.length > 0,
  [completeSemesters.length, data.totalSemestersTarget]);

  const validation = useMemo(() => {
    const hasPartial = data.semesters.some(s => getSemesterStatus(s) === 'partial');
    const hasComplete = completeSemesters.length > 0;
    return { 
      canCalculate: !hasPartial && hasComplete && data.targetAvg > 0 && data.totalSemestersTarget > 0,
      hasPartial
    };
  }, [data, completeSemesters, getSemesterStatus]);

  // FIX: Centralized logic to sync structural changes from S1 to all other semesters
  const syncS1ToOthers = (allSemesters: Semester[]) => {
    const s1 = allSemesters[0];
    return allSemesters.map(s => {
      if (s.id === 1) return s;
      // Reconstruct based on S1 subject names
      const newSubjects = s1.subjects.map(template => {
        const existing = s.subjects.find(sub => sub.name === template.name);
        return existing ? existing : { ...template, score: 0, id: generateId() };
      });
      return { ...s, subjects: newSubjects };
    });
  };

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });

      if (activeSemesterId === 1 && field === 'name') {
        return { ...prev, semesters: syncS1ToOthers(updatedSems) };
      }
      return { ...prev, semesters: updatedSems };
    });
    setShowResults(false);
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const s1 = prev.semesters[0];
      const targetSub = s1.subjects.find(s => s.id === subId);
      if (!targetSub) return prev;

      // Remove from S1
      const updatedS1Subjects = s1.subjects.filter(s => s.id !== subId);
      const newS1 = { ...s1, subjects: updatedS1Subjects };

      // Sync removal to others based on name
      const newSemesters = prev.semesters.map(s => {
        if (s.id === 1) return newS1;
        return { ...s, subjects: s.subjects.filter(sub => sub.name !== targetSub.name) };
      });

      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleAddSubject = () => {
    setData(prev => {
      const newId = generateId();
      const updatedSems = prev.semesters.map(s => {
        if (s.id === 1) {
          return { ...s, subjects: [...s.subjects, { id: newId, name: '', score: 0 }] };
        }
        return s;
      });
      return { ...prev, semesters: syncS1ToOthers(updatedSems) };
    });
  };

  const handleScanImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    setScanProgress({ current: 0, total: files.length });
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const scanPromises = Array.from(files).map(async (file: File) => {
        const base64 = await new Promise<string>(r => {
          const reader = new FileReader();
          reader.onloadend = () => r((reader.result as string).split(',')[1]);
          reader.readAsDataURL(file);
        });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: { parts: [{ inlineData: { data: base64, mimeType: file.type } }, { text: "Extract subjects and scores. Return JSON: { subjects: [{ name: string, score: number }] }" }] },
          config: { responseMimeType: "application/json", responseSchema: { type: Type.OBJECT, properties: { subjects: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, score: { type: Type.NUMBER } }, required: ["name", "score"] } } }, required: ["subjects"] } }
        });
        setScanProgress(prev => ({ ...prev, current: prev.current + 1 }));
        return JSON.parse(response.text || '{"subjects":[]}').subjects || [];
      });
      const allResultsArray = await Promise.all(scanPromises);
      const allDetected = allResultsArray.flat();
      setData(prev => {
        const updatedSems = prev.semesters.map(s => {
          if (s.id === activeSemesterId) {
            const current = [...s.subjects];
            allDetected.forEach(item => {
              const idx = current.findIndex(c => c.name.toLowerCase().replace(/\s/g,'') === item.name.toLowerCase().replace(/\s/g,''));
              if (idx > -1) { if (item.score > 0) current[idx].score = item.score; }
              else { current.push({ id: generateId(), name: item.name, score: item.score }); }
            });
            return { ...s, subjects: current };
          }
          return s;
        });

        if (activeSemesterId === 1) {
          return { ...prev, semesters: syncS1ToOthers(updatedSems) };
        }
        return { ...prev, semesters: updatedSems };
      });
    } catch (err) { alert("Scan Gagal."); } finally { setIsScanning(false); }
  };

  const triggerAnalysis = useCallback(() => {
    if (!validation.canCalculate) return;
    setIsCalculating(true);
    setTimeout(() => {
      setIsCalculating(false);
      setShowResults(true);
      if (allSemestersComplete) setShowFinalModal(true);
      reportRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 1200);
  }, [validation.canCalculate, allSemestersComplete]);

  const renderModal = (title: string, content: React.ReactNode, onClose: () => void, accentColor: string = "border-indigo-500") => (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-slate-950/90 backdrop-blur-md">
      <div className={`glass-card rounded-[2.5rem] w-full max-w-xl p-8 md:p-12 animate-in border-t-8 ${accentColor} shadow-3xl`}>
        <div className="flex justify-between items-center mb-8">
           <h3 className="text-2xl font-black uppercase tracking-tighter text-slate-100">{title}</h3>
           <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-slate-400">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="2" strokeLinecap="round"/></svg>
           </button>
        </div>
        <div className="text-slate-200">
          {content}
        </div>
        <button onClick={onClose} className="w-full mt-10 py-5 bg-indigo-600 text-white font-black uppercase tracking-widest rounded-2xl hover:bg-indigo-500 active:scale-95 transition-all shadow-xl">Tutup & Kembali</button>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col min-h-screen text-slate-100 selection:bg-indigo-500/30">

      {/* AI Scanning Loader */}
      {isScanning && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-slate-950/95 backdrop-blur-xl">
           <div className="relative w-24 h-24 mb-8">
              <div className="absolute inset-0 border-4 border-indigo-500/10 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-t-indigo-500 rounded-full animate-spin"></div>
           </div>
           <p className="tech-font text-indigo-400 animate-pulse text-xs tracking-[0.4em] uppercase font-black">AI Grade Intel: {scanProgress.current}/{scanProgress.total}</p>
        </div>
      )}

      {/* Welcome Modal */}
      {showWelcome && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-3xl">
          <div className="glass-card rounded-[3rem] p-10 md:p-14 w-full max-w-lg text-center animate-in shadow-3xl border-t-8 border-indigo-500">
            <h2 className="text-4xl font-black mb-3">Smart<span className="text-indigo-400">Rapor</span></h2>
            <p className="text-slate-400 text-[11px] uppercase tracking-[0.4em] font-black mb-10">Academic Intelligence Platform</p>
            <div className="relative mb-8">
              <input 
                type="text" 
                value={data.userName} 
                onChange={e => setData(prev => ({ ...prev, userName: e.target.value }))} 
                className="w-full bg-slate-900/50 border-2 border-white/10 rounded-2xl py-6 px-8 text-center text-xl font-bold text-white outline-none focus:border-indigo-500 transition-all placeholder:text-slate-600 shadow-inner" 
                placeholder="Siapa namamu?" 
                onKeyDown={e => e.key === 'Enter' && data.userName && setShowWelcome(false)}
              />
            </div>
            <button 
              onClick={() => data.userName && setShowWelcome(false)} 
              className="w-full py-6 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-2xl hover:bg-indigo-500 hover:scale-[1.02] active:scale-95 transition-all text-lg"
            >
              Akses Dashboard
            </button>
          </div>
        </div>
      )}

      {/* Final Outcome Modal */}
      {showFinalModal && renderModal(
        overallAvg >= data.targetAvg ? "TARGET TERCAPAI! 🎓" : "PERJALANAN BELUM BERAKHIR 🔥",
        <div className="text-center">
          <div className={`text-8xl font-black tech-font mb-6 ${overallAvg >= data.targetAvg ? 'text-emerald-400' : 'text-amber-400'}`}>
            {overallAvg.toFixed(1)}%
          </div>
          <p className="text-xl leading-relaxed text-slate-300 mb-8">
            {overallAvg >= data.targetAvg 
              ? `Selamat ${data.userName}! Kamu berhasil melampaui target ${data.targetAvg}%. Semua usaha kerasmu membuahkan hasil yang gemilang.`
              : `Halo ${data.userName}, rerata akhirmu adalah ${overallAvg.toFixed(1)}%. Meskipun belum menyentuh target ${data.targetAvg}%, perjalananmu adalah bukti kegigihan. Jadikan ini pijakan untuk sukses berikutnya!`
            }
          </p>
          <div className={`p-8 rounded-[2rem] border ${overallAvg >= data.targetAvg ? 'bg-emerald-500/10 border-emerald-500/20' : 'bg-amber-500/10 border-amber-500/20'} italic text-slate-300 text-base shadow-inner`}>
            {overallAvg >= data.targetAvg 
              ? "“Pendidikan adalah kunci untuk membuka pintu emas kebebasan.” — George Washington Carver" 
              : "“Sukses bukanlah akhir, kegagalan bukanlah hal yang fatal: keberanian untuk melanjutkanlah yang terpenting.” — Winston Churchill"
            }
          </div>
        </div>,
        () => setShowFinalModal(false),
        overallAvg >= data.targetAvg ? 'border-emerald-500' : 'border-amber-500'
      )}

      {/* Semester Summary Modal */}
