            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            className="bg-white dark:bg-slate-900 rounded-[3rem] p-8 md:p-16 mb-12 shadow-2xl border border-slate-200 dark:border-slate-800"
