            className="w-full py-8 bg-gradient-to-r from-indigo-600 to-blue-600 text-white rounded-[3rem] font-black text-2xl uppercase tracking-[0.3em] shadow-2xl shadow-indigo-500/30 disabled:opacity-30 disabled:grayscale transition-all"
