                <div className="lg:col-span-2 bg-slate-900 text-white p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden flex flex-col justify-center">
                   <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-600/10 blur-[100px] rounded-full"></div>
                   <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-8">{t.neededAvg}</h4>
                   <div className="flex flex-col sm:flex-row items-center gap-12">
                      <div className="p-10 bg-white/5 rounded-[3rem] border border-white/10 text-center min-w-[180px]">
                         <div className="text-6xl font-black tech-font text-indigo-400">{allSemestersComplete ? '✓' : `${neededAvg.toFixed(1)}%`}</div>
                      </div>
                      <p className="text-2xl italic font-medium leading-relaxed text-slate-300">
                        {allSemestersComplete 
                          ? (data.language === 'id' ? 'Seluruh rekam jejak akademik Anda telah tuntas dihitung.' : 'Your entire academic track record has been fully calculated.')
                          : (data.language === 'id' ? `Minimal rata-rata per semester berikutnya adalah ${neededAvg.toFixed(1)}% untuk mencapai target.` : `Minimum average per next semester is ${neededAvg.toFixed(1)}% to reach your target.`)}
                      </p>
                   </div>
                </div>
             </div>
          </motion.div>
        )}
      </main>

      {/* Modals Container */}
      <AnimatePresence>
        {showWelcome && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-3xl flex items-center justify-center p-4">
            <motion.div variants={modalVariants} initial="hidden" animate="visible" className="bg-white dark:bg-slate-900 p-12 rounded-[3rem] w-full max-w-lg text-center shadow-3xl">
              <h2 className="text-4xl font-black mb-2 tracking-tighter">{t.welcome}</h2>
              <p className="text-slate-500 font-bold text-xs uppercase tracking-widest mb-10">{t.subtitle}</p>
              <input 
                autoFocus
                type="text" 
                value={data.userName} 
                onChange={e => setData(d => ({ ...d, userName: e.target.value }))}
                placeholder={t.enterName}
                className="w-full p-6 bg-slate-100 dark:bg-slate-800 rounded-2xl text-xl font-bold text-center outline-none focus:ring-4 ring-indigo-500/20 mb-8 transition-all"
                onKeyDown={e => e.key === 'Enter' && data.userName && setShowWelcome(false)}
              />
              <button 
                onClick={() => data.userName && setShowWelcome(false)}
                className="w-full py-6 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-indigo-700 transition-all active:scale-95"
              >
                {t.start}
