        )}

        {showGuide && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4">
            <motion.div variants={modalVariants} initial="hidden" animate="visible" className="bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] w-full max-w-xl shadow-3xl border border-white/5">
              <h3 className="text-2xl font-black uppercase mb-8 tracking-tighter">{t.guide}</h3>
              <div className="space-y-6 mb-10">
                {t.guideSteps.map((step: string, i: number) => (
                  <div key={i} className="flex gap-4 items-start">
                    <div className="w-8 h-8 rounded-xl bg-indigo-600 text-white flex items-center justify-center font-black shrink-0">{i+1}</div>
                    <p className="text-slate-600 dark:text-slate-400 font-medium leading-relaxed">{step}</p>
                  </div>
                ))}
              </div>
              <button onClick={() => setShowGuide(false)} className="w-full py-5 bg-slate-200 dark:bg-slate-800 rounded-2xl font-black uppercase tracking-widest transition-all active:scale-95">{t.close}</button>
            </motion.div>
          </motion.div>
        )}

        {summarySemesterId !== null && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4">
            <motion.div variants={modalVariants} initial="hidden" animate="visible" className="bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] w-full max-w-xl shadow-3xl">
              <div className="flex justify-between items-center mb-8">
                <h3 className="text-2xl font-black uppercase tracking-tighter">SMT {summarySemesterId} {t.stats}</h3>
                <button onClick={() => setSummarySemesterId(null)} className="text-2xl">✕</button>
              </div>
              {(() => {
                const sem = data.semesters.find(s => s.id === summarySemesterId);
                const avg = calculateSemesterAverage(sem!);
                const sorted = [...sem!.subjects].sort((a,b) => b.score - a.score);
                return (
                  <div className="space-y-6">
                    <div className="p-8 bg-indigo-600/10 rounded-[2rem] text-center">
                      <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500 mb-2 block">Average Score</span>
                      <div className="text-5xl font-black tech-font text-indigo-600">{avg.toFixed(1)}</div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="p-5 bg-emerald-500/10 rounded-2xl border border-emerald-500/20">
                        <span className="text-[8px] font-black uppercase tracking-widest text-emerald-500 block mb-1">{t.highest}</span>
                        <div className="text-xl font-black tech-font text-emerald-600">{sorted[0]?.score || 0}</div>
                      </div>
                      <div className="p-5 bg-rose-500/10 rounded-2xl border border-rose-500/20">
                        <span className="text-[8px] font-black uppercase tracking-widest text-rose-500 block mb-1">{t.lowest}</span>
                        <div className="text-xl font-black tech-font text-rose-600">{sorted[sorted.length-1]?.score || 0}</div>
                      </div>
                    </div>
                    <div className="max-h-48 overflow-y-auto pr-2 no-scrollbar border-t border-slate-100 dark:border-slate-800 pt-4">
                      {sorted.map(s => (
                        <div key={s.id} className="flex justify-between py-2 text-sm border-b border-slate-50 dark:border-slate-800 last:border-0">
                          <span className="font-bold text-slate-500">{s.name}</span>
                          <span className="tech-font font-black">{s.score}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })()}
              <button onClick={() => setSummarySemesterId(null)} className="w-full mt-8 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl">{t.close}</button>
            </motion.div>
