import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  getSemesterStats,
  saveToStorage, 
  loadFromStorage,
  translations 
} from './utils';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6,
  theme: 'dark',
  language: 'id'
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [activeModal, setActiveModal] = useState<'semester' | 'final' | null>(null);
  const [selectedResultId, setSelectedResultId] = useState<number | null>(null);

  const t = useMemo(() => translations[data.language], [data.language]);

  // Load persistence
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      setData(prev => ({ ...prev, theme: prefersDark ? 'dark' : 'light' }));
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  // Theme Synchronizer
  useEffect(() => {
    if (data.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    if (isLoaded) saveToStorage(data);
  }, [data.theme, data, isLoaded]);

  // Dynamic Semester Sync
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);
    if (data.semesters.length !== targetCount) {
      setData(prev => {
        let currentSems = [...prev.semesters];
        const s1 = currentSems[0];
        if (currentSems.length < targetCount) {
          const toAdd = targetCount - currentSems.length;
          const newSems = Array.from({ length: toAdd }, (_, i) => ({ 
            id: currentSems.length + i + 1, 
            subjects: s1?.subjects.map(s => ({ ...s, score: 0, id: generateId() })) || [] 
          }));
          currentSems = [...currentSems, ...newSems];
        } else {
          currentSems = currentSems.slice(0, targetCount);
        }
        return { ...prev, semesters: currentSems };
      });
    }
  }, [data.totalSemestersTarget, isLoaded]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => 
    data.semesters.find(s => s.id === activeSemesterId) || null,
    [data.semesters, activeSemesterId]
  );

  const isGlobalCalculationValid = useMemo(() => {
    const sems = data.semesters;
    if (sems.length === 0 || sems[0].subjects.length === 0) return false;
    let lastActiveSemIdx = -1;
    for (let i = sems.length - 1; i >= 0; i--) {
      if (sems[i].subjects.some(sub => sub.score > 0)) {
        lastActiveSemIdx = i;
        break;
      }
    }
    if (lastActiveSemIdx === -1) return false;
    for (let i = 0; i <= lastActiveSemIdx; i++) {
      if (sems[i].subjects.some(sub => sub.score <= 0)) return false;
    }
    return true;
  }, [data.semesters]);

  const completeSemesters = useMemo(() => 
    data.semesters.filter(s => getSemesterStatus(s) === 'complete'), 
  [data.semesters, getSemesterStatus]);

  const allSemestersComplete = useMemo(() => 
    completeSemesters.length >= data.totalSemestersTarget && completeSemesters.length > 0,
    [completeSemesters.length, data.totalSemestersTarget]
  );

  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, Math.min(100, needed));
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const diagnostic = useMemo(() => {
    if (completeSemesters.length < 2) return null;
    const last = calculateSemesterAverage(completeSemesters[completeSemesters.length - 1]);
    const prev = calculateSemesterAverage(completeSemesters[completeSemesters.length - 2]);
    if (last > prev + 0.3) return { trend: t.trendTypes.up, color: 'text-emerald-500', icon: '↗️' };
    if (last < prev - 0.3) return { trend: t.trendTypes.down, color: 'text-rose-500', icon: '↘️' };
    return { trend: t.trendTypes.stable, color: 'text-indigo-500', icon: '➡️' };
  }, [completeSemesters, t]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });

      const syncS1ToOthers = (allSemesters: Semester[]) => {
        const s1 = allSemesters[0];
        if (!s1) return allSemesters;
        return allSemesters.map(s => {
          if (s.id === 1) return s;
          const newSubjects = s1.subjects.map(template => {
            const existing = s.subjects.find(sub => sub.name === template.name);
            return existing ? { ...existing, name: template.name } : { ...template, score: 0, id: generateId() };
          });
          return { ...s, subjects: newSubjects };
        });
      };

      return activeSemesterId === 1 && field === 'name' 
        ? { ...prev, semesters: syncS1ToOthers(updatedSems) }
        : { ...prev, semesters: updatedSems };
    });
    setShowResults(false);
  };

  const handleAddSubject = () => {
    setData(prev => {
      const newId = generateId();
      const updatedSems = prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: generateId(), name: '', score: 0 }]
      }));
      return { ...prev, semesters: updatedSems };
    });
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const targetSub = prev.semesters[activeSemesterId - 1].subjects.find(s => s.id === subId);
      if (!targetSub) return prev;
      const newSemesters = prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => {
          if (activeSemesterId === 1) return sub.name !== targetSub.name;
          return sub.id !== subId;
        })
      }));
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const runCalculation = () => {
    if (!isGlobalCalculationValid) return;
    setIsCalculating(true);
    setTimeout(() => {
      setIsCalculating(false);
      setShowResults(true);
      if (allSemestersComplete) {
        setActiveModal('final');
      } else {
        const lastFilled = [...data.semesters].reverse().find(s => getSemesterStatus(s) === 'complete');
        if (lastFilled) {
          setSelectedResultId(lastFilled.id);
          setActiveModal('semester');
        }
      }
    }, 1200);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const toggleLanguage = () => setData(d => ({ ...d, language: d.language === 'id' ? 'en' : 'id' }));
  const toggleTheme = () => setData(d => ({ ...d, theme: d.theme === 'dark' ? 'light' : 'dark' }));

  const ModalWrapper = ({ children, onClose, maxWidth = 'max-w-xl' }: { children?: React.ReactNode, onClose: () => void, maxWidth?: string }) => (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4 sm:p-6"
      onClick={onClose}
    >
      <motion.div 
        initial={{ scale: 0.95, y: 40, opacity: 0 }} 
        animate={{ scale: 1, y: 0, opacity: 1 }} 
        exit={{ scale: 0.95, y: 40, opacity: 0 }}
        transition={{ type: "spring", damping: 25, stiffness: 300 }}
        className={`bg-white dark:bg-slate-900 w-full ${maxWidth} rounded-[2.5rem] sm:rounded-[3.5rem] p-6 sm:p-12 shadow-3xl border border-slate-200 dark:border-slate-800 relative overflow-hidden max-h-[90vh] overflow-y-auto no-scrollbar`}
        onClick={e => e.stopPropagation()}
      >
        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 blur-[60px] rounded-full -mr-16 -mt-16"></div>
        <div className="absolute bottom-0 left-0 w-32 h-32 bg-blue-500/10 blur-[60px] rounded-full -ml-16 -mb-16"></div>
        {children}
      </motion.div>
    </motion.div>
  );

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-50 transition-colors duration-500 overflow-x-hidden">

      {/* Navigation */}
      <nav className="sticky top-0 z-50 bg-white/70 dark:bg-slate-900/70 backdrop-blur-2xl border-b border-slate-200 dark:border-slate-800 px-4 md:px-8 py-3 sm:py-4 print:hidden">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} className="flex items-center gap-2 sm:gap-3">
            <div className="w-8 h-8 sm:w-10 sm:h-10 bg-indigo-600 rounded-xl sm:rounded-2xl flex items-center justify-center font-black text-white text-lg sm:text-xl shadow-lg">S</div>
