                      <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500 mb-3 block">Semester Average Score</span>
                      <div className="text-6xl sm:text-7xl font-black tech-font text-indigo-600">{avg.toFixed(1)}</div>
