                      <motion.div initial={{ x: -20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: 0.2 }} className="p-6 sm:p-8 bg-emerald-500/5 rounded-[2rem] sm:rounded-[2.5rem] border border-emerald-500/10 shadow-sm text-center">
