                 <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6 block relative z-10">Final Cumulative Score</span>
                 <div className="text-7xl sm:text-9xl font-black tech-font text-indigo-400 relative z-10">{overallAvg.toFixed(1)}</div>
              </motion.div>
              <div className="flex flex-col sm:flex-row gap-4">
                <button 
                  onClick={handleExportPDF}
