                >
                  SELESAI
                </button>
              </div>
            </div>
          </ModalWrapper>
        )}
      </AnimatePresence>

      <footer className="py-24 sm:py-32 text-center border-t border-slate-200 dark:border-slate-800 mt-12 sm:mt-24 print:hidden">
        <div className="flex flex-col items-center gap-4 sm:gap-6">
           <div className="w-10 h-10 sm:w-12 sm:h-12 bg-slate-200 dark:bg-slate-800 rounded-xl sm:rounded-2xl flex items-center justify-center font-black text-xs sm:text-sm shadow-md">S</div>
           <p className="text-[8px] sm:text-[10px] font-black uppercase tracking-[0.6em] sm:tracking-[0.8em] text-slate-400 opacity-50 px-4">Smart Rapor Ecosystem Pro &copy; 2025</p>
        </div>
      </footer>
    </div>
  );
};

