                  <p className="text-slate-600 dark:text-slate-400 font-medium leading-relaxed text-base sm:text-lg">{step}</p>
                </motion.div>
              ))}
            </div>
            <button onClick={() => setShowGuide(false)} className="w-full py-6 bg-slate-100 dark:bg-slate-800 rounded-2xl font-black uppercase tracking-widest transition-all hover:bg-slate-200 dark:hover:bg-slate-700 active:scale-95">{t.close}</button>
          </ModalWrapper>
        )}

        {activeModal === 'semester' && selectedResultId !== null && (
          <ModalWrapper onClose={() => setActiveModal(null)}>
            {(() => {
                const sem = data.semesters.find(s => s.id === selectedResultId);
                if (!sem) return null;
                const avg = calculateSemesterAverage(sem);
                const stats = getSemesterStats(sem);
                return (
                  <div className="text-center relative">
                    <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2 block">{t.semester} {selectedResultId}</span>
                    <h3 className="text-3xl sm:text-4xl font-black uppercase tracking-tighter mb-8 sm:mb-10 text-indigo-600 truncate px-4">{data.userName}</h3>

                    <motion.div 
                      initial={{ scale: 0.9, opacity: 0 }} 
                      animate={{ scale: 1, opacity: 1 }} 
                      className="p-8 sm:p-12 bg-indigo-600/10 rounded-[2.5rem] sm:rounded-[3rem] border-2 border-indigo-600/20 mb-8 sm:mb-10 shadow-inner"
                    >
                      <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500 mb-3 block">Semester Average Score</span>
                      <div className="text-6xl sm:text-7xl font-black tech-font text-indigo-600">{avg.toFixed(1)}</div>
                    </motion.div>

                    <div className="grid grid-cols-2 gap-4 sm:gap-6 mb-8 sm:mb-10">
                      <motion.div initial={{ x: -20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: 0.2 }} className="p-6 sm:p-8 bg-emerald-500/5 rounded-[2rem] sm:rounded-[2.5rem] border border-emerald-500/10 shadow-sm text-center">
                        <span className="text-[8px] sm:text-[10px] font-black uppercase tracking-widest text-emerald-500 block mb-2">{t.highest}</span>
                        <div className="text-2xl sm:text-3xl font-black tech-font text-emerald-600">{stats.highest > 0 ? stats.highest : '---'}</div>
                      </motion.div>
                      <motion.div initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: 0.2 }} className="p-6 sm:p-8 bg-rose-500/5 rounded-[2rem] sm:rounded-[2.5rem] border border-rose-500/10 shadow-sm text-center">
                        <span className="text-[8px] sm:text-[10px] font-black uppercase tracking-widest text-rose-500 block mb-2">{t.lowest}</span>
                        <div className="text-2xl sm:text-3xl font-black tech-font text-rose-600">{stats.lowest > 0 ? stats.lowest : '---'}</div>
                      </motion.div>
                    </div>

                    <button onClick={() => setActiveModal(null)} className="w-full py-6 sm:py-8 bg-indigo-600 text-white rounded-[2rem] font-black uppercase tracking-[0.2em] shadow-2xl transition-all hover:brightness-110 active:scale-95 text-lg sm:text-xl">{t.close}</button>
                  </div>
                );
            })()}
          </ModalWrapper>
        )}

        {activeModal === 'final' && (
          <ModalWrapper onClose={() => setActiveModal(null)} maxWidth="max-w-2xl">
            <div className="text-center">
              <motion.div 
                initial={{ scale: 0.5, rotate: -20, opacity: 0 }}
                animate={{ scale: 1, rotate: 0, opacity: 1 }}
                className="w-24 h-24 sm:w-28 sm:h-28 bg-indigo-600/10 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 text-5xl shadow-inner border border-indigo-500/10"
              >
                🎓
              </motion.div>
              <h3 className="text-3xl sm:text-4xl font-black uppercase tracking-tighter mb-2 text-indigo-600 truncate px-4">{data.userName}</h3>
              <p className="text-xl sm:text-2xl font-black uppercase tracking-tight mb-4">
                {overallAvg >= data.targetAvg ? t.finalSuccess : t.finalFail}
              </p>
              <p className="text-slate-500 dark:text-slate-400 font-medium mb-10 sm:mb-12 px-2 sm:px-6 text-base sm:text-lg">
                {overallAvg >= data.targetAvg 
                  ? `Prestasi luar biasa! Rata-rata akhir ${overallAvg.toFixed(1)}% berhasil menembus target ${data.targetAvg}%.`
                  : `Tetap semangat! Rata-rata ${overallAvg.toFixed(1)}% belum mencapai target ${data.targetAvg}%.`
                }
              </p>
              <motion.div 
                initial={{ y: 20, opacity: 0 }} 
                animate={{ y: 0, opacity: 1 }} 
                transition={{ delay: 0.3 }}
                className="p-10 sm:p-16 bg-slate-900 text-white rounded-[3rem] sm:rounded-[4rem] shadow-3xl mb-10 sm:mb-12 border-t-8 border-indigo-600 relative overflow-hidden"
              >
                 <div className="absolute top-0 right-0 w-48 h-48 bg-indigo-500/10 blur-[60px] rounded-full"></div>
                 <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6 block relative z-10">Final Cumulative Score</span>
                 <div className="text-7xl sm:text-9xl font-black tech-font text-indigo-400 relative z-10">{overallAvg.toFixed(1)}</div>
              </motion.div>
              <div className="flex flex-col sm:flex-row gap-4">
                <button 
                  onClick={handleExportPDF}
                  className="flex-1 py-6 sm:py-8 bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl hover:bg-slate-200 dark:hover:bg-slate-700 transition-all text-lg"
                >
                  Ekspor PDF
                </button>
                <button 
                  onClick={() => setActiveModal(null)} 
                  className="flex-[2] py-6 sm:py-8 bg-indigo-600 text-white rounded-[2rem] font-black uppercase tracking-[0.3em] shadow-2xl hover:bg-indigo-700 transition-all text-lg active:scale-95"
                >
                  SELESAI
                </button>
              </div>
            </div>
          </ModalWrapper>
        )}
      </AnimatePresence>

      <footer className="py-24 sm:py-32 text-center border-t border-slate-200 dark:border-slate-800 mt-12 sm:mt-24 print:hidden">
        <div className="flex flex-col items-center gap-4 sm:gap-6">
           <div className="w-10 h-10 sm:w-12 sm:h-12 bg-slate-200 dark:bg-slate-800 rounded-xl sm:rounded-2xl flex items-center justify-center font-black text-xs sm:text-sm shadow-md">S</div>
           <p className="text-[8px] sm:text-[10px] font-black uppercase tracking-[0.6em] sm:tracking-[0.8em] text-slate-400 opacity-50 px-4">Smart Rapor Ecosystem Pro &copy; 2025</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  getSemesterStats,
  saveToStorage, 
  loadFromStorage,
  translations 
} from './utils';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6,
  theme: 'dark',
  language: 'id'
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [activeModal, setActiveModal] = useState<'semester' | 'final' | null>(null);
  const [selectedResultId, setSelectedResultId] = useState<number | null>(null);

  const t = useMemo(() => translations[data.language], [data.language]);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      setData(prev => ({ ...prev, theme: prefersDark ? 'dark' : 'light' }));
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (data.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    if (isLoaded) saveToStorage(data);
  }, [data.theme, data, isLoaded]);

  const syncS1ToOthers = useCallback((allSemesters: Semester[]) => {
    const s1 = allSemesters[0];
    if (!s1) return allSemesters;
    return allSemesters.map(s => {
      if (s.id === 1) return s;
      const newSubjects = s1.subjects.map(template => {
        const existing = s.subjects.find(sub => sub.name === template.name);
        return existing ? { ...existing, name: template.name } : { id: generateId(), name: template.name, score: 0 };
      });
      return { ...s, subjects: newSubjects };
    });
  }, []);

  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);
    if (data.semesters.length !== targetCount) {
      setData(prev => {
        let currentSems = [...prev.semesters];
        if (currentSems.length < targetCount) {
          const toAdd = targetCount - currentSems.length;
          const newSems = Array.from({ length: toAdd }, (_, i) => ({ id: currentSems.length + i + 1, subjects: [] }));
          currentSems = [...currentSems, ...newSems];
        } else {
          currentSems = currentSems.slice(0, targetCount);
        }
        return { ...prev, semesters: syncS1ToOthers(currentSems) };
      });
    }
  }, [data.totalSemestersTarget, isLoaded, syncS1ToOthers]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => data.semesters.find(s => s.id === activeSemesterId) || null, [data.semesters, activeSemesterId]);
  const completeSemesters = useMemo(() => data.semesters.filter(s => getSemesterStatus(s) === 'complete'), [data.semesters, getSemesterStatus]);
  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, Math.min(100, needed));
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const isGlobalCalculationValid = useMemo(() => {
    const sems = data.semesters;
    if (sems.length === 0 || sems[0].subjects.length === 0) return false;
    let lastActiveSemIdx = -1;
    for (let i = sems.length - 1; i >= 0; i--) {
      if (sems[i].subjects.some(sub => sub.score > 0)) {
        lastActiveSemIdx = i;
        break;
      }
    }
    if (lastActiveSemIdx === -1) return false;
    for (let i = 0; i <= lastActiveSemIdx; i++) {
      if (sems[i].subjects.some(sub => sub.score <= 0)) return false;
    }
    return true;
  }, [data.semesters]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });
      return activeSemesterId === 1 && field === 'name' ? { ...prev, semesters: syncS1ToOthers(updatedSems) } : { ...prev, semesters: updatedSems };
    });
    setShowResults(false);
  };

  const handleAddSubject = () => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: generateId(), name: '', score: 0 }]
      }));
      return { ...prev, semesters: updatedSems };
    });
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const targetSem = prev.semesters.find(s => s.id === activeSemesterId);
      const targetSub = targetSem?.subjects.find(s => s.id === subId);
      if (!targetSub) return prev;
      const newSemesters = prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => activeSemesterId === 1 ? sub.name !== targetSub.name : sub.id !== subId)
      }));
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const ModalWrapper = ({ children, onClose, maxWidth = 'max-w-xl' }: { children?: React.ReactNode, onClose: () => void, maxWidth?: string }) => (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] bg-slate-950/70 backdrop-blur-md flex items-center justify-center p-4 sm:p-6"
      onClick={onClose}
    >
      <motion.div 
        initial={{ scale: 0.9, y: 30, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.9, y: 30, opacity: 0 }}
        className={`bg-white dark:bg-slate-900 w-full ${maxWidth} rounded-5xl p-6 sm:p-10 shadow-3xl border border-slate-200 dark:border-slate-800 relative overflow-hidden max-h-[90vh] overflow-y-auto no-scrollbar`}
        onClick={e => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:scale-110 transition-all">✕</button>
        {children}
      </motion.div>
    </motion.div>
  );

  return (
    <div className="min-h-screen flex flex-col bg-indigo-50/50 dark:bg-slate-950 transition-colors duration-500">

      {/* Navbar Modern */}
      <nav className="sticky top-0 z-50 glass dark:glass border-b border-slate-200 dark:border-slate-800 px-6 md:px-12 py-4 print-hide">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-lg">S</div>
            <h1 className="text-xl font-extrabold tracking-tight hidden xs:block">Smart<span className="text-indigo-600">Rapor</span></h1>
          </div>

          <div className="flex items-center gap-3">
            <button onClick={() => setData(d => ({ ...d, language: d.language === 'id' ? 'en' : 'id' }))} className="px-4 py-2 rounded-xl bg-white dark:bg-slate-800 text-[10px] font-black uppercase tracking-wider shadow-sm hover:bg-indigo-600 hover:text-white transition-all">
              {data.language.toUpperCase()}
            </button>
            <button onClick={() => setData(d => ({ ...d, theme: d.theme === 'dark' ? 'light' : 'dark' }))} className="p-2.5 rounded-xl bg-white dark:bg-slate-800 shadow-sm hover:scale-110 transition-all text-xl">
              {data.theme === 'dark' ? '🌞' : '🌙'}
            </button>
            <div onClick={() => setShowWelcome(true)} className="flex items-center gap-2 cursor-pointer p-1.5 pr-4 bg-white dark:bg-slate-800 rounded-full shadow-sm hover:shadow-md transition-all border border-slate-200 dark:border-slate-700">
              <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white font-bold text-sm">{data.userName[0] || '?'}</div>
              <span className="hidden sm:inline text-xs font-bold uppercase truncate max-w-[100px]">{data.userName || 'Guest'}</span>
            </div>
          </div>
        </div>
      </nav>

      {/* Header Print */}
      <div className="hidden print-block p-12 border-b-4 border-indigo-600 mb-12">
        <div className="flex justify-between items-end">
          <div>
            <h1 className="text-4xl font-black mb-2">SmartRapor <span className="text-indigo-600 text-2xl font-bold">Analysis Report</span></h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">{new Date().toLocaleDateString()}</p>
          </div>
          <div className="text-right">
            <p className="text-xs font-black uppercase text-indigo-600 mb-1">Student Name</p>
            <p className="text-3xl font-black uppercase tracking-tight">{data.userName}</p>
          </div>
        </div>
      </div>

      <main className="flex-grow max-w-7xl mx-auto w-full px-6 md:px-12 py-10 md:py-16">

        {/* Welcome Section */}
        <section className="mb-12 text-center md:text-left print-hide">
          <motion.h2 initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="text-5xl sm:text-7xl font-black tracking-tight leading-tight mb-4">
            Hello, <span className="text-indigo-600">{data.userName || 'Student'}!</span>
          </motion.h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-2xl text-lg font-medium">Lacak dan petakan nilai rapormu dengan analisis tercanggih.</p>
        </section>

        {/* Big Dashboard Statistics */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-16 print-mb-10">
          {[
            { label: t.targetAvg, value: data.targetAvg, key: 'targetAvg', suffix: '%', editable: true },
            { label: t.totalSemesters, value: data.totalSemestersTarget, key: 'totalSemestersTarget', suffix: '', editable: true },
            { label: t.neededAvg, value: neededAvg.toFixed(1), suffix: '%', highlight: true },
            { label: 'GPA Cumulative', value: overallAvg.toFixed(1), suffix: '', highlight: true, color: 'text-indigo-600' }
          ].map((stat, i) => (
            <motion.div key={i} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: i * 0.1 }}
              className="bg-white dark:bg-slate-900 p-8 rounded-4xl shadow-xl shadow-indigo-100 dark:shadow-none border border-slate-100 dark:border-slate-800 print-shadow-none print-border-slate-200"
            >
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 block mb-4">{stat.label}</span>
              <div className="flex items-end gap-1">
                {stat.editable ? (
                  <input type="number" value={stat.value} onChange={e => setData(d => ({ ...d, [stat.key!]: parseFloat(e.target.value) || 0 }))}
                    className="bg-transparent text-4xl font-black tech-font outline-none focus:text-indigo-600 w-full print-hide" />
                ) : (
                  <span className={`text-4xl font-black tech-font ${stat.color || ''}`}>{stat.value}</span>
                )}
                <span className="text-xl font-bold text-slate-400 pb-1">{stat.suffix}</span>
              </div>
              {stat.editable && <div className="hidden print-block text-3xl font-black tech-font">{stat.value}</div>}
            </motion.div>
          ))}
        </section>

        {/* Semester Tabs - Modern Pills */}
        <div className="flex gap-3 overflow-x-auto pb-6 no-scrollbar mb-10 print-hide">
          {data.semesters.map(s => {
            const active = activeSemesterId === s.id;
            const status = getSemesterStatus(s);
            return (
              <button key={s.id} onClick={() => setActiveSemesterId(s.id)}
                className={`flex-shrink-0 px-8 py-4 rounded-full font-bold transition-all border-2 ${
                  active ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white dark:bg-slate-900 border-transparent text-slate-500 hover:border-indigo-200'
                }`}
              >
                Semester {s.id}
                {status === 'complete' && <span className="ml-2">✅</span>}
                {status === 'partial' && <span className="ml-2 text-amber-500">!</span>}
              </button>
            );
          })}
        </div>

        {/* Editor Card */}
        <AnimatePresence mode="wait">
          <motion.div key={activeSemesterId} initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}
            className="bg-white dark:bg-slate-900 rounded-5xl p-8 sm:p-12 mb-16 shadow-2xl border border-slate-100 dark:border-slate-800 print-shadow-none print-border-slate-200"
          >
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8 mb-10">
              <div>
                <h3 className="text-3xl font-black tracking-tight mb-1">Semester {activeSemesterId}</h3>
                <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">
                  {activeSemesterId === 1 ? 'Template Master (Sinkron ke SMT lain)' : 'Daftar Mata Pelajaran'}
                </p>
              </div>
              {activeSemesterId === 1 && (
                <button onClick={handleAddSubject} className="w-full md:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:brightness-110 shadow-lg transition-all print-hide">
                  + {t.addSubject}
                </button>
              )}
            </div>

            <div className="space-y-4">
              {activeSemester?.subjects.length === 0 ? (
                <div className="py-20 text-center border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-4xl text-slate-400 font-bold uppercase tracking-widest">
                  Belum ada data mata pelajaran
                </div>
              ) : activeSemester?.subjects.map((sub, i) => (
                <div key={sub.id} className="flex flex-col sm:flex-row items-center gap-4 bg-slate-50 dark:bg-slate-950 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 hover:border-indigo-200 transition-all group">
                  <div className="flex items-center gap-4 flex-grow w-full">
                    <span className="tech-font text-slate-300 dark:text-slate-700 font-bold text-lg">{(i+1).toString().padStart(2,'0')}</span>
                    <input type="text" value={sub.name} readOnly={activeSemesterId !== 1}
                      onChange={e => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      placeholder="Nama Mata Pelajaran"
                      className={`bg-transparent font-bold text-xl outline-none w-full print-hide ${activeSemesterId === 1 ? 'focus:text-indigo-600' : 'text-slate-500 cursor-default'}`} />
                    <div className="hidden print-block font-bold text-xl flex-grow">{sub.name || '-'}</div>
                  </div>
                  <div className="flex items-center gap-4 w-full sm:w-auto">
                    <input type="number" value={sub.score || ''} onChange={e => handleUpdateSubject(sub.id, 'score', parseFloat(e.target.value) || 0)}
                      className="w-full sm:w-28 bg-white dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl py-3 text-center font-black tech-font text-2xl focus:border-indigo-600 outline-none transition-all print-hide" placeholder="0" />
                    <div className="hidden print-block font-black text-2xl tech-font w-16 text-right">{sub.score}</div>
                    {activeSemesterId === 1 && (
                      <button onClick={() => handleDeleteSubject(sub.id)} className="p-3 text-slate-300 hover:text-rose-500 transition-colors print-hide">🗑️</button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Global Action Button */}
        <div className="max-w-2xl mx-auto mb-24 print-hide">
          <button disabled={!isGlobalCalculationValid || isCalculating} onClick={runCalculation}
            className={`w-full py-8 rounded-5xl font-black text-2xl uppercase tracking-[0.3em] shadow-2xl transition-all ${
              isGlobalCalculationValid ? 'bg-indigo-600 text-white hover:scale-105 shadow-indigo-200' : 'bg-slate-200 text-slate-400 cursor-not-allowed grayscale'
            }`}
          >
            {isCalculating ? t.calculating : t.calculate}
          </button>
          {!isGlobalCalculationValid && data.semesters[0].subjects.length > 0 && (
            <p className="text-amber-500 text-center mt-6 font-bold uppercase text-[10px] tracking-widest">⚠️ LENGKAPI SEMUA NILAI UNTUK MENGHITUNG</p>
          )}
        </div>

        {/* Summary Table Section */}
        <section className="mb-24 print-mt-12">
          <div className="flex justify-between items-center mb-10">
            <h4 className="text-3xl font-black tracking-tight">{t.analysisTable}</h4>
            {showResults && <button onClick={handleExportPDF} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:brightness-110 transition-all print-hide flex items-center gap-2">📥 {t.exportPdf}</button>}
          </div>
          <div className="bg-white dark:bg-slate-900 rounded-5xl overflow-hidden border border-slate-200 dark:border-slate-800 shadow-xl print-shadow-none print-border-slate-200">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-indigo-50/50 dark:bg-slate-950/50 border-b border-slate-200 dark:border-slate-800">
                  <th className="px-8 py-6 text-[10px] font-black uppercase text-slate-400">Semester</th>
                  <th className="px-8 py-6 text-[10px] font-black uppercase text-slate-400">{t.avgScore}</th>
                  <th className="px-8 py-6 text-[10px] font-black uppercase text-slate-400">{t.highest}</th>
                  <th className="px-8 py-6 text-[10px] font-black uppercase text-slate-400">{t.lowest}</th>
                  <th className="px-8 py-6 text-[10px] font-black uppercase text-slate-400 print-hide">Status</th>
                </tr>
              </thead>
              <tbody>
                {data.semesters.map(s => (
                  <tr key={s.id} className="border-b border-slate-100 dark:border-slate-800 last:border-0 hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                    <td className="px-8 py-6 font-black tech-font text-lg">{s.id.toString().padStart(2, '0')}</td>
                    <td className="px-8 py-6 font-black tech-font text-2xl text-indigo-600">{calculateSemesterAverage(s) > 0 ? calculateSemesterAverage(s).toFixed(1) : '---'}</td>
                    <td className="px-8 py-6 font-bold tech-font text-emerald-600">{getSemesterStats(s).highest > 0 ? getSemesterStats(s).highest : '---'}</td>
                    <td className="px-8 py-6 font-bold tech-font text-rose-500">{getSemesterStats(s).lowest > 0 ? getSemesterStats(s).lowest : '---'}</td>
                    <td className="px-8 py-6 print-hide">
                      <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase ${
                        getSemesterStatus(s) === 'complete' ? 'bg-emerald-100 text-emerald-600' : getSemesterStatus(s) === 'partial' ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'
                      }`}>
                        {t[`status${getSemesterStatus(s).charAt(0).toUpperCase() + getSemesterStatus(s).slice(1)}`]}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

      </main>

      {/* Modals Section */}
      <AnimatePresence>
        {showWelcome && (
          <ModalWrapper onClose={() => {}} maxWidth="max-w-md">
            <div className="text-center pt-6">
              <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-8 text-3xl text-white shadow-2xl">S</div>
              <h2 className="text-5xl font-black mb-2 tracking-tighter">{t.welcome}</h2>
              <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.2em] mb-10">SmartRapor Ecosystem</p>
              <input autoFocus type="text" value={data.userName} onChange={e => setData(d => ({ ...d, userName: e.target.value }))}
                placeholder={t.enterName}
                className="w-full p-8 bg-slate-100 dark:bg-slate-800 rounded-4xl text-2xl font-black text-center outline-none mb-8 focus:ring-8 ring-indigo-500/10 shadow-inner"
                onKeyDown={e => e.key === 'Enter' && data.userName && setShowWelcome(false)} />
              <button onClick={() => data.userName && setShowWelcome(false)} 
                className="w-full py-8 bg-indigo-600 text-white rounded-4xl font-black uppercase tracking-[0.2em] shadow-xl hover:brightness-110 active:scale-95 transition-all text-xl">
                {t.start}
              </button>
            </div>
          </ModalWrapper>
        )}

        {activeModal === 'semester' && selectedResultId !== null && (
          <ModalWrapper onClose={() => setActiveModal(null)}>
            <div className="text-center">
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">Analysis Complete</p>
              <h3 className="text-4xl font-black mb-8">Halo, {data.userName}!</h3>
              <div className="p-12 bg-indigo-50 dark:bg-slate-950 rounded-5xl border-2 border-indigo-100 dark:border-indigo-900/30 mb-8">
                <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-4">Rata-rata Semester {selectedResultId}</p>
                <div className="text-8xl font-black tech-font text-indigo-600">{calculateSemesterAverage(data.semesters[selectedResultId-1]).toFixed(1)}</div>
              </div>
              <button onClick={() => setActiveModal(null)} className="w-full py-6 bg-indigo-600 text-white rounded-3xl font-black uppercase tracking-widest text-lg shadow-lg">Lanjutkan</button>
            </div>
          </ModalWrapper>
        )}

        {activeModal === 'final' && (
          <ModalWrapper onClose={() => setActiveModal(null)} maxWidth="max-w-2xl">
            <div className="text-center">
              <div className="text-6xl mb-6">🎓</div>
              <h3 className="text-4xl font-black text-indigo-600 mb-2">{data.userName}</h3>
              <h4 className="text-2xl font-extrabold uppercase mb-8">{overallAvg >= data.targetAvg ? t.finalSuccess : t.finalFail}</h4>
              <div className="p-16 bg-slate-900 text-white rounded-5xl shadow-3xl mb-10 border-t-8 border-indigo-600 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-48 h-48 bg-indigo-500/10 blur-[60px] rounded-full"></div>
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4">Final GPA Score</p>
                <div className="text-9xl font-black tech-font text-indigo-400">{overallAvg.toFixed(1)}</div>
              </div>
              <div className="flex flex-col sm:flex-row gap-4">
                <button onClick={handleExportPDF} className="flex-1 py-6 bg-slate-100 dark:bg-slate-800 rounded-3xl font-black uppercase tracking-widest">Ekspor PDF</button>
                <button onClick={() => setActiveModal(null)} className="flex-[2] py-6 bg-indigo-600 text-white rounded-3xl font-black uppercase tracking-widest shadow-xl">Selesai</button>
              </div>
            </div>
          </ModalWrapper>
        )}
      </AnimatePresence>

      <footer className="py-20 text-center opacity-50 print-hide">
        <p className="text-[10px] font-black uppercase tracking-[1em]">SmartRapor &copy; 2025</p>
      </footer>
    </div>
  );
};

export default App;

