    status: "Status",
    statusComplete: "Complete",
    statusPartial: "Incomplete",
    statusEmpty: "Empty",
    exportPdf: "Download PDF",
    reportOf: "Report For:",
    reportTitle: "SmartRapor Academic Analysis Report",
    trendTypes: { up: "INCREASING", down: "DECREASING", stable: "STABLE" }
  }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  getSemesterStats,
  saveToStorage, 
  loadFromStorage,
  translations 
} from './utils';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6,
  theme: 'light',
  language: 'id'
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [activeModal, setActiveModal] = useState<'semester' | 'final' | null>(null);

  const t = useMemo(() => translations[data.language], [data.language]);

  // Persistent storage loader
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  // Theme & Auto-save
  useEffect(() => {
    if (data.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    if (isLoaded) saveToStorage(data);
  }, [data.theme, data, isLoaded]);

  // Subject synchronization logic
  const syncS1ToOthers = useCallback((allSemesters: Semester[]) => {
    const s1 = allSemesters[0];
    if (!s1) return allSemesters;
    return allSemesters.map(s => {
      if (s.id === 1) return s;
      const newSubjects = s1.subjects.map(template => {
        const existing = s.subjects.find(sub => sub.name === template.name);
        return existing ? { ...existing, name: template.name } : { id: generateId(), name: template.name, score: 0 };
      });
      return { ...s, subjects: newSubjects };
    });
  }, []);

  // Dynamic semester management
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);
    if (data.semesters.length !== targetCount) {
      setData(prev => {
        let currentSems = [...prev.semesters];
        if (currentSems.length < targetCount) {
          const toAdd = targetCount - currentSems.length;
          const newSems = Array.from({ length: toAdd }, (_, i) => ({ id: currentSems.length + i + 1, subjects: [] }));
          currentSems = [...currentSems, ...newSems];
        } else {
          currentSems = currentSems.slice(0, targetCount);
        }
        return { ...prev, semesters: syncS1ToOthers(currentSems) };
      });
    }
  }, [data.totalSemestersTarget, isLoaded, syncS1ToOthers]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => data.semesters.find(s => s.id === activeSemesterId) || null, [data.semesters, activeSemesterId]);
  const completeSemesters = useMemo(() => data.semesters.filter(s => getSemesterStatus(s) === 'complete'), [data.semesters, getSemesterStatus]);
  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, Math.min(100, needed));
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const isGlobalCalculationValid = useMemo(() => {
    const sems = data.semesters;
    if (sems.length === 0 || sems[0].subjects.length === 0) return false;
    let lastActiveIdx = -1;
    for (let i = sems.length - 1; i >= 0; i--) {
      if (sems[i].subjects.some(sub => sub.score > 0)) {
        lastActiveIdx = i;
        break;
      }
    }
    if (lastActiveIdx === -1) return false;
    for (let i = 0; i <= lastActiveIdx; i++) {
      if (sems[i].subjects.some(sub => sub.score <= 0)) return false;
    }
    return true;
  }, [data.semesters]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });
      return activeSemesterId === 1 && field === 'name' ? { ...prev, semesters: syncS1ToOthers(updatedSems) } : { ...prev, semesters: updatedSems };
    });
    setShowResults(false);
  };

  const handleAddSubject = () => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: generateId(), name: '', score: 0 }]
      }));
      return { ...prev, semesters: updatedSems };
    });
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const targetSem = prev.semesters.find(s => s.id === activeSemesterId);
      const targetSub = targetSem?.subjects.find(s => s.id === subId);
      if (!targetSub) return prev;
      const newSemesters = prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => activeSemesterId === 1 ? sub.name !== targetSub.name : sub.id !== subId)
      }));
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const runCalculation = async () => {
    if (!isGlobalCalculationValid) return;
    setIsCalculating(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsCalculating(false);
    setShowResults(true);
    setActiveModal('final');
  };

  const ModalWrapper = ({ children, onClose, maxWidth = 'max-w-xl' }: { children?: React.ReactNode, onClose: () => void, maxWidth?: string }) => (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] bg-slate-950/70 backdrop-blur-md flex items-center justify-center p-4 sm:p-6"
      onClick={onClose}
    >
      <motion.div 
        initial={{ scale: 0.9, y: 30, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.9, y: 30, opacity: 0 }}
        className={`bg-white dark:bg-slate-900 w-full ${maxWidth} rounded-[2.5rem] sm:rounded-[3.5rem] p-8 sm:p-12 shadow-3xl border border-slate-200 dark:border-slate-800 relative overflow-hidden max-h-[90vh] overflow-y-auto no-scrollbar`}
        onClick={e => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:scale-110 transition-all text-xl">✕</button>
        {children}
      </motion.div>
    </motion.div>
  );

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-500">

      {/* Navbar - Accessible & Clear */}
      <nav className="sticky top-0 z-50 glass dark:glass border-b border-slate-200 dark:border-slate-800 px-6 md:px-12 py-5 print-hide">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-2xl shadow-lg">S</div>
            <h1 className="text-2xl font-black tracking-tighter hidden xs:block uppercase">Smart<span className="text-indigo-600">Rapor</span></h1>
          </div>

          <div className="flex items-center gap-4">
            <button onClick={() => setData(d => ({ ...d, language: d.language === 'id' ? 'en' : 'id' }))} className="px-5 py-2.5 rounded-2xl bg-white dark:bg-slate-800 text-xs font-black uppercase tracking-widest shadow-sm hover:bg-indigo-600 hover:text-white transition-all border border-slate-100 dark:border-slate-700">
              {data.language.toUpperCase()}
            </button>
            <button onClick={() => setData(d => ({ ...d, theme: d.theme === 'dark' ? 'light' : 'dark' }))} className="p-3 rounded-2xl bg-white dark:bg-slate-800 shadow-sm hover:scale-110 transition-all text-2xl border border-slate-100 dark:border-slate-700">
              {data.theme === 'dark' ? '🌞' : '🌙'}
            </button>
            <div onClick={() => setShowWelcome(true)} className="flex items-center gap-3 cursor-pointer p-2 pr-5 bg-white dark:bg-slate-800 rounded-full shadow-sm hover:shadow-md transition-all border border-slate-200 dark:border-slate-700">
              <div className="w-9 h-9 rounded-full bg-indigo-600 flex items-center justify-center text-white font-bold text-base shadow-sm">{data.userName[0] || '?'}</div>
              <span className="hidden sm:inline text-sm font-black uppercase truncate max-w-[120px] tracking-tight">{data.userName || 'Guest'}</span>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-7xl mx-auto w-full px-6 md:px-12 py-12 md:py-20">

        {/* Welcome Section */}
        <section className="mb-16 text-center md:text-left print-hide">
          <motion.h2 initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="text-6xl sm:text-8xl font-black tracking-tight leading-[0.9] mb-6">
            Halo, <br className="md:hidden" /><span className="text-indigo-600">{data.userName || 'Siswa'}!</span>
          </motion.h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-2xl text-xl font-medium leading-relaxed">Kelola nilai rapormu dengan tampilan bersih dan analisis akurat untuk masa depan pendidikanmu.</p>
        </section>

        {/* Dash Stats Cards */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mb-20">
          {[
            { label: t.targetAvg, value: data.targetAvg, key: 'targetAvg', suffix: '%', editable: true },
            { label: t.totalSemesters, value: data.totalSemestersTarget, key: 'totalSemestersTarget', suffix: '', editable: true },
            { label: t.neededAvg, value: neededAvg.toFixed(1), suffix: '%', color: 'text-indigo-600' },
            { label: 'Rata-rata Kumulatif', value: overallAvg.toFixed(1), suffix: '', color: 'text-indigo-600' }
          ].map((stat, i) => (
            <motion.div key={i} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: i * 0.1 }}
              className="bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] shadow-xl shadow-indigo-100/50 dark:shadow-none border border-slate-100 dark:border-slate-800"
            >
              <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 block mb-5">{stat.label}</span>
              <div className="flex items-end gap-2">
                {stat.editable ? (
                  <input type="number" value={stat.value} onChange={e => setData(d => ({ ...d, [stat.key!]: parseFloat(e.target.value) || 0 }))}
                    className="bg-transparent text-5xl font-black tech-font outline-none focus:text-indigo-600 w-full print-hide" />
                ) : (
                  <span className={`text-5xl font-black tech-font ${stat.color || ''}`}>{stat.value}</span>
                )}
                <span className="text-2xl font-black text-slate-300 pb-2">{stat.suffix}</span>
              </div>
              {stat.editable && <div className="hidden print-block text-4xl font-black tech-font">{stat.value}</div>}
            </motion.div>
          ))}
        </section>

        {/* Semester Navigator - Large Pills */}
        <div className="flex gap-4 overflow-x-auto pb-8 no-scrollbar mb-12 print-hide px-2">
          {data.semesters.map(s => {
            const active = activeSemesterId === s.id;
            const status = getSemesterStatus(s);
            return (
              <button key={s.id} onClick={() => setActiveSemesterId(s.id)}
                className={`flex-shrink-0 px-10 py-5 rounded-full font-black text-base transition-all border-4 uppercase tracking-tighter ${
                  active ? 'bg-indigo-600 border-indigo-600 text-white shadow-2xl scale-105' : 'bg-white dark:bg-slate-900 border-transparent text-slate-400 hover:border-indigo-100'
                }`}
              >
                Semester {s.id}
                {status === 'complete' && <span className="ml-3">✅</span>}
                {status === 'partial' && <span className="ml-3 text-amber-500">!</span>}
              </button>
            );
          })}
        </div>

        {/* Subject Editor Card */}
        <AnimatePresence mode="wait">
          <motion.div key={activeSemesterId} initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}
            className="bg-white dark:bg-slate-900 rounded-[3rem] sm:rounded-[4rem] p-10 sm:p-16 mb-20 shadow-2xl border border-slate-100 dark:border-slate-800 relative overflow-hidden"
          >
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-10 mb-12">
              <div>
                <h3 className="text-4xl font-black tracking-tight mb-2">Semester {activeSemesterId}</h3>
                <p className="text-base font-black text-slate-400 uppercase tracking-widest">
                  {activeSemesterId === 1 ? 'Template Master (Mata Pelajaran Utama)' : 'Input Nilai Semester'}
                </p>
              </div>
              {activeSemesterId === 1 && (
                <button onClick={handleAddSubject} className="w-full md:w-auto px-10 py-5 bg-indigo-600 text-white rounded-3xl font-black text-sm uppercase tracking-widest hover:brightness-110 shadow-xl transition-all print-hide">
                  + {t.addSubject}
                </button>
              )}
            </div>

            <div className="space-y-6">
              {activeSemester?.subjects.length === 0 ? (
                <div className="py-24 text-center border-4 border-dashed border-slate-100 dark:border-slate-800 rounded-[3rem] text-slate-300 font-black uppercase tracking-[0.3em] text-lg">
                  Mulai dengan menambah mata pelajaran
                </div>
              ) : activeSemester?.subjects.map((sub, i) => (
                <div key={sub.id} className="flex flex-col sm:flex-row items-center gap-6 bg-slate-50 dark:bg-slate-950 p-8 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 hover:border-indigo-300 transition-all group">
                  <div className="flex items-center gap-6 flex-grow w-full">
                    <span className="tech-font text-slate-300 dark:text-slate-700 font-black text-2xl">{(i+1).toString().padStart(2,'0')}</span>
                    <input type="text" value={sub.name} readOnly={activeSemesterId !== 1}
                      onChange={e => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      placeholder="Nama Mata Pelajaran"
                      className={`bg-transparent font-black text-2xl outline-none w-full print-hide ${activeSemesterId === 1 ? 'focus:text-indigo-600' : 'text-slate-500 cursor-default'}`} />
                    <div className="hidden print-block font-black text-2xl flex-grow">{sub.name || '-'}</div>
                  </div>
                  <div className="flex items-center gap-6 w-full sm:w-auto">
                    <input type="number" value={sub.score || ''} onChange={e => handleUpdateSubject(sub.id, 'score', parseFloat(e.target.value) || 0)}
                      className="w-full sm:w-32 bg-white dark:bg-slate-800 border-4 border-slate-100 dark:border-slate-700 rounded-3xl py-4 text-center font-black tech-font text-3xl focus:border-indigo-600 outline-none transition-all print-hide" placeholder="0" />
                    <div className="hidden print-block font-black text-3xl tech-font w-24 text-right">{sub.score}</div>
                    {activeSemesterId === 1 && (
                      <button onClick={() => handleDeleteSubject(sub.id)} className="p-4 text-slate-300 hover:text-rose-500 transition-colors print-hide text-2xl">🗑️</button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Global Action Button - Massive & Clear */}
        <div className="max-w-2xl mx-auto mb-32 print-hide">
          <button disabled={!isGlobalCalculationValid || isCalculating} onClick={runCalculation}
            className={`w-full py-10 rounded-[3.5rem] font-black text-3xl uppercase tracking-[0.4em] shadow-2xl transition-all ${
              isGlobalCalculationValid ? 'bg-indigo-600 text-white hover:scale-105 shadow-indigo-200' : 'bg-slate-200 text-slate-400 cursor-not-allowed grayscale'
            }`}
          >
            {isCalculating ? t.calculating : t.calculate}
          </button>
          {!isGlobalCalculationValid && data.semesters[0].subjects.length > 0 && (
            <p className="text-amber-500 text-center mt-8 font-black uppercase text-xs tracking-widest leading-relaxed px-6">
              ⚠️ LENGKAPI SEMUA NILAI DI SEMESTER AKTIF UNTUK MELIHAT HASIL ANALISIS
            </p>
          )}
        </div>

        {/* Report Table */}
        <section className="mb-32">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-12">
            <h4 className="text-4xl font-black tracking-tight">{t.analysisTable}</h4>
            {showResults && (
              <button onClick={handleExportPDF} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm uppercase tracking-widest hover:brightness-110 transition-all print-hide flex items-center gap-3 shadow-lg">
                <span>📥</span> {t.exportPdf}
              </button>
            )}
          </div>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] sm:rounded-[4rem] overflow-hidden border border-slate-200 dark:border-slate-800 shadow-2xl">
            <div className="overflow-x-auto no-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800">
                    <th className="px-10 py-8 text-xs font-black uppercase tracking-widest text-slate-400">Semester</th>
                    <th className="px-10 py-8 text-xs font-black uppercase tracking-widest text-slate-400">Rata-rata</th>
                    <th className="px-10 py-8 text-xs font-black uppercase tracking-widest text-slate-400">Tertinggi</th>
                    <th className="px-10 py-8 text-xs font-black uppercase tracking-widest text-slate-400">Terendah</th>
                    <th className="px-10 py-8 text-xs font-black uppercase tracking-widest text-slate-400 print-hide">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {data.semesters.map(s => {
                    const avg = calculateSemesterAverage(s);
                    const stats = getSemesterStats(s);
                    const status = getSemesterStatus(s);
                    return (
                      <tr key={s.id} className="hover:bg-indigo-50/30 dark:hover:bg-slate-800/20 transition-colors">
                        <td className="px-10 py-8 font-black tech-font text-2xl">{s.id.toString().padStart(2, '0')}</td>
                        <td className="px-10 py-8 font-black tech-font text-4xl text-indigo-600">{avg > 0 ? avg.toFixed(1) : '---'}</td>
                        <td className="px-10 py-8 font-black tech-font text-2xl text-emerald-600">{stats.highest > 0 ? stats.highest : '---'}</td>
                        <td className="px-10 py-8 font-black tech-font text-2xl text-rose-500">{stats.lowest > 0 ? stats.lowest : '---'}</td>
                        <td className="px-10 py-8 print-hide">
                          <span className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest ${
                            status === 'complete' ? 'bg-emerald-100 text-emerald-600' : status === 'partial' ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'
                          }`}>
                            {t[`status${status.charAt(0).toUpperCase() + status.slice(1)}`]}
                          </span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </main>

      {/* Popups & Modals */}
      <AnimatePresence>
        {showWelcome && (
          <ModalWrapper onClose={() => {}} maxWidth="max-w-lg">
            <div className="text-center py-10">
              <div className="w-24 h-24 bg-indigo-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 text-5xl text-white shadow-2xl">S</div>
              <h2 className="text-5xl font-black mb-4 tracking-tighter uppercase">{t.welcome}</h2>
              <p className="text-slate-400 font-black text-xs uppercase tracking-[0.3em] mb-12 leading-relaxed px-8">{t.subtitle}</p>

              <div className="space-y-8 px-4">
                <input autoFocus type="text" value={data.userName} onChange={e => setData(d => ({ ...d, userName: e.target.value }))}
                  placeholder={t.enterName}
                  className="w-full p-10 bg-slate-50 dark:bg-slate-800 rounded-[3rem] text-3xl font-black text-center outline-none focus:ring-[1rem] ring-indigo-500/10 shadow-inner border-2 border-slate-100 dark:border-slate-700"
                  onKeyDown={e => e.key === 'Enter' && data.userName && setShowWelcome(false)} />
                <button onClick={() => data.userName && setShowWelcome(false)} 
                  className="w-full py-10 bg-indigo-600 text-white rounded-[3rem] font-black uppercase tracking-[0.3em] shadow-2xl hover:brightness-110 active:scale-95 transition-all text-2xl">
                  {t.start}
                </button>
              </div>
            </div>
          </ModalWrapper>
        )}

        {activeModal === 'final' && (
          <ModalWrapper onClose={() => setActiveModal(null)} maxWidth="max-w-2xl">
            <div className="text-center py-6">
              <div className="text-8xl mb-10">🏆</div>
              <h3 className="text-5xl font-black text-indigo-600 mb-4 uppercase tracking-tighter truncate">{data.userName}</h3>
              <h4 className="text-2xl font-black uppercase tracking-widest mb-12">{overallAvg >= data.targetAvg ? t.finalSuccess : t.finalFail}</h4>

              <motion.div initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.3 }}
                className="p-20 bg-slate-900 text-white rounded-[4rem] shadow-3xl mb-12 border-t-[1rem] border-indigo-600 relative overflow-hidden"
              >
                <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 blur-[80px] rounded-full"></div>
                <p className="text-xs font-black uppercase tracking-widest text-slate-500 mb-6 relative z-10">Rata-rata Kumulatif Akhir</p>
                <div className="text-[10rem] font-black tech-font text-indigo-400 leading-none relative z-10">{overallAvg.toFixed(1)}</div>
              </motion.div>

              <div className="flex flex-col sm:flex-row gap-6 px-4">
                <button onClick={handleExportPDF} className="flex-1 py-8 bg-slate-100 dark:bg-slate-800 rounded-[2.5rem] font-black uppercase tracking-widest text-xl shadow-lg">PDF</button>
                <button onClick={() => setActiveModal(null)} className="flex-[2] py-8 bg-indigo-600 text-white rounded-[2.5rem] font-black uppercase tracking-[0.3em] shadow-2xl text-xl hover:scale-105 transition-all">Selesai</button>
              </div>
            </div>
          </ModalWrapper>
        )}
      </AnimatePresence>

      <footer className="py-24 text-center opacity-30 print-hide border-t border-slate-100 dark:border-slate-900 mt-20">
        <p className="text-xs font-black uppercase tracking-[1.5em] sm:tracking-[2em]">SmartRapor Ecosystem &copy; 2025</p>
      </footer>
    </div>
  );
};

export default App;

