import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  getSemesterStats,
  saveToStorage, 
  loadFromStorage,
  translations 
} from './utils';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6,
  theme: 'light',
  language: 'id'
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [activeModal, setActiveModal] = useState<'semester' | 'final' | null>(null);

  // Local state for name to prevent full app blink/re-render during typing
  const [tempName, setTempName] = useState('');

  const t = useMemo(() => translations[data.language], [data.language]);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      setTempName(saved.userName || '');
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (data.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    if (isLoaded) saveToStorage(data);
  }, [data.theme, data, isLoaded]);

  const syncS1ToOthers = useCallback((allSemesters: Semester[]) => {
    const s1 = allSemesters[0];
    if (!s1) return allSemesters;
    return allSemesters.map(s => {
      if (s.id === 1) return s;
      const newSubjects = s1.subjects.map(template => {
        const existing = s.subjects.find(sub => sub.name === template.name);
        return existing ? { ...existing, name: template.name } : { id: generateId(), name: template.name, score: 0 };
      });
      return { ...s, subjects: newSubjects };
    });
  }, []);

  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, data.totalSemestersTarget);
    if (data.semesters.length !== targetCount) {
      setData(prev => {
        let currentSems = [...prev.semesters];
        if (currentSems.length < targetCount) {
          const toAdd = targetCount - currentSems.length;
          const newSems = Array.from({ length: toAdd }, (_, i) => ({ id: currentSems.length + i + 1, subjects: [] }));
          currentSems = [...currentSems, ...newSems];
        } else {
          currentSems = currentSems.slice(0, targetCount);
        }
        return { ...prev, semesters: syncS1ToOthers(currentSems) };
      });
    }
  }, [data.totalSemestersTarget, isLoaded, syncS1ToOthers]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => data.semesters.find(s => s.id === activeSemesterId) || null, [data.semesters, activeSemesterId]);
  const completeSemesters = useMemo(() => data.semesters.filter(s => getSemesterStatus(s) === 'complete'), [data.semesters, getSemesterStatus]);
  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemesters.length;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, Math.min(100, needed));
  }, [data.targetAvg, data.totalSemestersTarget, completeSemesters]);

  const isGlobalCalculationValid = useMemo(() => {
    const sems = data.semesters;
    if (sems.length === 0 || sems[0].subjects.length === 0) return false;
    let lastActiveIdx = -1;
    for (let i = sems.length - 1; i >= 0; i--) {
      if (sems[i].subjects.some(sub => sub.score > 0)) {
        lastActiveIdx = i;
        break;
      }
    }
    if (lastActiveIdx === -1) return false;
    for (let i = 0; i <= lastActiveIdx; i++) {
      if (sems[i].subjects.some(sub => sub.score <= 0)) return false;
    }
    return true;
  }, [data.semesters]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });
      return activeSemesterId === 1 && field === 'name' ? { ...prev, semesters: syncS1ToOthers(updatedSems) } : { ...prev, semesters: updatedSems };
    });
    setShowResults(false);
  };

  const handleAddSubject = () => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: generateId(), name: '', score: 0 }]
      }));
      return { ...prev, semesters: updatedSems };
    });
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const targetSem = prev.semesters.find(s => s.id === activeSemesterId);
      const targetSub = targetSem?.subjects.find(s => s.id === subId);
      if (!targetSub) return prev;
      const newSemesters = prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => activeSemesterId === 1 ? sub.name !== targetSub.name : sub.id !== subId)
      }));
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const runCalculation = async () => {
    if (!isGlobalCalculationValid) return;
    setIsCalculating(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsCalculating(false);
    setShowResults(true);
    setActiveModal('final');
  };

  const saveNameAndStart = () => {
    if (tempName.trim()) {
      setData(prev => ({ ...prev, userName: tempName.trim() }));
      setShowWelcome(false);
    }
  };

  const ModalWrapper = ({ children, onClose, maxWidth = 'max-w-xl' }: { children?: React.ReactNode, onClose: () => void, maxWidth?: string }) => (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] bg-slate-950/70 backdrop-blur-md flex items-center justify-center p-4 sm:p-6 overflow-y-auto"
      onClick={onClose}
    >
      <motion.div 
        initial={{ scale: 0.9, y: 30, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.9, y: 30, opacity: 0 }}
        className={`bg-white dark:bg-slate-900 w-full ${maxWidth} rounded-[2rem] sm:rounded-[3rem] p-6 sm:p-10 shadow-3xl border border-slate-200 dark:border-slate-800 relative overflow-hidden`}
        onClick={e => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-4 right-4 sm:top-6 sm:right-6 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:scale-110 transition-all text-lg print-hide">✕</button>
        {children}
      </motion.div>
    </motion.div>
  );

  return (
    <div className="min-h-screen flex flex-col transition-colors duration-500 overflow-x-hidden">

      {/* Navbar */}
      <nav className="sticky top-0 z-50 glass dark:glass border-b border-slate-200 dark:border-slate-800 px-4 md:px-12 py-3 sm:py-5 print-hide">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 sm:w-12 sm:h-12 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-xl sm:text-2xl shadow-lg">S</div>
            <h1 className="text-lg sm:text-2xl font-black tracking-tighter hidden xs:block uppercase">Smart<span className="text-indigo-600">Rapor</span></h1>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
            <button onClick={() => setData(d => ({ ...d, language: d.language === 'id' ? 'en' : 'id' }))} className="px-3 py-1.5 sm:px-5 sm:py-2.5 rounded-2xl bg-white dark:bg-slate-800 text-[10px] sm:text-xs font-black uppercase tracking-widest shadow-sm border border-slate-100 dark:border-slate-700">
              {data.language.toUpperCase()}
            </button>
            <button onClick={() => setData(d => ({ ...d, theme: d.theme === 'dark' ? 'light' : 'dark' }))} className="p-2 sm:p-3 rounded-2xl bg-white dark:bg-slate-800 shadow-sm text-lg sm:text-2xl border border-slate-100 dark:border-slate-700">
              {data.theme === 'dark' ? '🌞' : '🌙'}
            </button>
            <div onClick={() => setShowWelcome(true)} className="flex items-center gap-2 sm:gap-3 cursor-pointer p-1.5 pr-3 sm:pr-5 bg-white dark:bg-slate-800 rounded-full shadow-sm border border-slate-200 dark:border-slate-700">
              <div className="w-7 h-7 sm:w-9 sm:h-9 rounded-full bg-indigo-600 flex items-center justify-center text-white font-bold text-xs sm:text-base">{data.userName[0] || '?'}</div>
              <span className="hidden sm:inline text-xs sm:text-sm font-black uppercase truncate max-w-[100px] tracking-tight">{data.userName || 'Guest'}</span>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-7xl mx-auto w-full px-4 md:px-12 py-8 md:py-20">

        {/* Print Only Header */}
        <div className="hidden print:block mb-8 border-b-2 border-indigo-600 pb-4">
          <h1 className="text-3xl font-black uppercase">Laporan Analisis Nilai SmartRapor</h1>
          <div className="mt-2 flex justify-between items-end">
             <div>
                <p className="text-xs font-bold text-slate-500 uppercase">Nama Siswa:</p>
                <p className="text-xl font-black">{data.userName}</p>
             </div>
             <div className="text-right">
                <p className="text-xs font-bold text-slate-500 uppercase">Tanggal Cetak:</p>
                <p className="text-sm font-bold">{new Date().toLocaleDateString('id-ID', { dateStyle: 'long' })}</p>
             </div>
          </div>
        </div>

        {/* Welcome Text */}
        <section className="mb-10 sm:mb-16 text-center md:text-left print-hide">
          <motion.h2 initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="text-4xl sm:text-7xl font-black tracking-tight leading-tight mb-4">
            Halo, <span className="text-indigo-600">{data.userName || 'Siswa'}!</span>
          </motion.h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-2xl text-base sm:text-xl font-medium leading-relaxed">Pantau perkembangan akademikmu dengan analisis presisi.</p>
        </section>

        {/* Dashboard Cards */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-8 mb-12 sm:mb-20">
          {[
            { label: t.targetAvg, value: data.targetAvg, key: 'targetAvg', suffix: '%', editable: true },
            { label: t.totalSemesters, value: data.totalSemestersTarget, key: 'totalSemestersTarget', suffix: '', editable: true },
            { label: t.neededAvg, value: neededAvg.toFixed(1), suffix: '%', color: 'text-indigo-600' },
            { label: 'Rata-rata Kumulatif', value: overallAvg.toFixed(1), suffix: '', color: 'text-indigo-600' }
          ].map((stat, i) => (
            <motion.div key={i} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: i * 0.1 }}
              className="bg-white dark:bg-slate-900 p-6 sm:p-10 rounded-[1.5rem] sm:rounded-[2.5rem] shadow-lg shadow-indigo-100/50 dark:shadow-none border border-slate-100 dark:border-slate-800"
            >
              <span className="text-[10px] sm:text-xs font-black uppercase tracking-[0.2em] text-slate-400 block mb-3 sm:mb-5">{stat.label}</span>
              <div className="flex items-end gap-1 sm:gap-2">
                {stat.editable ? (
                  <input type="number" value={stat.value} onChange={e => setData(d => ({ ...d, [stat.key!]: parseFloat(e.target.value) || 0 }))}
                    className="bg-transparent text-3xl sm:text-5xl font-black tech-font outline-none focus:text-indigo-600 w-full print-hide" />
                ) : (
                  <span className={`text-3xl sm:text-5xl font-black tech-font ${stat.color || ''}`}>{stat.value}</span>
                )}
                <span className="text-lg sm:text-2xl font-black text-slate-300 pb-1 sm:pb-2">{stat.suffix}</span>
              </div>
              {stat.editable && <div className="hidden print:block text-2xl font-black tech-font">{stat.value}</div>}
            </motion.div>
          ))}
        </section>

        {/* Tab Navigator */}
        <div className="flex gap-2 sm:gap-4 overflow-x-auto pb-4 sm:pb-8 no-scrollbar mb-8 sm:mb-12 print-hide px-1">
          {data.semesters.map(s => {
            const active = activeSemesterId === s.id;
            const status = getSemesterStatus(s);
            return (
              <button key={s.id} onClick={() => setActiveSemesterId(s.id)}
                className={`flex-shrink-0 px-6 py-3 sm:px-10 sm:py-5 rounded-full font-black text-sm sm:text-base transition-all border-2 sm:border-4 uppercase tracking-tighter ${
                  active ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-105' : 'bg-white dark:bg-slate-900 border-transparent text-slate-400 hover:border-indigo-100'
                }`}
              >
                SMT {s.id}
                {status === 'complete' && <span className="ml-2">✅</span>}
                {status === 'partial' && <span className="ml-2 text-amber-500">!</span>}
              </button>
            );
          })}
        </div>

        {/* Editor Card */}
        <AnimatePresence mode="wait">
          <motion.div key={activeSemesterId} initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}
            className="bg-white dark:bg-slate-900 rounded-[2rem] sm:rounded-[3rem] p-6 sm:p-12 mb-12 sm:mb-20 shadow-2xl border border-slate-100 dark:border-slate-800 print-shadow-none print-border-slate-200"
          >
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 sm:gap-10 mb-8 sm:mb-12">
              <div>
                <h3 className="text-2xl sm:text-4xl font-black tracking-tight mb-1 sm:mb-2 uppercase">Semester {activeSemesterId}</h3>
                <p className="text-xs sm:text-sm font-black text-slate-400 uppercase tracking-widest">
                  {activeSemesterId === 1 ? 'Template Master (Mata Pelajaran Utama)' : 'Input Nilai Semester'}
                </p>
              </div>
              {activeSemesterId === 1 && (
                <button onClick={handleAddSubject} className="w-full sm:w-auto px-6 py-3 sm:px-10 sm:py-5 bg-indigo-600 text-white rounded-2xl sm:rounded-3xl font-black text-xs sm:text-sm uppercase tracking-widest shadow-xl print-hide">
                  + {t.addSubject}
                </button>
              )}
            </div>

            <div className="space-y-4 sm:space-y-6">
              {activeSemester?.subjects.length === 0 ? (
                <div className="py-16 sm:py-24 text-center border-2 sm:border-4 border-dashed border-slate-100 dark:border-slate-800 rounded-[2rem] text-slate-300 font-black uppercase tracking-widest text-sm sm:text-lg">
                  Tambah mata pelajaran di Semester 1
                </div>
              ) : activeSemester?.subjects.map((sub, i) => (
                <div key={sub.id} className="flex flex-col sm:flex-row items-center gap-4 sm:gap-6 bg-slate-50 dark:bg-slate-950 p-4 sm:p-8 rounded-[1.5rem] sm:rounded-[2.5rem] border border-slate-200 dark:border-slate-800 hover:border-indigo-300 transition-all group">
                  <div className="flex items-center gap-4 sm:gap-6 flex-grow w-full">
                    <span className="tech-font text-slate-300 dark:text-slate-700 font-black text-lg sm:text-2xl">{(i+1).toString().padStart(2,'0')}</span>
                    <input type="text" value={sub.name} readOnly={activeSemesterId !== 1}
                      onChange={e => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      placeholder="Mapel"
                      className={`bg-transparent font-black text-lg sm:text-2xl outline-none w-full print-hide ${activeSemesterId === 1 ? 'focus:text-indigo-600' : 'text-slate-500 cursor-default'}`} />
                    <div className="hidden print-block font-black text-lg flex-grow">{sub.name || '-'}</div>
                  </div>
                  <div className="flex items-center gap-4 sm:gap-6 w-full sm:w-auto">
                    <input type="number" value={sub.score || ''} onChange={e => handleUpdateSubject(sub.id, 'score', parseFloat(e.target.value) || 0)}
                      className="w-full sm:w-32 bg-white dark:bg-slate-800 border-2 sm:border-4 border-slate-100 dark:border-slate-700 rounded-2xl sm:rounded-3xl py-3 sm:py-4 text-center font-black tech-font text-xl sm:text-3xl focus:border-indigo-600 outline-none print-hide" placeholder="0" />
                    <div className="hidden print-block font-black text-xl tech-font w-16 text-right">{sub.score}</div>
                    {activeSemesterId === 1 && (
                      <button onClick={() => handleDeleteSubject(sub.id)} className="p-2 sm:p-4 text-slate-300 hover:text-rose-500 transition-colors print-hide text-xl sm:text-2xl">🗑️</button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Main Action Button */}
        <div className="max-w-2xl mx-auto mb-20 sm:mb-32 print-hide px-4">
          <button disabled={!isGlobalCalculationValid || isCalculating} onClick={runCalculation}
            className={`w-full py-6 sm:py-10 rounded-3xl sm:rounded-[3.5rem] font-black text-xl sm:text-3xl uppercase tracking-[0.2em] sm:tracking-[0.4em] shadow-2xl transition-all ${
              isGlobalCalculationValid ? 'bg-indigo-600 text-white hover:scale-105' : 'bg-slate-200 text-slate-400 cursor-not-allowed'
            }`}
          >
            {isCalculating ? t.calculating : t.calculate}
          </button>
          {!isGlobalCalculationValid && data.semesters[0].subjects.length > 0 && (
            <p className="text-amber-500 text-center mt-6 font-black uppercase text-[10px] tracking-widest leading-relaxed">
              ⚠️ Lengkapi nilai di semester aktif untuk melihat laporan lengkap
            </p>
          )}
        </div>

        {/* Data Table */}
        <section className="mb-20 sm:mb-32">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 sm:gap-6 mb-8 sm:mb-12">
            <h4 className="text-2xl sm:text-4xl font-black tracking-tight uppercase">Tabel Laporan Nilai</h4>
            {showResults && (
              <button onClick={handleExportPDF} className="px-6 py-3 sm:px-8 sm:py-4 bg-indigo-600 text-white rounded-2xl sm:rounded-[2rem] font-black text-[10px] sm:text-sm uppercase tracking-widest print-hide flex items-center gap-3">
                <span>📥</span> UNDUH LAPORAN PDF
              </button>
            )}
          </div>
          <div className="bg-white dark:bg-slate-900 rounded-[2rem] sm:rounded-[3rem] overflow-hidden border border-slate-200 dark:border-slate-800 shadow-xl overflow-x-auto no-scrollbar print-shadow-none print-border-slate-200">
              <table className="w-full text-left border-collapse min-w-[500px]">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800">
                    <th className="px-6 sm:px-10 py-5 sm:py-8 text-[10px] sm:text-xs font-black uppercase tracking-widest text-slate-400">SMT</th>
                    <th className="px-6 sm:px-10 py-5 sm:py-8 text-[10px] sm:text-xs font-black uppercase tracking-widest text-slate-400">Rata-rata</th>
                    <th className="px-6 sm:px-10 py-5 sm:py-8 text-[10px] sm:text-xs font-black uppercase tracking-widest text-slate-400">Tertinggi</th>
                    <th className="px-6 sm:px-10 py-5 sm:py-8 text-[10px] sm:text-xs font-black uppercase tracking-widest text-slate-400">Terendah</th>
                    <th className="px-6 sm:px-10 py-5 sm:py-8 text-[10px] sm:text-xs font-black uppercase tracking-widest text-slate-400 print-hide">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {data.semesters.map(s => {
                    const avg = calculateSemesterAverage(s);
                    const stats = getSemesterStats(s);
                    const status = getSemesterStatus(s);
                    return (
                      <tr key={s.id} className="hover:bg-indigo-50/30 dark:hover:bg-slate-800/20 transition-colors">
                        <td className="px-6 sm:px-10 py-5 sm:py-8 font-black tech-font text-lg sm:text-2xl">{s.id.toString().padStart(2, '0')}</td>
                        <td className="px-6 sm:px-10 py-5 sm:py-8 font-black tech-font text-2xl sm:text-4xl text-indigo-600">{avg > 0 ? avg.toFixed(1) : '---'}</td>
                        <td className="px-6 sm:px-10 py-5 sm:py-8 font-black tech-font text-lg sm:text-2xl text-emerald-600">{stats.highest > 0 ? stats.highest : '---'}</td>
                        <td className="px-6 sm:px-10 py-5 sm:py-8 font-black tech-font text-lg sm:text-2xl text-rose-500">{stats.lowest > 0 ? stats.lowest : '---'}</td>
                        <td className="px-6 sm:px-10 py-5 sm:py-8 print-hide">
                          <span className={`px-4 py-1.5 rounded-full text-[8px] sm:text-[10px] font-black uppercase tracking-widest ${
                            status === 'complete' ? 'bg-emerald-100 text-emerald-600' : status === 'partial' ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'
                          }`}>
                            {status}
                          </span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
          </div>
        </section>
      </main>

      {/* Modals */}
      <AnimatePresence>
        {showWelcome && (
          <ModalWrapper onClose={() => {}} maxWidth="max-w-lg">
            <div className="text-center py-6 sm:py-10">
