            <div className="text-center py-4">
              <div className="text-6xl sm:text-8xl mb-6 sm:mb-10">🏆</div>
              <h3 className="text-3xl sm:text-5xl font-black text-indigo-600 mb-2 sm:mb-4 uppercase tracking-tighter truncate px-4">{data.userName}</h3>
              <h4 className="text-lg sm:text-2xl font-black uppercase tracking-widest mb-8 sm:mb-12">{overallAvg >= data.targetAvg ? t.finalSuccess : t.finalFail}</h4>

              <motion.div initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.3 }}
                className="p-12 sm:p-20 bg-slate-900 text-white rounded-[3rem] sm:rounded-[4rem] shadow-3xl mb-8 sm:mb-12 border-t-[0.5rem] sm:border-t-[1rem] border-indigo-600 relative overflow-hidden"
              >
                <p className="text-[10px] sm:text-xs font-black uppercase tracking-widest text-slate-500 mb-4 sm:mb-6">Rata-rata Kumulatif Akhir</p>
                <div className="text-7xl sm:text-[10rem] font-black tech-font text-indigo-400 leading-none">{overallAvg.toFixed(1)}</div>
              </motion.div>

              <div className="flex flex-col sm:flex-row gap-4 sm:gap-6 px-4">
                <button onClick={handleExportPDF} className="flex-1 py-6 sm:py-8 bg-slate-100 dark:bg-slate-800 rounded-3xl font-black uppercase tracking-widest text-lg sm:text-xl shadow-lg hover:bg-slate-200">PDF</button>
                <button onClick={() => setActiveModal(null)} className="flex-[2] py-6 sm:py-8 bg-indigo-600 text-white rounded-3xl font-black uppercase tracking-[0.3em] shadow-2xl text-lg sm:text-xl hover:scale-105">Selesai</button>
              </div>
            </div>
          </ModalWrapper>
        )}
      </AnimatePresence>

      <footer className="py-16 sm:py-24 text-center opacity-30 print-hide border-t border-slate-100 dark:border-slate-900 mt-10">
        <p className="text-[8px] sm:text-xs font-black uppercase tracking-[1.5em] sm:tracking-[2em]">SmartRapor Ecosystem &copy; 2025</p>
      </footer>
