import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  getSemesterStats,
  saveToStorage, 
  loadFromStorage,
  translations 
} from './utils';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6,
  theme: 'light',
  language: 'id'
};

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [activeModal, setActiveModal] = useState<'final' | null>(null);
  const [tempName, setTempName] = useState('');

  const t = useMemo(() => translations[data.language], [data.language]);

  // Load persistence
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      setTempName(saved.userName || '');
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  // Theme & Auto-save
  useEffect(() => {
    document.documentElement.classList.toggle('dark', data.theme === 'dark');
    if (isLoaded) saveToStorage(data);
  }, [data.theme, data, isLoaded]);

  // Sync logic
  const syncS1ToOthers = useCallback((allSemesters: Semester[]) => {
    const s1 = allSemesters[0];
    if (!s1) return allSemesters;
    return allSemesters.map(s => {
      if (s.id === 1) return s;
      const newSubjects = s1.subjects.map(template => {
        const existing = s.subjects.find(sub => sub.name === template.name);
        return existing ? { ...existing, name: template.name } : { id: generateId(), name: template.name, score: 0 };
      });
      return { ...s, subjects: newSubjects };
    });
  }, []);

  // Semester Count Sync
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, Math.min(12, data.totalSemestersTarget));
    if (data.semesters.length !== targetCount) {
      setData(prev => {
        let currentSems = [...prev.semesters];
        if (currentSems.length < targetCount) {
          const toAdd = targetCount - currentSems.length;
          const newSems = Array.from({ length: toAdd }, (_, i) => ({ id: currentSems.length + i + 1, subjects: [] }));
          currentSems = [...currentSems, ...newSems];
        } else {
          currentSems = currentSems.slice(0, targetCount);
        }
        return { ...prev, semesters: syncS1ToOthers(currentSems) };
      });
    }
  }, [data.totalSemestersTarget, isLoaded, syncS1ToOthers]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => data.semesters.find(s => s.id === activeSemesterId) || null, [data.semesters, activeSemesterId]);
  const completeSemestersCount = useMemo(() => data.semesters.filter(s => getSemesterStatus(s) === 'complete').length, [data.semesters, getSemesterStatus]);
  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemestersCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = data.semesters
      .filter(s => getSemesterStatus(s) === 'complete')
      .reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, Math.min(100, needed));
  }, [data.targetAvg, data.totalSemestersTarget, completeSemestersCount, data.semesters, getSemesterStatus]);

  const isValidToCalculate = useMemo(() => {
    return data.semesters.some(s => s.subjects.some(sub => sub.score > 0));
  }, [data.semesters]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });
      return activeSemesterId === 1 && field === 'name' ? { ...prev, semesters: syncS1ToOthers(updatedSems) } : { ...prev, semesters: updatedSems };
    });
    setShowResults(false);
  };

  const handleAddSubject = () => {
    setData(prev => {
      const newId = generateId();
      const updatedSems = prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
      }));
      return { ...prev, semesters: updatedSems };
    });
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const targetSem = prev.semesters.find(s => s.id === activeSemesterId);
      const targetSub = targetSem?.subjects.find(s => s.id === subId);
      if (!targetSub) return prev;
      const newSemesters = prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => activeSemesterId === 1 ? sub.name !== targetSub.name : sub.id !== subId)
      }));
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleReset = () => {
    if (confirm('Hapus semua data? Tindakan ini tidak bisa dibatalkan.')) {
      setData(INITIAL_DATA);
      setTempName('');
      setShowWelcome(true);
      setShowResults(false);
    }
  };

  const runCalculation = async () => {
    if (!isValidToCalculate) return;
    setIsCalculating(true);
    await new Promise(r => setTimeout(r, 1200));
    setIsCalculating(false);
    setShowResults(true);
    setActiveModal('final');
  };

  const saveName = () => {
    if (tempName.trim()) {
      setData(prev => ({ ...prev, userName: tempName.trim() }));
      setShowWelcome(false);
    }
  };

  const Modal = ({ children, onClose, maxWidth = 'max-w-xl' }: { children: React.ReactNode, onClose: () => void, maxWidth?: string }) => (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4 print:hidden"
      onClick={onClose}>
      <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 20 }}
        className={`bg-white dark:bg-slate-900 w-full ${maxWidth} rounded-[2.5rem] p-8 sm:p-12 shadow-3xl border border-slate-200 dark:border-slate-800 relative`}
        onClick={e => e.stopPropagation()}>
        <button onClick={onClose} className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:scale-110 transition-all">✕</button>
        {children}
      </motion.div>
    </motion.div>
  );

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-500 overflow-x-hidden">

      {/* Navigation */}
      <nav className="sticky top-0 z-50 glass dark:glass border-b border-slate-200 dark:border-slate-800 px-4 md:px-12 py-4 print-hide">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-lg">S</div>
            <h1 className="text-xl font-black hidden sm:block">SMART<span className="text-indigo-600">RAPOR</span></h1>
          </div>
          <div className="flex items-center gap-2 sm:gap-4">
            <button onClick={() => setData(d => ({ ...d, theme: d.theme === 'dark' ? 'light' : 'dark' }))}
              className="p-2.5 rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm text-xl transition-transform hover:scale-105">
              {data.theme === 'dark' ? '🌞' : '🌙'}
            </button>
            <div onClick={() => setShowWelcome(true)} className="flex items-center gap-2 p-1.5 pr-4 bg-white dark:bg-slate-800 rounded-full shadow-sm border border-slate-200 dark:border-slate-700 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
              <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white font-bold text-sm shadow-sm">{data.userName[0] || '?'}</div>
              <span className="hidden xs:inline text-xs font-black uppercase tracking-tight truncate max-w-[120px]">{data.userName || 'Siswa'}</span>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-7xl mx-auto w-full px-4 md:px-12 py-10 md:py-20">

        {/* PDF Transkrip Header */}
        <div className="hidden print-block mb-10 border-b-4 border-black pb-4">
          <h1 className="text-3xl font-black uppercase text-center mb-2">Transkrip Analisis Akademik Mandiri</h1>
          <div className="flex justify-between text-sm font-bold">
            <p>NAMA: {data.userName.toUpperCase()}</p>
            <p>TANGGAL: {new Date().toLocaleDateString('id-ID', { dateStyle: 'full' }).toUpperCase()}</p>
          </div>
        </div>

        {/* Hero Section */}
        <section className="mb-12 text-center md:text-left print-hide">
          <motion.h2 initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}
            className="text-4xl sm:text-6xl lg:text-8xl font-black tracking-tight leading-[1.1] mb-6">
            Peta <span className="text-indigo-600">Akademik</span><br />Masa Depanmu.
          </motion.h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-2xl text-lg sm:text-xl font-medium">Input nilai rapormu dan biarkan sistem menghitung strategi terbaik untuk mencapai target kelulusan.</p>
        </section>

        {/* Global Stats Grid */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-16 sm:mb-20">
          {[
            { label: t.targetAvg, value: data.targetAvg, key: 'targetAvg', suffix: '%', editable: true },
            { label: t.totalSemesters, value: data.totalSemestersTarget, key: 'totalSemestersTarget', suffix: '', editable: true },
            { label: t.neededAvg, value: neededAvg.toFixed(1), suffix: '%', highlight: true },
            { label: 'Cumulative GPA', value: overallAvg.toFixed(1), suffix: '', highlight: true }
          ].map((stat, i) => (
            <motion.div key={i} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}
