                    <span className="tech-font text-slate-300 dark:text-slate-700 font-black text-xl">{(i+1).toString().padStart(2,'0')}</span>
                    <input type="text" value={sub.name} readOnly={activeSemesterId !== 1}
                      onChange={e => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      placeholder="Nama Mata Pelajaran"
                      className={`bg-transparent font-black text-xl outline-none w-full print-hide ${activeSemesterId === 1 ? 'focus:text-indigo-600' : 'text-slate-500 cursor-default'}`} />
