                      className="w-full sm:w-28 bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 rounded-[1.2rem] py-4 text-center font-black tech-font text-2xl focus:border-indigo-600 outline-none print-hide" placeholder="0" />
                    <div className="hidden print-block font-black text-2xl tech-font w-20 text-right">{sub.score}</div>
