        </AnimatePresence>

        {/* Global Action */}
        <div className="max-w-2xl mx-auto mb-24 print-hide text-center">
          <button disabled={!isValidToCalculate || isCalculating} onClick={runCalculation}
            className={`w-full py-10 rounded-[2.5rem] font-black text-2xl uppercase tracking-[0.3em] shadow-2xl transition-all ${
              isValidToCalculate ? 'bg-indigo-600 text-white hover:scale-105 shadow-indigo-200' : 'bg-slate-200 text-slate-400 cursor-not-allowed'
            }`}>
            {isCalculating ? t.calculating : t.calculate}
          </button>
          <button onClick={handleReset} className="mt-8 text-[10px] font-black uppercase tracking-widest text-rose-500 hover:underline">
            {t.resetData}
          </button>
        </div>

        {/* Summary Table */}
        <section className="mb-24">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-12">
            <h4 className="text-3xl font-black tracking-tight uppercase">{t.analysisTable}</h4>
            {showResults && (
              <button onClick={() => window.print()} className="px-8 py-4 bg-slate-900 text-white dark:bg-white dark:text-slate-950 rounded-2xl font-black text-xs uppercase tracking-widest hover:scale-105 transition-all print-hide flex items-center gap-3">
                📥 {t.exportPdf}
              </button>
            )}
          </div>
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] overflow-hidden border border-slate-200 dark:border-slate-800 shadow-xl overflow-x-auto no-scrollbar">
            <table className="w-full text-left border-collapse min-w-[600px]">
              <thead>
                <tr className="bg-slate-50 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800">
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">SMT</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">Rata-rata</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">Tertinggi</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">Terendah</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400 print-hide">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                {data.semesters.map(s => {
                  const avg = calculateSemesterAverage(s);
                  const stats = getSemesterStats(s);
                  const status = getSemesterStatus(s);
                  return (
                    <tr key={s.id} className="hover:bg-indigo-50/20 dark:hover:bg-slate-800/30 transition-colors">
                      <td className="px-10 py-8 font-black tech-font text-2xl">{s.id.toString().padStart(2, '0')}</td>
                      <td className="px-10 py-8 font-black tech-font text-4xl text-indigo-600">{avg > 0 ? avg.toFixed(1) : '---'}</td>
                      <td className="px-10 py-8 font-black tech-font text-2xl text-emerald-600">{stats.highest > 0 ? stats.highest : '---'}</td>
                      <td className="px-10 py-8 font-black tech-font text-2xl text-rose-500">{stats.lowest > 0 ? stats.lowest : '---'}</td>
                      <td className="px-10 py-8 print-hide">
                        <span className={`px-4 py-2 rounded-full text-[10px] font-black uppercase ${
                          status === 'complete' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'
                        }`}>
                          {status === 'complete' ? t.statusComplete : status === 'partial' ? t.statusPartial : t.statusEmpty}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>
      </main>

      {/* Popups */}
      <AnimatePresence>
        {showWelcome && (
          <Modal onClose={() => {}} maxWidth="max-w-md">
            <div className="text-center">
              <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center mx-auto mb-8 text-4xl text-white shadow-2xl">S</div>
              <h2 className="text-4xl font-black mb-2 tracking-tighter uppercase">{t.welcome}</h2>
              <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest mb-10 px-6 leading-relaxed">{t.subtitle}</p>
              <div className="space-y-6">
                <input autoFocus type="text" value={tempName} onChange={e => setTempName(e.target.value)}
                  placeholder={t.enterName}
                  className="w-full p-8 bg-slate-50 dark:bg-slate-800 rounded-[2rem] text-3xl font-black text-center outline-none focus:ring-8 ring-indigo-500/10 border-2 border-slate-100 dark:border-slate-700"
                  onKeyDown={e => e.key === 'Enter' && tempName.trim() && saveName()} />
                <button onClick={saveName} disabled={!tempName.trim()}
                  className={`w-full py-8 rounded-[2rem] font-black uppercase tracking-[0.2em] shadow-xl text-xl transition-all ${
                    tempName.trim() ? 'bg-indigo-600 text-white hover:scale-105' : 'bg-slate-200 text-slate-400 cursor-not-allowed'
                  }`}>
                  {t.start}
                </button>
              </div>
            </div>
          </Modal>
        )}

        {activeModal === 'final' && (
          <Modal onClose={() => setActiveModal(null)} maxWidth="max-w-2xl">
            <div className="text-center">
              <div className="text-8xl mb-8">🏆</div>
              <h3 className="text-4xl font-black text-indigo-600 mb-2 uppercase tracking-tighter">{data.userName}</h3>
              <h4 className="text-2xl font-black uppercase tracking-widest mb-10">{overallAvg >= data.targetAvg ? t.finalSuccess : t.finalFail}</h4>
              <div className="p-14 bg-slate-900 text-white rounded-[3.5rem] shadow-3xl mb-12 border-t-[12px] border-indigo-600 relative overflow-hidden">
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6">Cumulative GPA Prediction</p>
                <div className="text-9xl font-black tech-font text-indigo-400 leading-none">{overallAvg.toFixed(1)}</div>
              </div>
              <div className="flex flex-col sm:flex-row gap-4">
                <button onClick={() => window.print()} className="flex-1 py-8 bg-slate-100 dark:bg-slate-800 rounded-3xl font-black uppercase tracking-widest text-lg">Export PDF</button>
                <button onClick={() => setActiveModal(null)} className="flex-[2] py-8 bg-indigo-600 text-white rounded-3xl font-black uppercase tracking-[0.2em] shadow-2xl text-xl hover:scale-105">Selesai</button>
              </div>
            </div>
          </Modal>
        )}
      </AnimatePresence>

      <footer className="py-20 text-center opacity-30 print-hide border-t border-slate-100 dark:border-slate-900 mt-10">
        <p className="text-[10px] font-black uppercase tracking-[1.5em]">SmartRapor &copy; 2025</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  getSemesterStats,
  saveToStorage, 
  loadFromStorage,
  translations 
} from './utils';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6,
  theme: 'light',
  language: 'id'
};

// Moved Modal component outside of App and added children?: React.ReactNode 
// to resolve TypeScript inference errors where children were not recognized correctly.
const Modal = ({ children, onClose, maxWidth = 'max-w-xl' }: { children?: React.ReactNode, onClose: () => void, maxWidth?: string }) => (
  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
    className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4 print:hidden"
    onClick={onClose}>
    <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 20 }}
      className={`bg-white dark:bg-slate-900 w-full ${maxWidth} rounded-[2.5rem] p-8 sm:p-12 shadow-3xl border border-slate-200 dark:border-slate-800 relative`}
      onClick={e => e.stopPropagation()}>
      <button onClick={onClose} className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:scale-110 transition-all">✕</button>
      {children}
    </motion.div>
  </motion.div>
);

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [activeModal, setActiveModal] = useState<'final' | null>(null);
  const [tempName, setTempName] = useState('');

  const t = useMemo(() => translations[data.language], [data.language]);

  // Load persistence
  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      setTempName(saved.userName || '');
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  // Theme & Auto-save
  useEffect(() => {
    document.documentElement.classList.toggle('dark', data.theme === 'dark');
    if (isLoaded) saveToStorage(data);
  }, [data.theme, data, isLoaded]);

  // Sync logic
  const syncS1ToOthers = useCallback((allSemesters: Semester[]) => {
    const s1 = allSemesters[0];
    if (!s1) return allSemesters;
    return allSemesters.map(s => {
      if (s.id === 1) return s;
      const newSubjects = s1.subjects.map(template => {
        const existing = s.subjects.find(sub => sub.name === template.name);
        return existing ? { ...existing, name: template.name } : { id: generateId(), name: template.name, score: 0 };
      });
      return { ...s, subjects: newSubjects };
    });
  }, []);

  // Semester Count Sync
  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, Math.min(12, data.totalSemestersTarget));
    if (data.semesters.length !== targetCount) {
      setData(prev => {
        let currentSems = [...prev.semesters];
        if (currentSems.length < targetCount) {
          const toAdd = targetCount - currentSems.length;
          const newSems = Array.from({ length: toAdd }, (_, i) => ({ id: currentSems.length + i + 1, subjects: [] }));
          currentSems = [...currentSems, ...newSems];
        } else {
          currentSems = currentSems.slice(0, targetCount);
        }
        return { ...prev, semesters: syncS1ToOthers(currentSems) };
      });
    }
  }, [data.totalSemestersTarget, isLoaded, syncS1ToOthers]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => data.semesters.find(s => s.id === activeSemesterId) || null, [data.semesters, activeSemesterId]);
  const completeSemestersCount = useMemo(() => data.semesters.filter(s => getSemesterStatus(s) === 'complete').length, [data.semesters, getSemesterStatus]);
  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemestersCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = data.semesters
      .filter(s => getSemesterStatus(s) === 'complete')
      .reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, Math.min(100, needed));
  }, [data.targetAvg, data.totalSemestersTarget, completeSemestersCount, data.semesters, getSemesterStatus]);

  const isValidToCalculate = useMemo(() => {
    return data.semesters.some(s => s.subjects.some(sub => sub.score > 0));
  }, [data.semesters]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });
      return activeSemesterId === 1 && field === 'name' ? { ...prev, semesters: syncS1ToOthers(updatedSems) } : { ...prev, semesters: updatedSems };
    });
    setShowResults(false);
  };

  const handleAddSubject = () => {
    setData(prev => {
      const newId = generateId();
      const updatedSems = prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
      }));
      return { ...prev, semesters: updatedSems };
    });
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const targetSem = prev.semesters.find(s => s.id === activeSemesterId);
      const targetSub = targetSem?.subjects.find(s => s.id === subId);
      if (!targetSub) return prev;
      const newSemesters = prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => activeSemesterId === 1 ? sub.name !== targetSub.name : sub.id !== subId)
      }));
      return { ...prev, semesters: newSemesters };
    });
    setShowResults(false);
  };

  const handleReset = () => {
    if (confirm('Hapus semua data? Tindakan ini tidak bisa dibatalkan.')) {
      setData(INITIAL_DATA);
      setTempName('');
      setShowWelcome(true);
      setShowResults(false);
    }
  };

  const runCalculation = async () => {
    if (!isValidToCalculate) return;
    setIsCalculating(true);
    await new Promise(r => setTimeout(r, 1200));
    setIsCalculating(false);
    setShowResults(true);
    setActiveModal('final');
  };

  const saveName = () => {
    if (tempName.trim()) {
      setData(prev => ({ ...prev, userName: tempName.trim() }));
      setShowWelcome(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-500 overflow-x-hidden">

      {/* Navigation */}
      <nav className="sticky top-0 z-50 glass dark:glass border-b border-slate-200 dark:border-slate-800 px-4 md:px-12 py-4 print-hide">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-lg">S</div>
            <h1 className="text-xl font-black hidden sm:block">SMART<span className="text-indigo-600">RAPOR</span></h1>
          </div>
          <div className="flex items-center gap-2 sm:gap-4">
            <button onClick={() => setData(d => ({ ...d, theme: d.theme === 'dark' ? 'light' : 'dark' }))}
              className="p-2.5 rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm text-xl transition-transform hover:scale-105">
              {data.theme === 'dark' ? '🌞' : '🌙'}
            </button>
            <div onClick={() => setShowWelcome(true)} className="flex items-center gap-2 p-1.5 pr-4 bg-white dark:bg-slate-800 rounded-full shadow-sm border border-slate-200 dark:border-slate-700 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
              <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white font-bold text-sm shadow-sm">{data.userName[0] || '?'}</div>
              <span className="hidden xs:inline text-xs font-black uppercase tracking-tight truncate max-w-[120px]">{data.userName || 'Siswa'}</span>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-7xl mx-auto w-full px-4 md:px-12 py-10 md:py-20">

        {/* PDF Transkrip Header */}
        <div className="hidden print-block mb-10 border-b-4 border-black pb-4">
          <h1 className="text-3xl font-black uppercase text-center mb-2">Transkrip Analisis Akademik Mandiri</h1>
          <div className="flex justify-between text-sm font-bold">
            <p>NAMA: {data.userName.toUpperCase()}</p>
            <p>TANGGAL: {new Date().toLocaleDateString('id-ID', { dateStyle: 'full' }).toUpperCase()}</p>
          </div>
        </div>

        {/* Hero Section */}
        <section className="mb-12 text-center md:text-left print-hide">
          <motion.h2 initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}
            className="text-4xl sm:text-6xl lg:text-8xl font-black tracking-tight leading-[1.1] mb-6">
            Peta <span className="text-indigo-600">Akademik</span><br />Masa Depanmu.
          </motion.h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-2xl text-lg sm:text-xl font-medium">Input nilai rapormu dan biarkan sistem menghitung strategi terbaik untuk mencapai target kelulusan.</p>
        </section>

        {/* Global Stats Grid */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-16 sm:mb-20">
          {[
            { label: t.targetAvg, value: data.targetAvg, key: 'targetAvg', suffix: '%', editable: true },
            { label: t.totalSemesters, value: data.totalSemestersTarget, key: 'totalSemestersTarget', suffix: '', editable: true },
            { label: t.neededAvg, value: neededAvg.toFixed(1), suffix: '%', highlight: true },
            { label: 'Cumulative GPA', value: overallAvg.toFixed(1), suffix: '', highlight: true }
          ].map((stat, i) => (
            <motion.div key={i} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}
              className="bg-white dark:bg-slate-900 p-8 rounded-[2rem] shadow-xl border border-slate-100 dark:border-slate-800 hover:border-indigo-500/30 transition-colors">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 block mb-4">{stat.label}</span>
              <div className="flex items-end gap-1">
                {stat.editable ? (
                  <input type="number" value={stat.value} onChange={e => setData(d => ({ ...d, [stat.key!]: parseFloat(e.target.value) || 0 }))}
                    className="bg-transparent text-4xl font-black tech-font outline-none focus:text-indigo-600 w-full print-hide" />
                ) : (
                  <span className={`text-4xl font-black tech-font ${stat.highlight ? 'text-indigo-600' : ''}`}>{stat.value}</span>
                )}
                <span className="text-xl font-bold text-slate-300 pb-1">{stat.suffix}</span>
              </div>
              {stat.editable && <div className="hidden print-block text-3xl font-black tech-font">{stat.value}</div>}
            </motion.div>
          ))}
        </section>

        {/* Semester Navigator */}
        <div className="flex gap-3 overflow-x-auto pb-8 no-scrollbar mb-10 print-hide px-1">
          {data.semesters.map(s => {
            const active = activeSemesterId === s.id;
            const status = getSemesterStatus(s);
            return (
              <button key={s.id} onClick={() => setActiveSemesterId(s.id)}
                className={`flex-shrink-0 px-8 py-4 rounded-full font-black text-xs uppercase tracking-widest transition-all border-4 ${
                  active ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-105' : 'bg-white dark:bg-slate-900 border-transparent text-slate-400 hover:border-indigo-100'
                }`}>
                SMT {s.id}
                {status === 'complete' && <span className="ml-2">✅</span>}
              </button>
            );
          })}
        </div>

        {/* Main Editor Card */}
        <AnimatePresence mode="wait">
          <motion.div key={activeSemesterId} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }}
            className="bg-white dark:bg-slate-900 rounded-[3rem] p-8 sm:p-14 mb-20 shadow-2xl border border-slate-100 dark:border-slate-800 relative">

            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8 mb-12">
              <div>
                <h3 className="text-3xl sm:text-4xl font-black tracking-tighter mb-1">Semester {activeSemesterId}</h3>
                <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">
                  {activeSemesterId === 1 ? 'Template Daftar Mata Pelajaran' : 'Nilai Capaian Semester'}
                </p>
              </div>
              {activeSemesterId === 1 && (
                <button onClick={handleAddSubject} className="w-full md:w-auto px-10 py-5 bg-indigo-600 text-white rounded-[1.5rem] font-black text-xs uppercase tracking-widest hover:brightness-110 shadow-lg transition-all print-hide">
                  + {t.addSubject}
                </button>
              )}
            </div>

            <div className="space-y-4">
              {activeSemester?.subjects.length === 0 ? (
                <div className="py-24 text-center border-4 border-dashed border-slate-100 dark:border-slate-800 rounded-[2rem] text-slate-300 font-black uppercase tracking-widest">
                  Klik tombol tambah untuk memulai
                </div>
              ) : activeSemester?.subjects.map((sub, i) => (
                <div key={sub.id} className="flex flex-col sm:flex-row items-center gap-6 bg-slate-50 dark:bg-slate-950 p-6 rounded-[2rem] border border-slate-200 dark:border-slate-800 hover:border-indigo-400 transition-all group">
                  <div className="flex items-center gap-6 flex-grow w-full">
                    <span className="tech-font text-slate-300 dark:text-slate-700 font-black text-xl">{(i+1).toString().padStart(2,'0')}</span>
                    <input type="text" value={sub.name} readOnly={activeSemesterId !== 1}
                      onChange={e => handleUpdateSubject(sub.id, 'name', e.target.value)}
                      placeholder="Nama Mata Pelajaran"
                      className={`bg-transparent font-black text-xl outline-none w-full print-hide ${activeSemesterId === 1 ? 'focus:text-indigo-600' : 'text-slate-500 cursor-default'}`} />
                    <div className="hidden print-block font-black text-xl flex-grow">{sub.name || '-'}</div>
                  </div>
                  <div className="flex items-center gap-4 w-full sm:w-auto">
                    <input type="number" value={sub.score || ''} onChange={e => handleUpdateSubject(sub.id, 'score', parseFloat(e.target.value) || 0)}
                      className="w-full sm:w-28 bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 rounded-[1.2rem] py-4 text-center font-black tech-font text-2xl focus:border-indigo-600 outline-none print-hide" placeholder="0" />
                    <div className="hidden print-block font-black text-2xl tech-font w-20 text-right">{sub.score}</div>
                    {activeSemesterId === 1 && (
                      <button onClick={() => handleDeleteSubject(sub.id)} className="p-4 text-slate-300 hover:text-rose-500 transition-colors print-hide">🗑️</button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Global Action */}
        <div className="max-w-2xl mx-auto mb-24 print-hide text-center">
          <button disabled={!isValidToCalculate || isCalculating} onClick={runCalculation}
            className={`w-full py-10 rounded-[2.5rem] font-black text-2xl uppercase tracking-[0.3em] shadow-2xl transition-all ${
              isValidToCalculate ? 'bg-indigo-600 text-white hover:scale-105 shadow-indigo-200' : 'bg-slate-200 text-slate-400 cursor-not-allowed'
            }`}>
            {isCalculating ? t.calculating : t.calculate}
          </button>
          <button onClick={handleReset} className="mt-8 text-[10px] font-black uppercase tracking-widest text-rose-500 hover:underline">
            {t.resetData}
          </button>
        </div>

        {/* Summary Table */}
        <section className="mb-24">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-12">
            <h4 className="text-3xl font-black tracking-tight uppercase">{t.analysisTable}</h4>
            {showResults && (
              <button onClick={() => window.print()} className="px-8 py-4 bg-slate-900 text-white dark:bg-white dark:text-slate-950 rounded-2xl font-black text-xs uppercase tracking-widest hover:scale-105 transition-all print-hide flex items-center gap-3">
                📥 {t.exportPdf}
              </button>
            )}
          </div>
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] overflow-hidden border border-slate-200 dark:border-slate-800 shadow-xl overflow-x-auto no-scrollbar">
            <table className="w-full text-left border-collapse min-w-[600px]">
              <thead>
                <tr className="bg-slate-50 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800">
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">SMT</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">Rata-rata</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">Tertinggi</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400">Terendah</th>
                  <th className="px-10 py-8 text-[10px] font-black uppercase tracking-widest text-slate-400 print-hide">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                {data.semesters.map(s => {
                  const avg = calculateSemesterAverage(s);
                  const stats = getSemesterStats(s);
                  const status = getSemesterStatus(s);
                  return (
                    <tr key={s.id} className="hover:bg-indigo-50/20 dark:hover:bg-slate-800/30 transition-colors">
                      <td className="px-10 py-8 font-black tech-font text-2xl">{s.id.toString().padStart(2, '0')}</td>
                      <td className="px-10 py-8 font-black tech-font text-4xl text-indigo-600">{avg > 0 ? avg.toFixed(1) : '---'}</td>
                      <td className="px-10 py-8 font-black tech-font text-2xl text-emerald-600">{stats.highest > 0 ? stats.highest : '---'}</td>
                      <td className="px-10 py-8 font-black tech-font text-2xl text-rose-500">{stats.lowest > 0 ? stats.lowest : '---'}</td>
                      <td className="px-10 py-8 print-hide">
                        <span className={`px-4 py-2 rounded-full text-[10px] font-black uppercase ${
                          status === 'complete' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'
                        }`}>
                          {status === 'complete' ? t.statusComplete : status === 'partial' ? t.statusPartial : t.statusEmpty}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>
      </main>

      {/* Popups */}
      <AnimatePresence>
        {showWelcome && (
          <Modal onClose={() => {}} maxWidth="max-w-md">
            <div className="text-center">
              <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center mx-auto mb-8 text-4xl text-white shadow-2xl">S</div>
              <h2 className="text-4xl font-black mb-2 tracking-tighter uppercase">{t.welcome}</h2>
              <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest mb-10 px-6 leading-relaxed">{t.subtitle}</p>
              <div className="space-y-6">
                <input autoFocus type="text" value={tempName} onChange={e => setTempName(e.target.value)}
                  placeholder={t.enterName}
                  className="w-full p-8 bg-slate-50 dark:bg-slate-800 rounded-[2rem] text-3xl font-black text-center outline-none focus:ring-8 ring-indigo-500/10 border-2 border-slate-100 dark:border-slate-700"
                  onKeyDown={e => e.key === 'Enter' && tempName.trim() && saveName()} />
                <button onClick={saveName} disabled={!tempName.trim()}
                  className={`w-full py-8 rounded-[2rem] font-black uppercase tracking-[0.2em] shadow-xl text-xl transition-all ${
                    tempName.trim() ? 'bg-indigo-600 text-white hover:scale-105' : 'bg-slate-200 text-slate-400 cursor-not-allowed'
                  }`}>
                  {t.start}
                </button>
              </div>
            </div>
          </Modal>
        )}

        {activeModal === 'final' && (
          <Modal onClose={() => setActiveModal(null)} maxWidth="max-w-2xl">
            <div className="text-center">
              <div className="text-8xl mb-8">🏆</div>
              <h3 className="text-4xl font-black text-indigo-600 mb-2 uppercase tracking-tighter">{data.userName}</h3>
              <h4 className="text-2xl font-black uppercase tracking-widest mb-10">{overallAvg >= data.targetAvg ? t.finalSuccess : t.finalFail}</h4>
              <div className="p-14 bg-slate-900 text-white rounded-[3.5rem] shadow-3xl mb-12 border-t-[12px] border-indigo-600 relative overflow-hidden">
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-6">Cumulative GPA Prediction</p>
                <div className="text-9xl font-black tech-font text-indigo-400 leading-none">{overallAvg.toFixed(1)}</div>
              </div>
              <div className="flex flex-col sm:flex-row gap-4">
                <button onClick={() => window.print()} className="flex-1 py-8 bg-slate-100 dark:bg-slate-800 rounded-3xl font-black uppercase tracking-widest text-lg">Export PDF</button>
                <button onClick={() => setActiveModal(null)} className="flex-[2] py-8 bg-indigo-600 text-white rounded-3xl font-black uppercase tracking-[0.2em] shadow-2xl text-xl hover:scale-105">Selesai</button>
              </div>
            </div>
          </Modal>
        )}
      </AnimatePresence>

      <footer className="py-20 text-center opacity-30 print-hide border-t border-slate-100 dark:border-slate-900 mt-10">
        <p className="text-[10px] font-black uppercase tracking-[1.5em]">SmartRapor &copy; 2025</p>
      </footer>
    </div>
  );
};

export default App;

