import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence, LayoutGroup } from 'framer-motion';
import { AppData, Semester, Subject } from './types';
import { 
  calculateSemesterAverage, 
  calculateOverallAverage, 
  getSemesterStats,
  saveToStorage, 
  loadFromStorage,
  translations 
} from './utils';

const generateId = () => Math.random().toString(36).substring(2, 11);

const INITIAL_DATA: AppData = {
  userName: '',
  semesters: Array.from({ length: 6 }, (_, i) => ({ id: i + 1, subjects: [] })),
  targetAvg: 85,
  totalSemestersTarget: 6,
  theme: 'light',
  language: 'id'
};

const Modal = ({ children, onClose, maxWidth = 'max-w-xl' }: { children?: React.ReactNode, onClose: () => void, maxWidth?: string }) => (
  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
    className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4 print:hidden"
    onClick={onClose}>
    <motion.div initial={{ scale: 0.9, y: 30 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 30 }}
      className={`bg-white dark:bg-slate-900 w-full ${maxWidth} rounded-[2.5rem] p-8 sm:p-12 shadow-3xl border border-slate-200 dark:border-slate-800 relative overflow-hidden`}
      onClick={e => e.stopPropagation()}>
      <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600"></div>
      <button onClick={onClose} className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:scale-110 transition-all text-slate-500">✕</button>
      {children}
    </motion.div>
  </motion.div>
);

const App: React.FC = () => {
  const [data, setData] = useState<AppData>(INITIAL_DATA);
  const [activeSemesterId, setActiveSemesterId] = useState<number>(1);
  const [isLoaded, setIsLoaded] = useState(false);
  const [isCalculating, setIsCalculating] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [activeModal, setActiveModal] = useState<'final' | null>(null);
  const [tempName, setTempName] = useState('');

  const t = useMemo(() => translations[data.language], [data.language]);

  useEffect(() => {
    const saved = loadFromStorage();
    if (saved) {
      setData(saved);
      setTempName(saved.userName || '');
      if (!saved.userName) setShowWelcome(true);
    } else {
      setShowWelcome(true);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', data.theme === 'dark');
    if (isLoaded) saveToStorage(data);
  }, [data.theme, data, isLoaded]);

  const syncS1ToOthers = useCallback((allSemesters: Semester[]) => {
    const s1 = allSemesters[0];
    if (!s1) return allSemesters;
    return allSemesters.map(s => {
      if (s.id === 1) return s;
      const newSubjects = s1.subjects.map(template => {
        const existing = s.subjects.find(sub => sub.name === template.name);
        return existing ? { ...existing, name: template.name } : { id: generateId(), name: template.name, score: 0 };
      });
      return { ...s, subjects: newSubjects };
    });
  }, []);

  useEffect(() => {
    if (!isLoaded) return;
    const targetCount = Math.max(1, Math.min(12, data.totalSemestersTarget));
    if (data.semesters.length !== targetCount) {
      setData(prev => {
        let currentSems = [...prev.semesters];
        if (currentSems.length < targetCount) {
          const toAdd = targetCount - currentSems.length;
          const newSems = Array.from({ length: toAdd }, (_, i) => ({ id: currentSems.length + i + 1, subjects: [] }));
          currentSems = [...currentSems, ...newSems];
        } else {
          currentSems = currentSems.slice(0, targetCount);
        }
        return { ...prev, semesters: syncS1ToOthers(currentSems) };
      });
    }
  }, [data.totalSemestersTarget, isLoaded, syncS1ToOthers]);

  const getSemesterStatus = useCallback((semester: Semester) => {
    if (!semester || semester.subjects.length === 0) return 'empty';
    const scoredCount = semester.subjects.filter(s => s.score > 0).length;
    if (scoredCount === 0) return 'empty';
    if (scoredCount < semester.subjects.length) return 'partial';
    return 'complete';
  }, []);

  const activeSemester = useMemo(() => data.semesters.find(s => s.id === activeSemesterId) || null, [data.semesters, activeSemesterId]);
  const overallAvg = useMemo(() => calculateOverallAverage(data.semesters), [data.semesters]);
  const completeSemestersCount = useMemo(() => data.semesters.filter(s => getSemesterStatus(s) === 'complete').length, [data.semesters, getSemesterStatus]);

  const neededAvg = useMemo(() => {
    const remaining = data.totalSemestersTarget - completeSemestersCount;
    if (remaining <= 0) return 0;
    const targetTotalSum = data.targetAvg * data.totalSemestersTarget;
    const currentSumOfAverages = data.semesters
      .filter(s => getSemesterStatus(s) === 'complete')
      .reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
    const needed = (targetTotalSum - currentSumOfAverages) / remaining;
    return Math.max(0, Math.min(100, needed));
  }, [data.targetAvg, data.totalSemestersTarget, completeSemestersCount, data.semesters, getSemesterStatus]);

  const handleUpdateSubject = (subId: string, field: keyof Subject, value: string | number) => {
    setData(prev => {
      const updatedSems = prev.semesters.map(s => {
        if (s.id === activeSemesterId) {
          return { ...s, subjects: s.subjects.map(sub => sub.id === subId ? { ...sub, [field]: value } : sub) };
        }
        return s;
      });
      return activeSemesterId === 1 && field === 'name' ? { ...prev, semesters: syncS1ToOthers(updatedSems) } : { ...prev, semesters: updatedSems };
    });
  };

  const handleAddSubject = () => {
    setData(prev => {
      const newId = generateId();
      const updatedSems = prev.semesters.map(s => ({
        ...s,
        subjects: [...s.subjects, { id: newId, name: '', score: 0 }]
      }));
      return { ...prev, semesters: updatedSems };
    });
  };

  const handleDeleteSubject = (subId: string) => {
    setData(prev => {
      const targetSem = prev.semesters.find(s => s.id === activeSemesterId);
      const targetSub = targetSem?.subjects.find(s => s.id === subId);
      if (!targetSub) return prev;
      const newSemesters = prev.semesters.map(s => ({
        ...s,
        subjects: s.subjects.filter(sub => activeSemesterId === 1 ? sub.name !== targetSub.name : sub.id !== subId)
      }));
      return { ...prev, semesters: newSemesters };
    });
  };

  const handleReset = () => {
    if (confirm('Tindakan ini akan menghapus seluruh data akademik Anda. Lanjutkan?')) {
      setData(INITIAL_DATA);
      setTempName('');
      setShowWelcome(true);
    }
  };

  const runCalculation = async () => {
    setIsCalculating(true);
    await new Promise(r => setTimeout(r, 1500));
    setIsCalculating(false);
    setActiveModal('final');
  };

  const saveName = () => {
    if (tempName.trim()) {
      setData(prev => ({ ...prev, userName: tempName.trim() }));
      setShowWelcome(false);
    }
  };

  // Visual Components
  const ProgressRing = ({ value, target }: { value: number, target: number }) => {
    const percentage = Math.min(100, (value / target) * 100);
    return (
      <div className="relative w-32 h-32 flex items-center justify-center">
        <svg className="w-full h-full -rotate-90">
          <circle cx="64" cy="64" r="58" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-100 dark:text-slate-800" />
          <motion.circle cx="64" cy="64" r="58" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray="364.4"
            initial={{ strokeDashoffset: 364.4 }} animate={{ strokeDashoffset: 364.4 - (364.4 * percentage) / 100 }}
            className="text-indigo-600" />
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-2xl font-black tech-font">{value.toFixed(1)}</span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Current</span>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen flex flex-col transition-all">
      {/* Navbar */}
      <nav className="sticky top-0 z-50 glass dark:glass border-b border-slate-200 dark:border-slate-800 px-6 md:px-12 py-5 print-hide">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} className="flex items-center gap-4">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-2xl shadow-lg shadow-indigo-200 dark:shadow-none">S</div>
            <div>
              <h1 className="text-xl font-black tracking-tight leading-none uppercase">Smart<span className="text-indigo-600">Rapor</span></h1>
              <span className="text-[9px] font-black uppercase tracking-[0.3em] text-slate-400">Enterprise Edition</span>
            </div>
          </motion.div>
          <div className="flex items-center gap-3">
            <button onClick={() => setData(d => ({ ...d, theme: d.theme === 'dark' ? 'light' : 'dark' }))}
              className="p-3 rounded-2xl bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shadow-sm text-xl hover:bg-slate-50 transition-colors">
              {data.theme === 'dark' ? '🌞' : '🌙'}
            </button>
            <div onClick={() => setShowWelcome(true)} className="flex items-center gap-2 p-1.5 pr-4 bg-white dark:bg-slate-800 rounded-full shadow-sm border border-slate-200 dark:border-slate-700 cursor-pointer hover:border-indigo-400 transition-all">
              <div className="w-9 h-9 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold shadow-md">
                {data.userName[0]?.toUpperCase() || '?'}
              </div>
              <span className="hidden sm:inline text-xs font-black uppercase tracking-tight max-w-[120px] truncate">{data.userName || 'Guest User'}</span>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-7xl mx-auto w-full px-6 md:px-12 py-10 md:py-16">
        {/* PDF Heading (Hidden on Web) */}
        <div className="hidden print:block text-center border-b-4 border-black pb-8 mb-12">
          <h1 className="text-4xl font-black uppercase mb-2">Transkrip Laporan Akademik</h1>
          <div className="flex justify-between items-end mt-6">
            <div className="text-left">
              <p className="text-sm font-bold text-slate-500 uppercase">Nama Siswa</p>
              <p className="text-2xl font-black">{data.userName.toUpperCase()}</p>
            </div>
            <div className="text-right">
              <p className="text-sm font-bold text-slate-500 uppercase">Tanggal Analisis</p>
              <p className="text-xl font-bold">{new Date().toLocaleDateString('id-ID', { dateStyle: 'full' })}</p>
            </div>
          </div>
        </div>

        {/* Hero Dashboard */}
        <header className="mb-16 print-hide">
          <motion.h2 initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="text-5xl md:text-7xl font-black tracking-tight mb-4 leading-none">
            Welcome back,<br /><span className="gradient-text">{data.userName || 'Explorer'}</span>.
          </motion.h2>
          <p className="text-slate-500 dark:text-slate-400 text-lg md:text-xl font-medium max-w-2xl">Dashboard pintar untuk melacak performa akademik dan merencanakan strategi kelulusanmu.</p>
        </header>

        {/* Analytics Grid */}
        <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-16">
          {/* Main GPA Card */}
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
            className="col-span-1 lg:col-span-2 bg-white dark:bg-slate-900 rounded-[3rem] p-10 flex flex-col md:flex-row items-center justify-between gap-10 shadow-2xl shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-800 relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 text-8xl opacity-5 dark:opacity-10 group-hover:scale-110 transition-transform">🎓</div>
            <div className="flex flex-col gap-6 w-full md:w-auto text-center md:text-left">
              <div>
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Target Cumulative GPA</span>
                <div className="flex items-center justify-center md:justify-start gap-4 mt-2">
                  <input type="number" value={data.targetAvg} onChange={e => setData(d => ({ ...d, targetAvg: parseFloat(e.target.value) || 0 }))}
                    className="w-32 bg-slate-50 dark:bg-slate-800 border-2 border-transparent focus:border-indigo-600 rounded-2xl p-4 text-4xl font-black tech-font text-center outline-none transition-all" />
                  <span className="text-4xl font-black text-slate-300">/ 100</span>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-slate-50 dark:bg-slate-800 rounded-2xl p-4">
                  <span className="text-[9px] font-black uppercase tracking-widest text-slate-400 block mb-1">Needed Min.</span>
                  <span className="text-2xl font-black tech-font text-indigo-600">{neededAvg.toFixed(1)}</span>
                </div>
                <div className="bg-slate-50 dark:bg-slate-800 rounded-2xl p-4">
                  <span className="text-[9px] font-black uppercase tracking-widest text-slate-400 block mb-1">Semesters</span>
                  <span className="text-2xl font-black tech-font text-slate-900 dark:text-white">{completeSemestersCount}/{data.totalSemestersTarget}</span>
                </div>
              </div>
            </div>
            <ProgressRing value={overallAvg} target={data.targetAvg} />
          </motion.div>

          {/* Configuration Card */}
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.1 }}
            className="bg-indigo-600 rounded-[3rem] p-10 text-white shadow-2xl shadow-indigo-300 dark:shadow-none flex flex-col justify-between group">
            <div>
              <span className="text-[10px] font-black uppercase tracking-widest opacity-60">Setting Akun</span>
              <h3 className="text-2xl font-black mt-2 mb-8">Konfigurasi Target</h3>
              <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-black uppercase tracking-widest opacity-60 block mb-2">Target Semester</label>
                  <input type="range" min="1" max="12" value={data.totalSemestersTarget} onChange={e => setData(d => ({ ...d, totalSemestersTarget: parseInt(e.target.value) }))}
                    className="w-full h-2 bg-indigo-400 rounded-lg appearance-none cursor-pointer accent-white" />
                  <div className="text-right font-black tech-font mt-2">{data.totalSemestersTarget} SMT</div>
                </div>
              </div>
            </div>
            <button onClick={handleReset} className="w-full py-4 bg-white/10 hover:bg-white/20 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-colors">
              {t.resetData}
            </button>
          </motion.div>
        </section>

        {/* Dynamic Editor Section */}
        <section className="mb-20">
          <div className="flex gap-2 overflow-x-auto pb-6 no-scrollbar print-hide">
            {data.semesters.map(s => {
              const active = activeSemesterId === s.id;
              const status = getSemesterStatus(s);
              return (
                <button key={s.id} onClick={() => setActiveSemesterId(s.id)}
                  className={`flex-shrink-0 px-8 py-4 rounded-3xl font-black text-xs uppercase tracking-widest transition-all border-2 ${
                    active ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-105' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-400 hover:border-indigo-400'
                  }`}>
                  SMT {s.id} {status === 'complete' && '✅'}
                </button>
              );
            })}
          </div>

          <AnimatePresence mode="wait">
            <motion.div key={activeSemesterId} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }}
              className="bg-white dark:bg-slate-900 rounded-[3.5rem] p-8 md:p-14 shadow-2xl border border-slate-100 dark:border-slate-800">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8 mb-12">
                <div>
                  <h3 className="text-4xl font-black tracking-tight uppercase">Semester {activeSemesterId}</h3>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mt-2">
                    {activeSemesterId === 1 ? '🎓 MASTER TEMPLATE: Edit mata pelajaran di sini' : '📝 INPUT NILAI: Fokus pada angka pencapaian'}
                  </p>
                </div>
                {activeSemesterId === 1 && (
                  <button onClick={handleAddSubject} className="w-full md:w-auto px-10 py-5 bg-indigo-600 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-indigo-700 transition-colors flex items-center justify-center gap-3">
                    <span className="text-xl">+</span> {t.addSubject}
                  </button>
                )}
              </div>

              <div className="grid grid-cols-1 gap-4">
                {activeSemester?.subjects.length === 0 ? (
                  <div className="py-24 text-center border-4 border-dashed border-slate-100 dark:border-slate-800 rounded-[3rem] text-slate-300 font-black uppercase tracking-widest text-sm">
                    Belum ada data. Silakan tambah mata pelajaran di SMT 01.
                  </div>
                ) : activeSemester?.subjects.map((sub, i) => (
                  <motion.div layout key={sub.id} initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: i * 0.05 }}
