import { AppData, Semester, Subject } from './types';

export const calculateSemesterAverage = (semester: Semester): number => {
  if (!semester || semester.subjects.length === 0) return 0;
  const validScores = semester.subjects.map(s => s.score).filter(score => score > 0);
  if (validScores.length === 0) return 0;
  const sum = validScores.reduce((acc, score) => acc + score, 0);
  return sum / semester.subjects.length;
};

export const getSemesterStats = (semester: Semester) => {
  if (!semester || semester.subjects.length === 0) return { highest: 0, lowest: 0 };
  const scores = semester.subjects.map(s => s.score).filter(s => s > 0);
  if (scores.length === 0) return { highest: 0, lowest: 0 };
  return {
    highest: Math.max(...scores),
    lowest: Math.min(...scores)
  };
};

export const calculateOverallAverage = (semesters: Semester[]): number => {
  const completeSemesters = semesters.filter(s => {
    return s.subjects.length > 0 && s.subjects.every(sub => sub.score > 0);
  });
  if (completeSemesters.length === 0) return 0;
  const sumOfAverages = completeSemesters.reduce((acc, sem) => acc + calculateSemesterAverage(sem), 0);
  return sumOfAverages / completeSemesters.length;
};

/**
 * Menghitung prediksi nilai cerdas untuk subjek di semester berikutnya.
 * Jika trend naik, diproyeksikan naik. Jika di bawah target, diproyeksikan ke target minimal.
 */
export const calculateSubjectPrediction = (
  subjectName: string, 
  currentScore: number, 
  neededAvg: number, 
  targetAvg: number
): number => {
  if (currentScore === 0) return neededAvg || targetAvg;

  // Jika skor saat ini sudah bagus (di atas target), pertahankan dengan sedikit peningkatan
  if (currentScore >= targetAvg) {
    return Math.min(100, currentScore + 0.5);
  }

  // Jika di bawah target, hitung gap dan sarankan kenaikan moderat untuk mengejar target
  const gap = neededAvg - currentScore;
  const improvement = gap > 0 ? gap * 0.4 : 1; // Kejar 40% dari gap setiap semester agar realistis

  return Math.min(100, Math.max(currentScore + improvement, neededAvg));
};

export const STORAGE_KEY = 'smart_rapor_pro_v3_core';

export const saveToStorage = (data: AppData) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
};

export const loadFromStorage = (): AppData | null => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) return null;
  try {
    return JSON.parse(data);
  } catch (e) {
    return null;
  }
};

