                {activeSemesterId === 1 && (
                  <button onClick={handleAddSubject} className="w-full md:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl md:rounded-[1.5rem] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-indigo-700 transition-all">
