                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-950 border-b border-slate-100 dark:border-slate-800 uppercase text-[9px] md:text-[10px]">
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">Semester</th>
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">Avg Score</th>
