                        <div className="relative">
                          <input type="number" value={sub.prediction || ''} onChange={e => handleUpdateSubject(sub.id, 'prediction', e.target.value === '' ? 0 : parseFloat(e.target.value))}
                            className="w-full bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 rounded-xl md:rounded-2xl py-3 md:py-4 text-center font-black tech-font text-xl md:text-2xl focus:border-indigo-500 outline-none transition-all opacity-80" placeholder="0" />
                          <span className="absolute right-3 top-1/2 -translate-y-1/2 text-[8px] font-black text-indigo-300 pointer-events-none uppercase">Pred</span>
                        </div>

                        {/* DYNAMIC AI TARGET */}
                        <div className={`col-span-2 sm:col-span-1 rounded-xl md:rounded-2xl p-2 md:p-3 text-center min-w-[100px] shadow-lg transition-all border ${isImpossible ? 'bg-rose-500 border-rose-400 text-white shadow-rose-500/20' : 'bg-indigo-600 text-white border-indigo-500 shadow-indigo-500/20'}`}>
                          <span className="text-[7px] md:text-[8px] font-black uppercase opacity-60 block tracking-widest">{isImpossible ? t.impossibleTarget : t.requiredLabel}</span>
                          <span className="text-sm md:text-lg font-black tech-font">
                            {isImpossible ? '100+' : dynamicRequired.toFixed(1)}
                          </span>
                        </div>

                        {activeSemesterId === 1 && (
                          <button onClick={() => handleDeleteSubject(sub.id)} className="hidden sm:block p-3 text-slate-300 hover:text-rose-500 transition-colors">✕</button>
                        )}
                      </div>
                    </motion.div>
                  );
                })}
              </div>
            </motion.div>
          </AnimatePresence>
        </section>

        {/* ... remaining sections (Diagnosis, Summary) stay same ... */}

        {/* DIAGNOSIS TABLE SECTION */}
        <section className="mb-24">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] md:rounded-[3.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden">
            <div className="p-8 md:p-10 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row justify-between items-center gap-6">
              <h4 className="text-xl md:text-2xl font-black uppercase tracking-tight">{t.diagnosisTable}</h4>
              <button onClick={() => window.print()} className="px-6 md:px-8 py-3 md:py-4 bg-indigo-600 text-white rounded-xl md:rounded-2xl font-black text-[10px] md:text-xs uppercase tracking-widest hover:scale-105 transition-all print-hide flex items-center gap-2">
                <span>📥</span> {t.exportPdf}
              </button>
            </div>
            <div className="overflow-x-auto no-scrollbar">
              <table className="w-full text-left border-collapse min-w-[900px]">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-950 border-b border-slate-100 dark:border-slate-800 uppercase text-[9px] md:text-[10px]">
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">Semester</th>
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">Actual Avg</th>
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">Combined Avg</th>
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">Peak Performance</th>
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">{t.stability} (SD)</th>
                    <th className="px-8 md:px-10 py-6 md:py-8 font-black tracking-widest text-slate-400">Progress</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {data.semesters.map(s => {
                    const actualAvg = calculateSemesterAverage(s, false);
                    const combinedAvg = calculateSemesterAverage(s, true);
                    const stats = getSemesterStats(s);
                    const status = getSemesterStatus(s);
                    const isHealthy = stats.variance < 5 && combinedAvg > data.targetAvg;

                    return (
                      <tr key={s.id} className="hover:bg-indigo-50/20 dark:hover:bg-indigo-500/5 transition-colors">
                        <td className="px-8 md:px-10 py-6 md:py-8 font-black tech-font text-xl md:text-2xl">{s.id.toString().padStart(2, '0')}</td>
                        <td className="px-8 md:px-10 py-6 md:py-8 font-black tech-font text-xl md:text-2xl text-slate-400">
                          {actualAvg > 0 ? actualAvg.toFixed(1) : '---'}
                        </td>
                        <td className="px-8 md:px-10 py-6 md:py-8 font-black tech-font text-3xl md:text-4xl text-indigo-600">
                          {combinedAvg > 0 ? combinedAvg.toFixed(1) : '---'}
                        </td>
                        <td className="px-8 md:px-10 py-6 md:py-8 font-black tech-font text-xl md:text-2xl text-emerald-600">
                          {stats.highest > 0 ? stats.highest : '---'}
                        </td>
                        <td className="px-8 md:px-10 py-6 md:py-8">
                          {combinedAvg > 0 ? (
                            <div className="flex items-center gap-2">
                              <span className={`tech-font font-black ${isHealthy ? 'text-emerald-500' : 'text-amber-500'}`}>
                                {stats.variance.toFixed(2)}
                              </span>
                              <span className="text-[8px] font-black uppercase text-slate-400">{isHealthy ? 'Stable' : 'Volatile'}</span>
                            </div>
                          ) : '---'}
                        </td>
                        <td className="px-8 md:px-10 py-6 md:py-8">
                          <div className={`h-2 w-20 md:w-24 rounded-full overflow-hidden ${status === 'complete' ? 'bg-emerald-100' : 'bg-slate-100 dark:bg-slate-800'}`}>
                            <div className={`h-full transition-all duration-1000 ${status === 'complete' ? 'bg-emerald-500 w-full' : status === 'partial' ? 'bg-amber-500 w-1/2' : 'w-0'}`}></div>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </main>

      {/* Popups */}
      <AnimatePresence>
        {showWelcome && (
          <Modal onClose={() => {}} maxWidth="max-w-md">
            <div className="text-center py-4">
              <div className="w-20 h-20 bg-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-8 text-4xl text-white shadow-2xl">S</div>
              <h2 className="text-3xl font-black mb-3 tracking-tighter uppercase">{t.welcome}</h2>
              <p className="text-slate-400 font-black text-[9px] uppercase tracking-widest mb-10 px-6 leading-relaxed">{t.subtitle}</p>
              <div className="space-y-6">
                <input autoFocus type="text" value={tempName} onChange={e => setTempName(e.target.value)}
                  placeholder={t.enterName}
                  className="w-full p-6 bg-slate-50 dark:bg-slate-800 rounded-[2rem] text-2xl font-black text-center outline-none focus:ring-8 ring-indigo-500/10 border-2 border-slate-100 dark:border-slate-700 transition-all"
                  onKeyDown={e => e.key === 'Enter' && tempName.trim() && saveName()} />
                <button onClick={saveName} disabled={!tempName.trim()}
                  className={`w-full py-6 rounded-[2rem] font-black uppercase tracking-[0.3em] shadow-xl text-lg transition-all ${
                    tempName.trim() ? 'bg-indigo-600 text-white hover:scale-105 active:scale-95' : 'bg-slate-200 text-slate-400 cursor-not-allowed'
                  }`}>
                  {t.start}
                </button>
              </div>
            </div>
          </Modal>
        )}

        {activeModal === 'final' && (
          <Modal onClose={() => setActiveModal(null)} maxWidth="max-w-2xl">
            <div className="text-center py-4">
              <div className="text-8xl mb-10">🏆</div>
              <h3 className="text-4xl font-black text-indigo-600 mb-2 uppercase tracking-tighter">{data.userName}</h3>
              <h4 className="text-xl font-black uppercase tracking-widest mb-12">{overallAvg >= data.targetAvg ? t.finalSuccess : t.finalFail}</h4>

              <div className="relative p-12 md:p-16 bg-slate-950 text-white rounded-[3.5rem] md:rounded-[4.5rem] shadow-3xl mb-12 border-t-[12px] border-indigo-600 overflow-hidden">
                <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-500/20 blur-3xl rounded-full"></div>
                <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-500 mb-8">Gabungan Skor Aktual & Prediksi</p>
                <div className="text-8xl md:text-[10rem] font-black tech-font text-indigo-400 leading-none tracking-tighter">{overallAvg.toFixed(1)}</div>
                <p className="mt-8 text-xs font-bold opacity-40 uppercase tracking-[0.2em]">Strategi Roadmap Akademik</p>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <button onClick={() => { window.print(); setActiveModal(null); }} className="py-6 bg-slate-100 dark:bg-slate-800 rounded-3xl font-black uppercase tracking-widest text-sm md:text-base">Unduh PDF</button>
                <button onClick={() => setActiveModal(null)} className="py-6 bg-indigo-600 text-white rounded-3xl font-black uppercase tracking-[0.3em] shadow-2xl text-lg hover:scale-105 active:scale-95">Kembali</button>
              </div>
            </div>
          </Modal>
        )}
      </AnimatePresence>

      <footer className="py-16 md:py-24 text-center opacity-30 print-hide border-t border-slate-200 dark:border-slate-800 mt-12 md:mt-20">
        <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[1.5em] md:tracking-[2em]">SmartRapor &copy; 2025 • Strategic Planner Version</p>
      </footer>
    </div>
  );
};

export default App;
